         /* Search Popup Modal Styles */
         .search-popup-modal {
         display: none;
         position: fixed;
         top: 0;
         left: 0;
         width: 100%;
         height: 100%;
         background-color: rgba(0, 0, 0, 0.7);
         z-index: 9999;
         overflow-y: auto;
         }
         .search-popup-content {
         background: linear-gradient(135deg, #1a1f2e 0%, #2d3748 100%);
         margin: 50px auto;
         padding: 0;
         width: 90%;
         max-width: 900px;
         border-radius: 15px;
         box-shadow: 0 10px 40px rgba(0, 0, 0, 0.5);
         animation: slideDown 0.3s ease-out;
         }
         @keyframes slideDown {
         from {
         transform: translateY(-50px);
         opacity: 0;
         }
         to {
         transform: translateY(0);
         opacity: 1;
         }
         }
         .search-popup-header {
         background: linear-gradient(135deg, #8b7355 0%, #6b5535 100%);
         color: #fff;
         border-radius: 15px 15px 0 0;
         display: flex;
         justify-content: space-between;
         align-items: center;
         }
         .search-popup-header h2 {
         margin: 0;
         font-size: 18px;
         font-weight: 700;
         text-transform: uppercase;
         letter-spacing: 1px;
         }
         .search-popup-close {
         background: transparent;
         border: none;
         color: #fff;
         font-size: 32px;
         cursor: pointer;
         transition: transform 0.2s;
         line-height: 1;
         padding: 0;
         width: 35px;
         height: 35px;
         }
         .search-popup-close:hover {
         transform: rotate(90deg);
         }
         .search-popup-body {
         padding: 0px;
         max-height: 600px;
         overflow-y: auto;
         }
         .search-result-card {
         background: linear-gradient(135deg, #2d3748 0%, #1a1f2e 100%);
         border: 2px solid #8b7355;
         border-radius: 10px;
         padding: 8px;
         margin-bottom: 8px;
         transition: all 0.3s ease;
         display: flex;
         justify-content: space-between;
         align-items: center;
         }
         .search-result-card:hover {
         transform: translateY(-5px);
         box-shadow: 0 8px 20px rgba(139, 115, 85, 0.3);
         border-color: #fff;
         }
         .search-result-info {
         flex: 1;
         color: #fff;
         }
         .search-result-id {
         font-size: 14px;
         color: #8b7355;
         font-weight: 600;
         margin-bottom: 8px;
         }
         .search-result-name {
         font-size: 20px;
         font-weight: 700;
         margin-bottom: 10px;
         color: #fff;
         }
         .search-result-details {
         display: flex;
         gap: 20px;
         margin-top: 10px;
         }
         .search-result-detail-item {
         display: flex;
         flex-direction: column;
         }
         .search-result-label {
         font-size: 12px;
         color: #a0aec0;
         text-transform: uppercase;
         margin-bottom: 4px;
         }
         .search-result-value {
         font-size: 18px;
