         }
         /* Header */
         .calc-header {
         background: transparent;
         border-bottom: none;
         padding-inline: 16px;
         }
         .calc-header .modal-title {
         font-size: 14px;
         font-weight: 600;
         }
         .calc-header .btn-close {
         filter: invert(1);
         }
         /* Body */
         .calc-body {
         padding: 12px 16px 16px;
         }
         /* Display */
         .calc-display {
         height: 48px;
         border-radius: 12px;
         background: linear-gradient(145deg, #181c27, #10131b);
         box-shadow: inset 3px 3px 6px #0a0c12, inset -3px -3px 6px #1c2230;
         color: #fff;
         font-size: 24px;
         font-weight: 600;
         text-align: right;
         padding: 8px 12px;
         margin-bottom: 12px;
         overflow: hidden;
         white-space: nowrap;
         }
         /* Grid */
         .calc-grid {
         display: grid;
         grid-template-columns: repeat(4, 56px);
         grid-auto-rows: 44px;
         gap: 8px;
         justify-content: center;
         }
         /* Generic button */
         .calc-btn {
         border: none;
         border-radius: 50%;
         background: linear-gradient(145deg, #181c27, #10131b);
         box-shadow: 4px 4px 8px #0a0c12, -4px -4px 8px #1c2230;
         color: #f5f5f5;
         font-size: 15px;
         font-weight: 500;
         cursor: pointer;
         outline: none;
         display: flex;
         align-items: center;
         justify-content: center;
         transition: all 0.12s ease-in-out;
         }
         .calc-btn:active {
         box-shadow: inset 3px 3px 6px #0a0c12, inset -3px -3px 6px #1c2230;
         transform: translateY(1px);
         }
         /* Function buttons (AC, DE, %) */
         .calc-func {
         color: #4ade80;
         }
         /* Operators */
         .calc-op {
         color: #22c55e;
         }
         /* Equals â€“ big pill at bottom */
         .calc-eq {
         grid-column: 1 / -1;
         border-radius: 22px;
         background: linear-gradient(145deg, #f97316, #ea580c);
         box-shadow: 4px 4px 8px rgba(0,0,0,0.6), -2px -2px 8px rgba(255,255,255,0.05);
         font-size: 18px;
         font-weight: 700;
         color: #fff;
         }
         .calc-eq:active {
         box-shadow: inset 3px 3px 6px rgba(0,0,0,0.6), inset -3px -3px 6px rgba(255,255,255,0.05);
         }
         .calc-close-red {
         background-color: #ff4b4b !important;
         border-radius: 50%;
         padding: 6px;
         }
         .calc-close-red:hover {
         background-color: #ff1f1f !important;
         }
         .watermark {
         position: absolute;
         top: 50%;
         left: 50%;
         transform: translate(-50%, -50%);
         opacity: 0.18;
         pointer-events: none;
         z-index: 1; /* Below cart rows but above background */
         width: 45%;
         height: auto;
         }
         .watermark img {
         width: 100%;
         height: auto;
         display: block;
         border-radius: 50%;
         }
         /* Content wrapper to ensure it's above watermark */
         .content-wrapper {
         position: relative;
         z-index: 1;
         }
         .store-header {
         position: relative;
         overflow: hidden;           /* hide overflow */
         white-space: nowrap;        /* keep content in one line */
         width: 49%;
         margin-right: -13%;
         margin-left: -27%;
         }
         .store-header-inner {
         display: inline-block;
         padding-left: 100%;         /* start off-screen right */
         animation: storeHeaderScroll 20s linear infinite;
         }
         @keyframes storeHeaderScroll {
         0% {
         transform: translateX(0);
         }
         50% {
         transform: translateX(-100%);  /* move fully to left */
         }
         100% {
         transform: translateX(0);      /* back to start (right) */
         }
