         \tgetTotal(coupon_code) {
         \t\tvar total={};
         \t\tvar totalAmt=[];
         \t\t//if (sessionStorage.getItem(\"coupon\") != null) {
         \t\t\t//var coupon = JSON.parse(sessionStorage.getItem(\"coupon\"));
         \t\t\tvar coupon_info = this.getCoupon(coupon_code);
         \t\t\tif (coupon_info != null) {
         \t\t\t\tvar discount_total = 0;
         \t\t\t\tvar sub_total=0;
         \t\t\t\tif (!coupon_info.product.length) {
         \t\t\t\t\tsub_total = getSubTotal();
         \t\t\t\t} else {
         \t\t\t\t\tsub_total = 0;
         \t\t\t\t\$.each(CartObj.getProducts(),function(pro_key,product){
         \t\t\t\t if(coupon_info.product.indexOf(product.product_id) != -1 ){
         \t\t\t\t sub_total += product.total;
         \t\t\t\t }
         \t\t\t\t
         \t\t\t\t
         \t\t\t\t\t//\$.each(coupon_info.product,function(key,value){
         \t\t\t\t//\tif(parseInt(product.product_id) == value){
         \t\t\t\t\t//\tsub_total += product.total;
         \t\t\t\t\t//}
         \t\t\t\t//});\t
         \t\t\t\t
         \t\t\t\t
         \t\t\t\t
         \t\t\t\t
         \t\t\t\t});
         
         \t\t\t\t}
         \t\t\t\t
         \t\t\t\tif (coupon_info.type == 'F') {
         \t\t\t\t\tcoupon_info.discount = Math.min(coupon_info.discount, sub_total);
         \t\t\t\t}
         \t\t\t\t
         \t\t\t\t\$.each(CartObj.getProducts(),function(pro_key,product){
         \t\t\t\t\tvar discount = 0;
         
         \t\t\t\t\tif (!coupon_info.product.length) {
         \t\t\t\t\t\tvar status = true;
         \t\t\t\t\t} else {
         \t\t\t\t\t\tvar pro_status = false;
         \t\t\t\t\t\t\$.each(coupon_info.product,function(key,value){
         \t\t\t\t\t\t\tif(parseInt(product.product_id) == value){
         \t\t\t\t\t\t\t\tpro_status = true;
         \t\t\t\t\t\t\t}
         \t\t\t\t\t\t});\t
         \t\t\t\t
         \t\t\t\t\t\tvar status = pro_status;
         \t\t\t\t\t}
         
         \t\t\t\t\t
         \t\t\t\t\tif (status) {
         \t\t\t\t\tvar discount=0;
         \t\t\t\t\t\tif (coupon_info.type == 'F') {
         \t\t\t\t\t\t\tdiscount = parseFloat(coupon_info.discount) * (product.total / sub_total);
         \t\t\t\t\t\t} else if (coupon_info.type == 'P') {
         \t\t\t\t\t\t\tdiscount = product.total / 100 * parseFloat(coupon_info.discount);
         \t\t\t\t\t\t}
         
         \t\t\t\t\t\tif (parseInt(product.tax_class_id)) {
         \t\t\t\t\t\t\tvar tax_rates = taxObj.getRates(product.total - (product.total - discount), parseInt(product.tax_class_id));
         
         
         \t\t\t\t\t\$.each(tax_rates, function (taxKey,tax_rate){
         \t\t\t\t\t\tif (tax_rate.type == 'P') {
         \t\t\t\t\t\t\t\t\ttotalAmt.push(tax_rate.amount);
