         \t\t\t\t\t\t\t\t}
         \t\t
         \t\t\t\t\t\t});
         \t\t\t\t\t\t}
         \t\t\t\t\t}
         
         \t\t\t\t\tdiscount_total += discount;
         \t\t\t});
         
         \t\t\t\tif (discount_total > total.total) {
         \t\t\t\t\tdiscount_total = total.total;
         \t\t\t\t}
         \t\t\t\tif (discount_total > 0) {
         \t\t\t\treturn discount_total;
         \t\t\t\t//\ttotal['totals'] = {
         \t\t\t\t//\t\t'code'       : 'coupon',
