         \t\tfunction getSubTotal() {
         \t\t\tvar total = 0;
         \t\t\tif(typeof CartObj.getProducts() != 'undefined'){
         \t\t\t\t\$.each(CartObj.getProducts(),function(key,val){
         \t\t\t\ttotal+=val.total;
