         //Add to Cart\t
            function addToCartProducts(productData){
                 console.log(\"ProductData-------------------\", productData);
             var options = [];
             if(productData.filter_options){
                 options = productData.filter_options;
             }
             let customer_id=0;
             if(sessionStorage.getItem('currentCustomerData') != null){
                 currentCustomerData = JSON.parse(sessionStorage.getItem('currentCustomerData'));
                 customer_id=currentCustomerData.customer_id;
             }
             
             // EXTRACT GST (try multiple possible sources)
             let gst_percent = 0;
             if (productData.gst != null && productData.gst !== '') {
                 gst_percent = parseFloat(productData.gst) || 0;
             } else if (productData.gst_percent != null && productData.gst_percent !== '') {
                 gst_percent = parseFloat(productData.gst_percent) || 0;
             } else if (productData.categories && Array.isArray(productData.categories) && productData.categories.length > 0 && productData.categories[0].gst) {
                 gst_percent = parseFloat(productData.categories[0].gst) || 0;
             }
             console.log(\"GST for product \" + productData.product_id + \": \" + gst_percent + \"%\");
             
             var posCartData = {
                 'cart_id':parseInt((Math.floor(Math.random() * 10000000000) + 10000000000).toString().substring(1)),
                 'name' : productData.name || productData.heading_title || productData.model || '',
                 'price' : productData.price,
                 'pos_quantity' : productData.pos_quantity,
                 'reward' : productData.reward,
                 'customer_id':customer_id,
                 'disc_price' : productData.provided_discount,
                 'product_id':productData.product_id,
                 'recurring_id':'0',
                 'option':options,
                 'quantity':parseInt(productData.minimum || 1),  // FIXED: Ensure numeric quantity
                 'gst_percent': gst_percent,
                 'tax_class_id': productData.tax_class_id || 0,
                 'excluded': false
             };
             var duplicate_check=false;
             pos_cart =[];
             if(localStorage.getItem(\"pos_cart\") != null){
                 pos_cart = JSON.parse(localStorage.getItem(\"pos_cart\"))
             }
             if(pos_cart.length){
                 \$.each(pos_cart,function(key,val){
                     if((parseInt(val.product_id)==parseInt(productData.product_id)) && (JSON.stringify(val.option) == JSON.stringify(options))){
                         // FIXED: Properly accumulate quantity
                         pos_cart[key]['quantity'] = parseInt(val.quantity) + parseInt(posCartData.quantity);
                         const row = document.querySelector('.cart-row[data-product-id=\"' + productData.product_id + '\"]');
                         if (!row) return;
                         let product = decodeProduct(row.dataset.product);
                         if (!product) return;
                         product.quantity = parseInt(product.quantity) + parseInt(posCartData.quantity);;
                         product.total = product.quantity * product.price;
                         row.dataset.product = encodeProduct(product);
                         duplicate_check=true;
                         return false;  // Break the loop
                     }
                 });
                 if(!duplicate_check){
                     pos_cart.push(posCartData);    
                 }
             } else {
                 pos_cart.push(posCartData);    
             }
             localStorage.setItem(\"pos_cart\", JSON.stringify(pos_cart));
             return JSON.parse(localStorage.getItem(\"pos_cart\"));
         }
         
