         function ptscustomerdata(customer_id){
             var customerSearchData = JSON.parse(sessionStorage.getItem(\"customerSData\"));
             
             if (customerSearchData) {
                 \$.each(customerSearchData, function(key, val){
                     if (val.customer_id == customer_id) {
         
                         sessionStorage.removeItem('shipping_address');
                         sessionStorage.removeItem('payment_address');
                         sessionStorage.setItem(\"currentCustomerData\", JSON.stringify(val));
         
                         \$('#customerNameInput').val(val.name);
                         \$('#customerMobileInput').val(val.telephone);
                         \$('#customerEmailInput').val(val.email || '');
                         \$('#creditLimitSpan').text(val.rewards || '0.00');
                         \$('#advancedAmountSpan').text(val.wallet || '0.00');
                         \$('#dueAmountSpan').text(val.due_amount || '0.00');
                         \$('#dueAmountSpan').attr('data-original', val.due_amount || '0.00');
                         globalDueAmount = parseFloat(val.due_amount || 0);

                        // Display Last Order Details
                        console.log(\"DEBUG: Customer Data Object:\", val);
                        console.log(\"DEBUG: last_order_id:\", val.last_order_id);
                        console.log(\"DEBUG: last_order_amount:\", val.last_order_total);

                        if (val.last_order_id && val.last_order_total) {
                            \$('#lastOrderDisplay').html('Your last order is ' + val.last_order_id + ' with invoice amount of ' + val.last_order_total).show();
                        } else {
                            \$('#lastOrderDisplay').hide();
                        }
          
                          // Dynamic enabling of settlement checkbox
                          if (globalDueAmount > 0) {
                              \$('#includeDAInTotal').prop('disabled', false);
                          } else {
                              \$('#includeDAInTotal').prop('disabled', true).prop('checked', false);
                          }

                         // â„–ÂŸÂšÂ€ FIX: Hide dropdown immediately
                         \$('#modal_customer_list').hide();
         
                         \$('#pos_customer_lists').hide(); // OPTIONAL extra safety
         
                         getCartProductHTML();
                         updateTotals(); // Refresh math
                         \$('.close').trigger('click');
                     }
                 });
             }
         }
         
