         \$(document).off('click', '#add_hold_order').on('click', '#add_hold_order', function () {
         
             // âœ… CART VALIDATION
             if (!localStorage.getItem(\"pos_cart\")) {
                 errorMessage(\"Warning: Cart is empty!\", 2000);
                 return;
             }
         
             // âœ… TABLE VALIDATION (PREVENT \"NO TABLE\" & SERVER ERROR)
             let table_id   = sessionStorage.getItem(\"selected_table_id\");
             let table_name = sessionStorage.getItem(\"selected_table_name\");
             let members    = sessionStorage.getItem(\"selected_table_members\");
         
             if (!table_id || !table_name) {
                 errorMessage(\"Please select table first!\", 2000);
                 return;
             }
         
             let cartProducts = JSON.parse(localStorage.getItem(\"pos_cart\"));
             let message = \$('#hold_order_msg').val();
         
             let customerData = sessionStorage.getItem(\"currentCustomerData\")
                 ? JSON.parse(sessionStorage.getItem(\"currentCustomerData\"))
                 : null;
         
             let finalCustomer = {
                 id: customerData ? customerData.customer_id : 0,
                 name: customerData ? customerData.name : \"Guest\",
                 message: message,
                 customerData: customerData || \"\"
             };
         
             // âœ… ORDER ID LOGIC (UPDATE vs NEW)
             let order_id = sessionStorage.getItem(\"selected_order_id\");
             let isNew = false;
         
             if (!order_id) {
                 order_id = uid();
                 sessionStorage.setItem(\"selected_order_id\", order_id);
                 isNew = true;
             }
         
             let payload = {
                 table_id: table_id,
                 table_name: table_name,
                 members: members,
                 message: message,
                 cart: cartProducts,
                 order_id: order_id
             };
         
             let url = isNew
                 ? \"index.php?route=extension/purpletree_pos/pos/home.createHoldOrder\"
                 : \"index.php?route=extension/purpletree_pos/pos/home.updateHoldOrder\";
         
             \$.ajax({
                 url: url,
                 type: \"POST\",
                 data: payload,
                 dataType: \"json\",
         
                 success: function (res) {
         
                     if (!res || res.status !== \"success\") {
                         //console.log(\"DB Error: \" + (res?.message || \"Unknown error\"));
                         return;
                     }
         
                     // âœ… UPDATE OR PUSH INTO HOLD CART
                     let hold_cart = JSON.parse(localStorage.getItem(\"hold_cart\") || \"[]\");
         
                     let existingIndex = hold_cart.findIndex(
                         x => x.table?.order_id == order_id
                     );
         
                     let newHoldObj = {
                         data: finalCustomer,
                         cart_data: cartProducts,
                         table: {
                             table_id: table_id,
                             table_name: table_name,
                             order_id: order_id,
                             members: members,
                             note: message,
                             timestamp: Date.now()
                         }
                     };
         
                     if (existingIndex > -1) {
                         hold_cart[existingIndex] = newHoldObj;   // âœ… UPDATE
                     } else {
                         hold_cart.push(newHoldObj);             // âœ… NEW
                     }
         
                     localStorage.setItem(\"hold_cart\", JSON.stringify(hold_cart));
         
                     // âœ… CLEAR POS CART ONLY
                     localStorage.removeItem(\"pos_cart\");
                     emptyCart();
                     getCartProductHTML();
                     pos_cart = [];
         
                     // âœ… UI RESET
                     \$('#hold-order').modal('hide');
                     \$(\"#tablesContent\").hide();
                     \$('#posCateProduct').empty().hide();
                     \$(\"#posCateProduct\").hide();
                     \$(\"#pos-popular\").hide();
                     \$(\".pos-search-div\").show();
         
                     \$('#posproduct').show().removeClass().addClass(\"hold-grid\").empty();
         
                     // âœ… RENDER HOLD CARDS
                     if (hold_cart.length > 0) {
                         \$.each(hold_cart, function (key, val) {
                             let tname = val.table?.table_name || \"NO TABLE\";
                             let oid   = val.table?.order_id || \"\";
                             let text  = val.data?.message || \"\";
         
                             let html = `
                                 <div class=\"hold-card\">
                                     <div class=\"title\">\${tname}
                                         <span style=\"color:#0ff;font-size:12px;\">#\${oid}</span>
                                     </div>
                                     <div class=\"desc\" style=\"margin-left:35px\">\${text.substring(0,20)}</div>
                                     <div class=\"icons\">
                                         <i class=\"fa fa-undo\" onclick=\"holdCartRestore(\${key})\"></i>
                                         <i class=\"fa fa-trash\" style=\"margin-left:65%\" onclick=\"confirmHoldDelete(\${key})\"></i>
                                     </div>
                                 </div>
                             `;
                             \$('#posproduct').append(html);
                         });
                     } else {
                         \$('#posproduct').append(`<div class=\"hold-card\">No Hold Orders Found</div>`);
                     }
         
                     // âœ… CLEAR SESSION **AFTER UI IS UPDATED**
                     sessionStorage.removeItem(\"selected_table_id\");
                     sessionStorage.removeItem(\"selected_table_name\");
                     sessionStorage.removeItem(\"selected_table_members\");
                     sessionStorage.removeItem(\"selected_order_id\");
                     sessionStorage.removeItem(\"current_hold_key\");
                 },
         
                 error: function (xhr) {
                     console.error(xhr.responseText);
                     //console.log(\"Server error! Please check API.\");
                 }
             });
         });
         
