         function confirmHoldDelete(key) {
             let hold_cart = JSON.parse(localStorage.getItem('hold_cart') || '[]');
             let entry = hold_cart[key];
             if (!entry) return;
         
             let table = entry.table?.table_name || \"Unknown Table\";
             let orderId = entry.table?.order_id || \"N/A\";
             let msg = entry.data?.message?.substring(0, 40) || \"No Message\";
         
             if (confirm(`You are going to delete:\\n\\nTable: \${table}\\nOrder ID: \${orderId}\\nMessage: \${msg}\\n\\nDo you want to delete this hold order?`)) {
                 // 1ï¸âƒ£ Delete (now safer)
                 holdCartDelete(key);
                 
                 // 2ï¸âƒ£ ENSURE hold cart view stays active
                 \$(\"#tablesContent\").hide();
                 \$('#invoiceContent').hide();
                 \$(\"#posCateProduct\").hide();
                 \$(\"#pos-popular\").hide();
                 \$(\".pos-search-div\").show();
                 \$('#posproduct').show();
                 getCartProductHTML();
                 // 3ï¸âƒ£ Reload fresh data & refresh UI
                 refreshHoldCartDisplay();
             }
         }
         
         // ðŸ”„ New helper function for clean hold cart refresh
         function refreshHoldCartDisplay() {
             let hold_cart = JSON.parse(localStorage.getItem('hold_cart') || '[]');
             
             // Reset container completely
             \$('#posproduct').removeClass().addClass(\"hold-grid\").empty();
             
             if (hold_cart.length > 0) {
                 \$.each(hold_cart, function (idx, val) {
                     let table_name = (val.table && val.table.table_name) ? val.table.table_name : \"NO TABLE\";
                     let order_id = val.table?.order_id || \"\";
                     let text = val.data?.message || \"\";
                     let messageShort = text.substring(0, 20);
         
                     let html = `
                         <div class=\"hold-card\">
                             <div class=\"title\">\${table_name} 
                                 <span style=\"color:#0ff;font-size:12px;\">#\${order_id}</span>
                             </div>
                             <div class=\"desc\" style=\"margin-left:35px\">\${messageShort}</div>
                             <div class=\"icons\">
                                 <i class=\"fa fa-undo\" onclick=\"holdCartRestore(\${idx})\" title=\"Restore\"></i>
                                 <i class=\"fa fa-trash\" style=\"margin-left:65%\" onclick=\"confirmHoldDelete(\${idx})\" title=\"Delete\"></i>
                             </div>
                         </div>
                     `;
                     \$('#posproduct').append(html);
                 });
             } else {
                 \$('#posproduct').append(`<div class=\"hold-card\">No Hold Orders Found</div>`);
             }
         }
         
         
         function saveHoldLocally(message, cartProducts, customerData) {
         
             let table_id    = sessionStorage.getItem(\"selected_table_id\");
             let table_name  = sessionStorage.getItem(\"selected_table_name\");
             let members     = sessionStorage.getItem(\"selected_table_members\");
             let order_id    = sessionStorage.getItem(\"selected_order_id\");
         
             let hold_cart = JSON.parse(localStorage.getItem(\"hold_cart\") || \"[]\");
         
             hold_cart.push({
                 data: {
                     id: customerData ? customerData.customer_id : 0,
                     name: customerData ? customerData.name : \"Guest\",
                     message: message,
                     customerData: customerData || \"\"
                 },
                 cart_data: cartProducts,
                 table: {
                     table_id: table_id,
                     table_name: table_name,
                     order_id: order_id,
                     members: members,
                     note: message,
                     timestamp: Date.now()
                 }
             });
         
             localStorage.setItem(\"hold_cart\", JSON.stringify(hold_cart));
         
             // clear sessions, close modal, reload UI  
             \$('#hold-order').modal('hide');
             holdCartArea();
             getCartProductHTML();
         }
         
