             if (!qtyInput || !totalCell) return;
         
             var qty        = parseInt(qtyInput.value) || 1;
             var rowTotal   = parseFloat(totalCell.textContent.replace(/[^\\d.]/g, '')) || 0;
             var discText   = discountCell ? discountCell.textContent.trim() : '0';
             var rowDiscountPerUnit = parseFloat(discText.replace(/[^\\d.]/g, '')) || 0;
         
             quantity += qty;
             items    += 1;
         
             // reverse discount (per unit) to get original line subtotal
             var rowDiscountTotal = rowDiscountPerUnit * qty;
             subTotal += rowTotal + rowDiscountTotal;
             discount += rowDiscountTotal;
         });
         
        
         var netTotalElement  = document.getElementById('netTotalValue'); // Net
