         function clearCustomerSession() {
             // 1. Remove session storage items
             sessionStorage.removeItem('currentCustomerData');
             sessionStorage.removeItem('customerSData');
             sessionStorage.removeItem('payment_address');
             sessionStorage.removeItem('shipping_address');
             
             // 2. Clear input fields
             if (\$('#customerNameInput').length) \$('#customerNameInput').val('');
             if (\$('#customerMobileInput').length) \$('#customerMobileInput').val('');
             if (\$('#customerEmailInput').length) \$('#customerEmailInput').val('');
             
             // 3. Reset credit/advance displays
             if (\$('#creditLimitSpan').length) \$('#creditLimitSpan').text('0.00');
             if (\$('#advancedAmountSpan').length) \$('#advancedAmountSpan').text('0.00');
             if (\$('#dueAmountSpan').length) \$('#dueAmountSpan').text('0.00');
             if (\$('#dueAmountInput').length) \$('#dueAmountInput').val('');
             if (\$('#dueAmountInvoice').length) \$('#dueAmountInvoice').prop('checked', false);
             if (\$('#dueAmountWrapper').length) \$('#dueAmountWrapper').hide();
             
             // 4. Reset global variable
             if (typeof globalAdvanceAmount !== 'undefined') {
                 globalAdvanceAmount = 0;
                 globalDueAmount = 0;
             }
             
             // 5. Hide and clear dropdowns
             if (\$('#modal_customer_list').length) {
                 \$('#modal_customer_list').empty().hide();
             }
             if (\$('#all_customers_dropdown').length) {
                 \$('#all_customers_dropdown').empty().hide();
             }
             
             // 6. Clear error messages
             if (\$('#phoneError').length) \$('#phoneError').text('');
             if (\$('#nameError').length) \$('#nameError').text('');
             
             // 7. Clear any applied credit points
             const creditCheckbox = document.getElementById('creditLimitInvoice');
             if (creditCheckbox && creditCheckbox.checked) {
                 creditCheckbox.checked = false;
                 removeCreditPoints();
             }
             
             // 8. Re-enable advance checkbox if it was disabled
             const advanceCheckbox = document.getElementById('advancedAmountInvoice');
             if (advanceCheckbox) {
                 advanceCheckbox.checked = false;
                 advanceCheckbox.disabled = true; // Disable since no advance available now
             }
             
             //console.log('âœ“ Customer session cleared successfully');
         }

         // --- NEW: REFINED UPI QR CODE GENERATION LOGIC (MANUAL TRIGGER) ---
          window.generateUpiQrCode = function() {
             const upiInput = document.getElementById('upiAmount');
             const qrSelContainer = document.getElementById('qrSelectionContainer');
             const qrContent = document.getElementById('upiQrContent');
             
             let amount = parseFloat(upiInput.value) || 0;
             if (amount <= 0) {
                 alert('Please enter amount in UPI box');
                 return;
             }

             // Hide QR content and show selection
             if (qrContent) qrContent.style.display = 'none';
             if (qrSelContainer) qrSelContainer.style.display = 'block';
             
             // Reset radio buttons
             const rbs = document.getElementsByName('qr_type');
             for (let rb of rbs) rb.checked = false;
              
             // Auto-select First QR and trigger generation
             const qr1 = document.getElementById('qr_type_1');
             if (qr1) {
                 qr1.checked = true;
                 triggerQrGeneration();
             }
          }

           window.triggerQrGeneration = function() {
              const upiInput = document.getElementById('upiAmount');
              const qrContent = document.getElementById('upiQrContent');
              const qrImg = document.getElementById('upiQrImg');
              const qrPlaceholderAmt = document.getElementById('upiQrAmountPlaceholder');
              const qrType2 = document.getElementById('qr_type_2');
              let amount = parseFloat(upiInput.value) || 0;
              // Use rupees (with 2 decimals) so the generated QR amount matches what the user entered.
              // (Some backends expect paise; if that ever needs to change, adjust here.)
              const amountForApi = amount.toFixed(2);

              // Debugging: log what we're sending so we can verify correct unit conversion.
              console.log(\"UPI QR: entered amount=\", amount, \"rupees; amountForApi=\", amountForApi);
              let apiUrl = 'index.php?route=extension/purpletree_pos/pos/home|generateUpiQr';
              if (qrType2 && qrType2.checked) {
                 apiUrl = 'index.php?route=extension/purpletree_pos/pos/home|generateUpiQr1';
              }

              if (qrImg) qrImg.style.opacity = '0.3';
              if (qrContent) qrContent.style.display = 'block';

              \$.ajax({
                 url: apiUrl,
                 type: 'POST',
                 data: { amount: amountForApi },
                 success: function(json) {
                    if (json.status === 'success' && json.qr_image) {
                       if (qrPlaceholderAmt) qrPlaceholderAmt.textContent = amount.toFixed(2);
                       if (qrImg) {
                          qrImg.src = json.qr_image;
                          qrImg.style.opacity = '1';
                          qrImg.style.maxWidth = '180px';
                          // Keep the latest QR image so DQ12 can render the exact same QR
                          window.latestUpiQrData = json.qr_image;
                       }
                       if (qrContent) {
                          qrContent.classList.remove('upi-qr-blur');
                          qrContent.classList.add('upi-qr-unblur');
                       }
                       
                       // INTEGRATE: Display QR on DQ12 device
                       if (typeof displayQrDQ12 === 'function') {
                         displayQrDQ12();
                         console.log(\"DQ12 QR displayed\");
                       }
                       
                    } else {
                       alert('Error generating QR: ' + (json.message || 'Unknown error'));
                     
                    }
                 },
                 error: function() {
                    alert('Network error while generating QR code.');
                   
                 }
              });
           }

           
         

