// Shared payment logic
function processOrderPayment(btn, shouldPrint) {
    // 🔒 HARD LOCK
    if (btn.dataset.locked === '1') return;
    btn.dataset.locked = '1';
    btn.disabled = true;
    btn.dataset.originalText = btn.innerText; // Save original text
    btn.innerText = 'Processing...';

    function getElementValue(id) {
      const el = document.getElementById(id);
      if (!el) return '';
      return ('value' in el) ? el.value : el.textContent.trim();
    }

    /* ===============================
       CUSTOMER VALIDATION (SYNC)
    =============================== */

    const customerData = JSON.parse(sessionStorage.getItem('currentCustomerData') || '{}');

    const name = \$('#customerNameInput').val().trim()
      || ((customerData.firstname || '') + ' ' + (customerData.lastname || '')).trim();

    const phone = \$('#customerMobileInput').val().trim() || customerData.telephone || '';
    const email = \$('#customerEmailInput').val().trim() || customerData.email || '';

    \$('#nameError').text('');
    \$('#phoneError').text('');

    if (!name) {
      \$('#nameError').text('Please enter customer name.');
      unlockPayBtn(btn);
      return;
    }

    if (!phone) {
      \$('#phoneError').text('Please enter mobile number.');
      unlockPayBtn(btn);
      return;
    }

    /* ===============================
       CART READ + VALIDATE (SYNC)
    =============================== */

    const cartProducts = getCartProductsFromDOMSync();
    if (!cartProducts) {
      unlockPayBtn(btn);
      return;
    }

    /* ===============================
       PAYMENT VALIDATION (SYNC)
    =============================== */

    const creditPointsUsed = sessionStorage.getItem('credit_points_used')
      ? parseFloat(JSON.parse(sessionStorage.getItem('credit_points_used')))
      : 0;

    const cashAmt = parseFloat(getElementValue('cashAmount')) || 0;
    const upiAmt  = parseFloat(getElementValue('upiAmount')) || 0;
    const advAmt  = parseFloat(getElementValue('advanceAmount')) || 0;

    let paymentThrough = [];
    if (cashAmt > 0) paymentThrough.push(\"CASH\");
    if (upiAmt  > 0) paymentThrough.push(\"UPI\");
    if (advAmt  > 0) paymentThrough.push(\"ADVANCE\");
    paymentThrough = paymentThrough.join(\", \") || \"NONE\";

    const pendingAmount = parseFloat(
      (getElementValue('pendingAmount') || '0').replace(/[^0-9.-]/g, '')
    ) || 0;

    if (pendingAmount > 0) {
      alert('Please clear pending amount before proceeding!');
      unlockPayBtn(btn);
      return;
    }

    /* ===============================
       RETURN ORDER (SYNC)
    =============================== */

    let previousOrderId = 0;
    let activeQuoteId = '';
    let previourseditorderid = 0;
    const currentReturnOrder = sessionStorage.getItem('currentReturnOrder');
    const currentQuotationOrder = sessionStorage.getItem('currentQuotationOrder');
    const currentEditOrderSession = sessionStorage.getItem('currentEditOrder');

    if (currentReturnOrder) {
      try {
        const r = JSON.parse(currentReturnOrder);
        previousOrderId = r?.order_info?.order_id || 0;
      } catch (e) {}
    } else if (currentQuotationOrder) {
      try {
        const q = JSON.parse(currentQuotationOrder);
        previousOrderId = q?.order_info?.order_id || 0;
        activeQuoteId = q?.quote_info?.order_id || q?.quote_info?.quote_id || q?.order_id || q?.quote_id || '';
      } catch (e) {}
    }

    if (currentEditOrderSession) {
      try {
        const e = JSON.parse(currentEditOrderSession);
        previourseditorderid = e?.order_info?.order_id || 0;
      } catch (e) {}
    }

    /* ===============================
       CUSTOMER CREATE (ASYNC)
    =============================== */

    createNewCustomerIfNeeded()
      .then(function (customerId) {

        const orderDetails = {
          customerIdNumber: customerId,
          CustomerName: name,
          Mobile: phone,
          Email: email,

          AvailableCreditPoints: document.getElementById('creditLimitSpan')?.textContent || '0.00',
          CreditPointsUsed: creditPointsUsed,
          AvailableAdvancedAmount: document.getElementById('advancedAmountSpan')?.textContent || '0.00',

          CartProducts: cartProducts.map(p => {
            const gstPercent = parseFloat(p.gst_percent || 0);
            const linePrice = parseFloat(p.price || 0) * parseInt(p.quantity || 1);
            const rowGst = (gstPercent / 100) * linePrice;
            
            // Calculate discount percentage if available
            const discountPercent = parseFloat(p.gst_percent || 0);
            
            
            return {
              cartId: p.cart_id ?? null,
              product_id: p.product_id,
              name: p.name || p.heading_title || '',
              price: p.price ?? null,
              
              discount_percent: discountPercent,
              total: p.total ?? null,
              gst_percent: gstPercent,
              row_gst: parseFloat(rowGst.toFixed(2)),
              reward: p.reward ?? 0,
              quantity: p.quantity ?? 1,
              pos_quantity: p.pos_quantity ?? 0,
              excluded: p.excluded || false
            };
          }),

          InvoiceInfo: {
            SUBTotal: getElementValue('subTotal'),
            DiscountIncluded: getElementValue('discountIncluded'),
            TaxIncluded: getElementValue('taxIncluded'),
            TotalBeforeRoundoff: getElementValue('totalBeforeRoundoff'),
            RoundOffAmount: getElementValue('roundOffAmount'),
            QuantityTotal: getElementValue('quantityTotal'),
            NumberOfItems: getElementValue('numberOfItems'),
            credits_for_order: getElementValue('creditsOrder'),
            Coupon: getElementValue('couponCodeInvoice'),
            CouponAmount: (parseFloat(getElementValue('subTotal').replace(/[^0-9.-]/g, '')) - parseFloat(getElementValue('grandTotal').replace(/[^0-9.-]/g, ''))).toFixed(2),
            TotalTax: getElementValue('taxIncluded'),
            Total: getElementValue('grandTotal'),
            InvoiceDate: getElementValue('invoiceDate'),
            SalesExcutiveEmail: getElementValue('salesExcutiveEmail'),
            SalesExcutiveId: getElementValue('salesExcutiveId'),
            InvoiceNumber: getElementValue('invoiceNumber')
          },

          PaymentThrough: paymentThrough,
          CashAmount: cashAmt,
          UPIAmount: upiAmt,
          AdvanceUsed: advAmt,
          Note: getElementValue('orderNote'),
          SellerId: getElementValue('sellerId'),
          TotalReceivedAmount: getElementValue('totalReceived'),
          PendingAmount: getElementValue('pendingAmount'),
          ReturnableBalance: getElementValue('returnableBalance'),

          DueAmountUsed: document.getElementById('dueAmountInvoice')?.checked || false,
          DueAmountValue: parseFloat(getElementValue('dueAmountInput')) || 0,
          includedDA: document.getElementById('includeDAInTotal')?.checked || false,
          includedDAAmount: parseFloat(getElementValue('includeDAAmount')) || 0,
 
          SaveReturnableAsAdvance: document.getElementById('saveAdvance')?.checked || false,
          previousOrderId: previousOrderId,
          activeQuoteId: activeQuoteId,
          previourseditorderid: previourseditorderid,
          redeem_points_status: document.getElementById('creditLimitInvoice')?.checked || false
        };

        sessionStorage.setItem('paidOrderDetails', JSON.stringify(orderDetails));
        console.log(\"order details \", orderDetails);
        \$.ajax({
          url: 'index.php?route=extension/purpletree_pos/pos/home|addorder',
          type: 'POST',
          dataType: 'json',
          contentType: 'application/json',
          processData: false,
          data: JSON.stringify({ orderDetails }),

          success: function (json) {
            if (json.status === 'success') {

              localStorage.setItem('last_order_id', json.order_id);

              sessionStorage.removeItem('paidOrderDetails');
              sessionStorage.removeItem('currentCustomerData');
              sessionStorage.removeItem('cartProductsData');
              sessionStorage.clear();

              \$('#modalXl').modal('hide');

              localStorage.setItem('lastConfirmedOrder', JSON.stringify(orderDetails));

              // INTEGRATE: Display Success on DQ12 device
              if (typeof generateSuccessDQ12 === 'function') {
                generateSuccessDQ12();
                console.log(\"DQ12 success display triggered\");
              }

              // ONLY PRINT IF REQUESTED
              if (shouldPrint) {
                  printInvoice();
                  emptyCart();
                  refreshPage();
              } else {
                  // Save Order: Send WhatsApp ONLY and then reload
                  sendWhatsAppOnly(json.order_id);
                  emptyCart();
              }

              if (sessionStorage.getItem('currentholdkey') !== null) {
                const key = sessionStorage.getItem('currentholdkey');
                if (typeof holdCartDeleteonReload === 'function') {
                  holdCartDeleteonReload(key);
                }
                sessionStorage.removeItem('currentholdkey');
              }

              successMessage(json.message, 4000);

              localStorage.removeItem(\"pos_cart\");
              document.getElementById('cartArea').innerHTML = '';

              window.alreadyPaidAmount = 0;
              sessionStorage.removeItem('currentReturnOrder');
              sessionStorage.removeItem('currentQuotationOrder');
              sessionStorage.removeItem('currentEditOrder');

            } else {
              alert(json.message || \"Order failed\");
              unlockPayBtn(btn);
            }
          },

          error: function () {
            unlockPayBtn(btn);
          }
        });

      })
      .catch(function (err) {
        alert(err || 'Customer creation failed');
        unlockPayBtn(btn);
      });
}

// helper to disable the other two footer buttons once one is clicked
function disableFooterButtons(clickedId) {
    ['saveOrderBtn','payNowBtn','cancelPaymentBtn'].forEach(function(id) {
        if (id !== clickedId) {
            var btn = document.getElementById(id);
            if (btn) btn.disabled = true;
        }
    });
}

setTimeout(function () {
  const payBtn = document.getElementById('payNowBtn');
  if (payBtn) {
    payBtn.onclick = function () {
        disableFooterButtons('payNowBtn');
        processOrderPayment(this, true); // true = Print
    };
  }
  
  const saveBtn = document.getElementById('saveOrderBtn');
  if (saveBtn) {
    saveBtn.onclick = function () {
        disableFooterButtons('saveOrderBtn');
        processOrderPayment(this, false); // false = No Print
    };
  }

  const cancelBtn = document.getElementById('cancelPaymentBtn');
  if (cancelBtn) {
      cancelBtn.onclick = function() {
          disableFooterButtons('cancelPaymentBtn');
          clearCustomerSession();
      };
  }
}, 500);


