         function printSmallInvoice() {
    let orderId = localStorage.getItem('last_order_id');
    if (!orderId) return;

    \$.ajax({
        url: \"index.php?route=extension/purpletree_pos/pos/home|invoice\"
            + \"&order_id=\" + encodeURIComponent(orderId)
            + \"&small_print=1\",
        type: \"GET\",
        success: function (html) {

            /* ------------------ PRINT LOGIC ------------------ */
            let iframe = document.createElement('iframe');
            iframe.style.position = 'fixed';
            iframe.style.right = '0';
            iframe.style.bottom = '0';
            iframe.style.width = '0';
            iframe.style.height = '0';
            iframe.style.border = '0';
            document.body.appendChild(iframe);

            iframe.onload = function () {
                iframe.contentWindow.focus();
                iframe.contentWindow.print();

                setTimeout(() => {
                    document.body.removeChild(iframe);
                }, 1000);
            };

            iframe.contentDocument.open();
            iframe.contentDocument.write(html);
            iframe.contentDocument.close();

            /* ------------------ PHONE NORMALIZATION ------------------ */
            let rawPhone =
                \$('#customerMobileInput').val()?.trim() ||
                (JSON.parse(sessionStorage.getItem('currentCustomerData') || '{}').telephone || '');

            rawPhone = rawPhone.replace(/\\s+/g, '').replace(/^\\+/, '');

            if (rawPhone.startsWith('0')) {
                rawPhone = rawPhone.substring(1);
            }

            if (rawPhone && !rawPhone.startsWith('91')) {
                rawPhone = '91' + rawPhone;
            }

            if (!rawPhone) {
                console.warn('Customer phone not found, skipping WhatsApp');
                return;
            }

            /* ------------------ WHATSAPP API ------------------ */
            \$.ajax({
                url:
                    \"index.php?route=extension/purpletree_pos/pos/home|Order_sendwhatsapp\"
                    + \"&order_id=\" + encodeURIComponent(orderId)
                    + \"&phone=\" + encodeURIComponent(rawPhone),
                type: \"GET\",
                dataType: \"json\",
                success: function (res) {
                    console.log('WhatsApp sent:', res);

                    setTimeout(() => {
                        location.reload();
                    }, 500);
                },
                error: function () {
                    setTimeout(() => {
                        location.reload();
                    }, 500);
                }
            });
        },
        error: function () {
            console.error(\"Failed to load small invoice.\");
        }
    });
}
