                     // Individual checkbox handler
                     \$(document).off('change', '.merge-bill-checkbox').on('change', '.merge-bill-checkbox', function() {
                         var totalCheckboxes = \$('.merge-bill-checkbox').length;
                         var checkedCheckboxes = \$('.merge-bill-checkbox:checked').length;
                         \$('#selectAllMergeBill').prop('checked', totalCheckboxes === checkedCheckboxes);
                     });
