          function triggerSmallPrint() {
              if (typeof allInvoiceData === 'undefined' || !allInvoiceData || !allInvoiceData.length) {
                  toastr.warning('No invoice data available to print. Please search first.');
                  return;
              }

              var orderId = \$('#invoice_id_search').val().trim().toLowerCase();
              var mobile  = \$('#invoice_mobile_search').val().trim().toLowerCase();
              var name    = \$('#invoice_name_search').val().trim().toLowerCase();

              var filteredData = allInvoiceData.filter(function(row) {
                  var matchId     = orderId === '' || row.order_info.order_id.toString().toLowerCase().includes(orderId);
                  var matchMobile = mobile  === '' || (row.order_info.telephone || '').toString().toLowerCase().includes(mobile);
                  var fullName    = ((row.order_info.firstname || '') + ' ' + (row.order_info.lastname || '')).toLowerCase();
                  var matchName   = name    === '' || fullName.includes(name);
                  return matchId && matchMobile && matchName;
              });

              if (!filteredData.length) {
                  toastr.warning('No matching records to print.');
                  return;
              }

              // Prefer API-provided totals (status5 = Completed) instead of recalculating in the front-end
              const apiTotals = window.invoiceApiTotals || {};
              const printTotals = {
                  cash: parseFloat(apiTotals.status5_cash || 0),
                  upi: parseFloat(apiTotals.status5_upi || 0),
                  ra: parseFloat(apiTotals.status5_returnable || 0),
                  due: parseFloat(apiTotals.status5_balance || 0),
                  sbt: parseFloat(apiTotals.status5_subtotal || 0),
                  rc: parseFloat(apiTotals.status5_total_received || 0),
              };

              var payload = {
                  cash: printTotals.cash.toFixed(2),
                  upi: printTotals.upi.toFixed(2),
                  ra: printTotals.ra.toFixed(2),
                  rc: printTotals.rc.toFixed(2),
                  due: printTotals.due.toFixed(2),
                  sbt: printTotals.sbt.toFixed(2),
                  total_orders: filteredData.length,
              };
                console.log(\"small print details: \", payload);
              \$.ajax({
                  url: 'index.php?route=extension/purpletree_pos/pos/home|processSmallPrint',
                  type: 'POST',
                  data: payload,
                 
                  beforeSend: function() {
                       if (typeof showPremiumLoader === 'function') showPremiumLoader();
                  },
                  complete: function() {
                       if (typeof hidePremiumLoader === 'function') hidePremiumLoader();
                  },
                  success: function (html) {

                    let iframe = document.createElement('iframe');
                    iframe.style.position = 'fixed';
                    iframe.style.right = '0';
                    iframe.style.bottom = '0';
                    iframe.style.width = '0';
                    iframe.style.height = '0';
                    iframe.style.border = '0';
                
                    // IMPORTANT: put HTML into iframe
                    iframe.srcdoc = html;
                
                    document.body.appendChild(iframe);
                
                    iframe.onload = function () {
                        iframe.contentWindow.focus();
                        iframe.contentWindow.print();
                
                        setTimeout(() => {
                            document.body.removeChild(iframe);
                        }, 1000);
                    };
                
                    toastr.success('Small Print sent to printer!');
                },
                  error: function() {
                      toastr.error('Error sending print request. Backend API might be missing.');
                  }
              });
              
          }
         
       
       
