        \$(document).off('click', '#searchProductBtn').on('click', '#searchProductBtn', function() {
            const sku = \$('#manage_product_search_input').val().trim();
            if (!sku) {
                errorMessage('Please enter or scan a product SKU/Barcode', 2000);
                return;
            }
            searchManageProduct(sku);
        });

        \$(document).off('click', '#addManagedProductBtn').on('click', '#addManagedProductBtn', function() {
