        function saveProductDetails() {

    const productId = \$('#manage_product_id').val();
    const isNew = !productId;

    const barcodeType = \$('#manage_product_barcode_type').val();
    const barcodeValue = \$('#manage_product_sku').val();

    let sku = '';
    let upc = '';

    if (barcodeType === 'unit') {
        sku = barcodeValue;
    } else if (barcodeType === 'box') {
        upc = barcodeValue;
    }

    const formData = {
        product_id: productId,
        barcode_type: barcodeType,
        product_description: {
            1: {
                name: \$('#manage_product_name').val()
            }
        },
        sku: sku,
        upc: upc,
        model: \$('#manage_product_model').val(),
        category_name: \$('#manage_product_category').val(),
        category_id: \$('#manage_product_category_id').val(),
        box_id: \$('#manage_product_box_id').val(),
        price: \$('#manage_product_price').val(),
        wholesale_price: \$('#manage_product_wholesale_price').val(),
        additional_price: \$('#manage_product_additional_price').val(),
        pos_quentity: \$('#manage_product_quantity').val(),
        max_quantity: \$('#manage_product_box_details').val()
    };

    showPremiumLoader();

    \$.ajax({
        url: 'index.php?route=product/addproducts.addProduct',
        type: 'POST',
        data: formData,
        dataType: 'json',
        success: function(res) {
            hidePremiumLoader();
            if (res && res.success) {
                successMessage(isNew ? 'Product added successfully' : 'Product updated successfully', 3000);
                 \$('#manage_product_search_input').val(''); // Clear the search input
            renderProductForm(null); // Clear form for new product
            } else {
                errorMessage(res.error ? JSON.stringify(res.error) : 'Failed to save product', 3000);
            }
        }
    });
}



        function loadCancelOrderData() {
            var from = \$('#cancel_from_date').val();
            var to = \$('#cancel_to_date').val();
            var orderId = \$('#cancel_order_id').val().trim().toLowerCase();
            var mobile = \$('#cancel_mobile_search').val().trim().toLowerCase();
            var name = \$('#cancel_name_search').val().trim().toLowerCase();

            \$.ajax({
                url: 'index.php?route=extension/purpletree_pos/pos/home|getOrdersbyDate',
                beforeSend: function() { showPremiumLoader(); },
                complete: function() { hidePremiumLoader(); },
                type: 'GET',
                dataType: 'json',
                data: { from_date: from, to_date: to, order_id: orderId, mobile: mobile, name: name },
                success: function (res) {
                    if (!res || !res.data || !res.data.length) {
                        \$('#cancelOrderResults').html('<p style=\"color:white; padding:10px;\">No orders found.</p>');
                        allCancelOrderData = [];
                        return;
                    }

                    allCancelOrderData = res.data;
                    
                    var filteredData = allCancelOrderData.filter(function (row) {
                        var matchId = orderId === '' || row.order_info.order_id.toString().toLowerCase().includes(orderId);
                        var matchMobile = mobile === '' || (row.order_info.telephone || '').toString().toLowerCase().includes(mobile);
                        var fullName = ((row.order_info.firstname || '') + ' ' + (row.order_info.lastname || '')).toLowerCase();
                        var matchName = name === '' || fullName.includes(name);
                        
                        return matchId && matchMobile && matchName;
                    });

                    if (filteredData.length > 0) {
                        displayCancelOrderTable(filteredData);
                    } else {
                        \$('#cancelOrderResults').html('<p style=\"color:white; padding:10px;\">No results found matching your search criteria.</p>');
                    }
                },
                error: function (xhr, status, err) {
                    \$('#cancelOrderResults').html('<p style=\"color:red; padding:10px;\">Error loading orders.</p>');
                    allCancelOrderData = [];
                }
            });
        }

        function displayCancelOrderTable(data) {
            var html = ''
                + '<table id=\"cancelOrderTable\" class=\"table table-bordered table-dark mt-3\">'
                + '  <thead>'
                + '    <tr>'
                + '      <th style=\"background-color: white;color: black;\">Sl.No</th>'
                + '      <th style=\"background-color: white;color: black;\">Order</th>'
                + '      <th style=\"background-color: white;color: black;\">Date</th>'
                + '      <th style=\"background-color: white;color: black;\">Mobile</th>'
                + '      <th style=\"background-color: white;color: black;\">Subtotal</th>'
                + '      <th style=\"background-color: white;color: black;\">Tax</th>'
                + '      <th style=\"background-color: white;color: black;\">Received</th>'
                + '      <th style=\"background-color: white;color: black;\">PaymentMethod</th>'
                + '      <th style=\"background-color: white;color: black;\">SellerId</th>'
                + '      <th style=\"background-color: white;color: black;\">Status</th>'
                + '      <th style=\"background-color: white;color: black;\">Action</th>'
                + '    </tr>'
                + '  </thead>'
                + '  <tbody>';

            data.forEach(function (row, idx) {
                let paymentHTML = \"\";
                let methods = (row.invoice.amount_through || \"\").split(',');

                methods.forEach(function (m) {
                    m = m.trim().toUpperCase();
                    if (m === \"CASH\") paymentHTML += 'CASH: ₹ ' + row.invoice.cash_amount + ' ';
                    if (m === \"UPI\")  paymentHTML += '| UPI: ₹ ' + row.invoice.upi_amount + ' ';
                    if (m === \"CARD\") paymentHTML += '| CARD: ₹ ' + (row.invoice.card_amount || '0.00') + ' ';
                });

                var statusId = parseInt(row.order_info.order_status_id || row.order_info.order_status || 0, 10);
                var isCancelled = (statusId === 7);
                var btnLabel = isCancelled ? 'Cancelled' : 'Cancel';
                var btnDisabledAttr = isCancelled ? ' disabled' : '';
                var btnClass = isCancelled ? 'btn-secondary' : 'btn-danger cancel-order-action-btn';

                html += ''
                    + '<tr class=\"cancel-order-row\" data-order-id=\"' + row.order_info.order_id + '\">'
                    + '  <td style=\"background-color: white;color: black;\">' + (idx + 1) + '</td>'
                    + '  <td style=\"background-color: white;color: black;\">' + row.order_info.order_id + '</td>'
                    + '  <td style=\"background-color: white;color: black;\">' + row.order_info.date_added + '</td>'
                    + '  <td style=\"background-color: white;color: black;\">' + row.order_info.telephone + '</td>'
                    + '  <td style=\"background-color: white;color: black;\">' + row.invoice.sub_total + '</td>'
                    + '  <td style=\"background-color: white;color: black;\">' + row.invoice.total_tax + '</td>'
                    + '  <td style=\"background-color: white;color: black;\">' + row.invoice.total_received + '</td>'
                    + '  <td style=\"background-color: white;color: black;\">' + paymentHTML + '</td>'
                    + '  <td style=\"background-color: white;color: black;\">' + row.order_info.sellerId + '</td>'
                    + '  <td style=\"background-color: white;color: black;\">' + (row.order_info.order_status || 'null') + '</td>'
                    + '  <td style=\"background-color: white;color: black;\">'
                    + '      <button class=\"btn btn-sm ' + btnClass + '\" data-order-id=\"' + row.order_info.order_id + '\"' + btnDisabledAttr + '>'
                    +            btnLabel
                    + '      </button>'
                    + '  </td>'
                    + '</tr>';
            });

            html += '  </tbody></table>';
             html += '<div id=\"cancelPager\" style=\"margin-top:-15px; text-align:right;display: flex; justify-content: end;\">'
                   + '  <button type=\"button\" id=\"canFirst\" class=\"btn btn-sm btn-secondary me-1\">Start</button>'
                   + '  <button type=\"button\" id=\"canPrev\"  class=\"btn btn-sm btn-secondary me-1\"> < </button>'
                   + '  <button type=\"button\" id=\"canNext\"  class=\"btn btn-sm btn-secondary me-1\"> > </button>'
                   + '  <button type=\"button\" id=\"canLast\"  class=\"btn btn-sm btn-secondary\">End</button>'
                   + '</div>';

            \$('#cancelOrderResults').html(html);

             // Pagination
            var \$rows      = \$('#cancelOrderTable tbody tr');
            var perPage    = 10;
            var pageCount  = Math.ceil(\$rows.length / perPage);
            var current    = 1;

            function renderPage(page) {
                if (page < 1) page = 1;
                if (page > pageCount) page = pageCount;
                current = page;

                \$rows.hide();
                var start = (page - 1) * perPage;
                var end   = start + perPage;
                \$rows.slice(start, end).show();
            }

            renderPage(1);

            \$('#canFirst').off('click').on('click', function () { renderPage(1); });
            \$('#canPrev').off('click').on('click', function () { renderPage(current - 1); });
            \$('#canNext').off('click').on('click', function () { renderPage(current + 1); });
            \$('#canLast').off('click').on('click', function () { renderPage(pageCount); });
        }

