          function loadEditOrderData(callback) {
              var from = \$('#edit_from_date').val();
              var to = \$('#edit_to_date').val();
              var orderId = \$('#edit_order_id_search').val().trim().toLowerCase();
              var mobile = \$('#edit_mobile_search').val().trim().toLowerCase();
              var name = \$('#edit_name_search').val().trim().toLowerCase();

              \$.ajax({
                  url: 'index.php?route=extension/purpletree_pos/pos/home|getOrdersbyDate',
                  beforeSend: function() { showPremiumLoader(); },
                  complete: function() { hidePremiumLoader(); },
                  type: 'GET',
                  dataType: 'json',
                  data: { from_date: from, to_date: to, order_id: orderId, mobile: mobile, name: name },
                  success: function (res) {
                      if (!res || !res.data || !res.data.length) {
                          \$('#editOrderResults').html('<p style=\"color:white; padding:10px;\">No orders found.</p>');
                          allEditOrderData = [];
                          return;
                      }
                      allEditOrderData = res.data;
                      var filteredData = allEditOrderData.filter(function (row) {
                          var matchId = orderId === '' || row.order_info.order_id.toString().toLowerCase().includes(orderId);
                          var matchMobile = mobile === '' || (row.order_info.telephone || '').toString().toLowerCase().includes(mobile);
                          var fullName = ((row.order_info.firstname || '') + ' ' + (row.order_info.lastname || '')).toLowerCase();
                          var matchName = name === '' || fullName.includes(name);
                          return matchId && matchMobile && matchName;
                      });
                      if (filteredData.length > 0) {
                          displayEditOrderTable(filteredData);
                      } else {
                          \$('#editOrderResults').html('<p style=\"color:white; padding:10px;\">No results found matching your search criteria.</p>');
                      }

                      if (typeof callback === 'function') {
                          callback();
                      }
                  },
                  error: function () {
                      \$('#editOrderResults').html('<p style=\"color:red; padding:10px;\">Error loading orders.</p>');
                      allEditOrderData = [];
                      if (typeof callback === 'function') {
                          callback();
                      }
                  }
              });
          }

          function displayEditOrderTable(data) {
