                  + '  <thead>'
                  + '    <tr>'
                  + '      <th style=\"background-color: white;color: black;\">Sl.No</th>'
                  + '      <th style=\"background-color: white;color: black;\">Order</th>'
                  + '      <th style=\"background-color: white;color: black;\">Date</th>'
                  + '      <th style=\"background-color: white;color: black;\">Mobile</th>'
                  + '      <th style=\"background-color: white;color: black;\">Total</th>'
                  + '      <th style=\"background-color: white;color: black;\">Status</th>'
                  + '      <th style=\"background-color: white;color: black;\">Action</th>'
                  + '    </tr>'
                  + '  </thead>'
                  + '  <tbody>';

              data.forEach(function (row, idx) {
                  var statusId = parseInt(row.order_info.order_status_id || 0, 10);
                  var isEdited = (statusId === 17); 
                  var btnLabel = isEdited ? 'Edited' : 'Edit';
                  var btnDisabledAttr = isEdited ? ' disabled' : '';

                  html += '<tr>'
                      + '  <td style=\"background-color: white;color: black;\">' + (idx + 1) + '</td>'
                      + '  <td style=\"background-color: white;color: black;\">' + row.order_info.order_id + '</td>'
                      + '  <td style=\"background-color: white;color: black;\">' + row.order_info.date_added + '</td>'
                      + '  <td style=\"background-color: white;color: black;\">' + (row.order_info.telephone || '-') + '</td>'
                      + '  <td style=\"background-color: white;color: black;\">' + row.invoice.total_received + '</td>'
                      + '  <td style=\"background-color: white;color: black;\">' + (isEdited ? 'Finalized' : 'Editable') + '</td>'
                      + '  <td style=\"background-color: white;color: black;\">'
                      + '      <button class=\"btn btn-warning btn-sm edit-order-restore-btn\" data-order-id=\"' + row.order_info.order_id + '\"' + btnDisabledAttr + '>'
                      +            btnLabel
                      + '      </button>'
                      + '  </td>'
                      + '</tr>';
              });

              html += '</tbody></table>';

              // Pagination Controls
              html += '<div id=\"editOrderPager\" style=\"margin-top:-15px; text-align:right;display: flex; justify-content: end;\">'
                   + '  <button type=\"button\" id=\"eoFirst\" class=\"btn btn-sm btn-secondary me-1\">Start</button>'
                   + '  <button type=\"button\" id=\"eoPrev\"  class=\"btn btn-sm btn-secondary me-1\"> < </button>'
                   + '  <button type=\"button\" id=\"eoNext\"  class=\"btn btn-sm btn-secondary me-1\"> > </button>'
                   + '  <button type=\"button\" id=\"eoLast\"  class=\"btn btn-sm btn-secondary\">End</button>'
                   + '</div>';

              \$('#editOrderResults').html(html);

              // Pagination Logic
              var \$rows      = \$('#editOrderTable tbody tr');
              var perPage    = 10;
              var pageCount  = Math.ceil(\$rows.length / perPage);
              var current    = 1;

              function renderPage(page) {
                  if (page < 1) page = 1;
                  if (page > pageCount) page = pageCount;
                  current = page;
                  \$rows.hide();
                  var start = (page - 1) * perPage;
                  var end   = start + perPage;
                  \$rows.slice(start, end).show();
              }

              renderPage(1);

              \$('#eoFirst').off('click').on('click', function () { renderPage(1); });
              \$('#eoPrev').off('click').on('click', function () { renderPage(current - 1); });
              \$('#eoNext').off('click').on('click', function () { renderPage(current + 1); });
              \$('#eoLast').off('click').on('click', function () { renderPage(pageCount); });

              \$(document).off('click', '.edit-order-restore-btn').on('click', '.edit-order-restore-btn', function (e) {
                  var orderId = \$(this).data('order-id');
                  restoreEditOrder(orderId);
              });
          }

          function getAgentId() {
              // Try to use the POS session/loader agent ID, but fallback to the agent dropdown if present.
              if (typeof posData !== 'undefined' && posData.agent_id) {
                  return posData.agent_id;
              }

              var selectedAgent = \$('#pos_order_agent').val();
              return selectedAgent ? selectedAgent : null;
          }

          function getAgentBusinessClass() {
              // Prefer explicit DOM input value if available (rendered in modals)
              var el = document.getElementById('agentBusinessClass');
              if (el && el.value) {
                  return el.value;
              }

              // Fallback to server-rendered global constant.
              if (typeof AGENT_BUSINESS_CLASS !== 'undefined' && AGENT_BUSINESS_CLASS) {
                  return AGENT_BUSINESS_CLASS;
              }

              return '';
          }

          function fetchEditOrderById(orderId, callback) {
              if (!orderId) {
                  if (typeof callback === 'function') callback(null);
                  return;
              }

              \$.ajax({
                  url: 'index.php?route=extension/purpletree_pos/pos/home|getEditOrderById',
                  type: 'GET',
                  dataType: 'json',
                  data: {
                      order_id: orderId,
                      agent_id: getAgentId()
                  },
                  beforeSend: function() { showPremiumLoader(); },
                  complete: function() { hidePremiumLoader(); },
                  success: function(res) {
                      if (res && res.data) {
                          if (typeof callback === 'function') callback(res.data);
                      } else {
                          if (typeof callback === 'function') callback(null);
                      }
                  },
                  error: function() {
                      if (typeof callback === 'function') callback(null);
                  }
              });
          }

          function searchAndRestoreEditOrder(orderId) {
              if (!orderId || !orderId.toString().trim()) {
                  errorMessage(\"Please enter an order ID.\", 2000);
                  return;
              }

              // If we have a specific API endpoint for fetching an order by ID, use it.
              fetchEditOrderById(orderId, function(orderData) {
                  if (orderData) {
                      restoreEditOrder(orderId, orderData);
                      return;
                  }

                  // Fallback to the existing list-based approach
                  if (!allEditOrderData || !allEditOrderData.length) {
                      // If date filters are empty, default to today
                      var today = new Date().toISOString().split('T')[0];
                      if (!\$('#edit_from_date').val()) \$('#edit_from_date').val(today);
                      if (!\$('#edit_to_date').val()) \$('#edit_to_date').val(today);

                      \$('#edit_order_id_search').val(orderId);
                      loadEditOrderData(function() {
                          restoreEditOrder(orderId);
                      });
                      return;
                  }

                  restoreEditOrder(orderId);
              });
          }

          function restoreEditOrder(orderId, selectedOrder) {
              // If a pre-fetched order is provided, use it; otherwise, find it in the cached list.
              if (!selectedOrder) {
                  selectedOrder = allEditOrderData.find(function (row) {
                      return row && row.order_info && row.order_info.order_id.toString() === orderId.toString();
                  });
              }

              if (!selectedOrder) {
                  errorMessage(\"Order not found for editing.\", 2000);
                  return;
              }

              window.alreadyPaidAmount = 0;
              sessionStorage.setItem('currentEditOrder', JSON.stringify(selectedOrder));
              sessionStorage.removeItem('currentReturnOrder');
              sessionStorage.removeItem('currentQuotationOrder');

              var orderProducts = selectedOrder.products || [];
              var cartProducts = [];
              console.log(\"order product\",orderProducts);
              orderProducts.forEach(function (p) {
                  cartProducts.push({
                      product_id : p.product_id,
                      quantity   : parseInt(p.quantity) || 1,
                      price      : parseFloat(p.price) || 0,
                      name       : p.name,
                      reward     : p.reward || 0,
                      excluded   : p.excluded || 0,
                      gst_percent: parseFloat(p.gst_percent || p.gst || 0) || 0
                  });
              });

              localStorage.setItem(\"pos_cart\", JSON.stringify(cartProducts));

              var cartArea = document.getElementById('cartArea');
              if (cartArea) cartArea.innerHTML = '';
              cartProducts.forEach(function (p) {
                  addProductRowToCartArea(p);
              });

              updateCartTotals();
              updateInvoiceRightColumn();
              
              \$('#editOrderHistoryContent').hide();
              \$('#cartArea').show();
              \$('.cart-header-row').show();
              \$('.discount-row').show();
              \$('.search-section').show();
              
              successMessage(\"Order \" + orderId + \" loaded for editing.\", 3000);
          }

