          \$(document).on('click', '#searchWalletBtn', function () {
              const phone = \$('#wallet_phone_search').val().trim();
              if (!phone) {
                  alert('Please enter a phone number');
                  return;
              }
              
              loadWalletData(phone);
          });

          let currentWalletCustomerId = null;
          let currentAepsBalance = 0;
          let currentMainBalance = 0;

          function loadWalletData(phone) {
              \$('#tradeAdjustmentBtn, #dueAdjustmentBtn').hide();
              \$('#walletResults').html('<div class=\"text-center\" style=\"padding: 50px;\"><i class=\"fas fa-spinner fa-spin fa-3x\" style=\"color: #C9A24D;\"></i><p style=\"color: #8a93a2; margin-top: 15px; font-weight: 600;\">Retrieving customer wallet data...</p></div>');
              
              \$.ajax({
                  url: 'index.php?route=extension/purpletree_pos/pos/home|searchByMobile',
                  type: 'POST',
                  data: { mobile: phone },
                  dataType: 'json',
                  success: function (res) {
                      if (res && res.status === 'success' && res.customer) {
                          const customer = res.customer;
                          const wallet = res.wallet || {};
                          const transactions = res.transactions || [];
                          const mainWallet = parseFloat(wallet.amount || 0).toFixed(2);
                          const aepsAmount = parseFloat(wallet.aeps_amount || 0).toFixed(2);

                           currentWalletCustomerId = customer.customer_id;
                           currentAepsBalance = parseFloat(wallet.aeps_amount || 0);
                           currentMainBalance = parseFloat(wallet.amount || 0);

                           \$('#tradeAdjustmentBtn, #dueAdjustmentBtn').show();

                           // Ensure modal shows correct values even on first open
                           \$('#modal_current_main').text('₹' + currentMainBalance.toFixed(2));
                           \$('#modal_current_aeps').text('₹' + currentAepsBalance.toFixed(2));

                           // Update Customer Info Display with requested format
                           \$('#customerInfoDisplay').html(`
                              <div style=\"color: #333; font-size: 14px; font-weight: 600; line-height: 1.6;\">
                                 <div>name: \${customer.firstname} \${customer.lastname || ''}</div>
                                 <div>phone: \${customer.telephone}</div>
                                 <div>email: \${customer.email}</div>
                              </div>
                           `);
                      if (!transactions.length) {
                          \$('#walletResults').html(
                              '<p style=\"color:white; padding:10px;\">No wallet history found.</p>'
                          );
                          return;
                      }

                      var html = ''
                          + '<table id=\"walletTransactionTable\" class=\"table table-bordered table-dark mt-3\">'
                          + '  <thead>'
                          + '    <tr>'
                          + '      <th style=\"background-color: white; color: black;\">Sl.No</th>'
                          + '      <th style=\"background-color: white; color: black;\">Order</th>'
                          + '      <th style=\"background-color: white; color: black;\">Date</th>'
                          + '      <th style=\"background-color: white; color: black;\">Description</th>'
                          + '      <th style=\"background-color: white; color: black;\">Type</th>'
                          + '      <th style=\"background-color: white; color: black;\">Sub Type</th>'
                          + '      <th style=\"background-color: white; color: black; text-align: right;\">Amount</th>'
                          + '      <th style=\"background-color: white; color: black; text-align: right;\">Balance</th>'
                          + '    </tr>'
                          + '  </thead>'
                          + '  <tbody style=\"cursor: pointer;\">';

                      transactions.forEach(function (row, idx) {
                          var amount  = Number(row.amount)  || 0;
                          var balance = Number(row.balance) || 0;
          
                          html += ''
                              + '<tr>'
                              + '  <td style=\"background-color: white; color: black;\">' + (idx + 1) + '</td>'
                              + '  <td style=\"background-color: white; color: black;\">' + (row.order_id || 'N/A') + '</td>'
                              + '  <td style=\"background-color: white; color: black;\">' + (row.date_added || '') + '</td>'
                              + '  <td style=\"background-color: white; color: black;\">' + (row.description || '') + '</td>'
                              + '  <td style=\"background-color: white; color: black;\">' + (row.transactiontype || '') + '</td>'
                              + '  <td style=\"background-color: white; color: black;\">' + (row.transactionsubtype || '') + '</td>'
                              + '  <td style=\"background-color: white; color: black; text-align: right;\">₹' + amount.toFixed(2) + '</td>'
                              + '  <td style=\"background-color: white; color: black; text-align: right;\">₹' + balance.toFixed(2) + '</td>'
                              + '</tr>';
                      });

                      html += '  </tbody></table>';

                      html += '<div id=\"walletPager\" style=\"margin-top: 40px; text-align: right; display: flex; justify-content: end;\">'
                           + '  <button type=\"button\" id=\"walletFirst\" class=\"btn btn-sm btn-secondary me-1\">Start</button>'
                           + '  <button type=\"button\" id=\"walletPrev\"  class=\"btn btn-sm btn-secondary me-1\"> < </button>'
                           + '  <button type=\"button\" id=\"walletNext\"  class=\"btn btn-sm btn-secondary me-1\"> > </button>'
                           + '  <button type=\"button\" id=\"walletLast\"  class=\"btn btn-sm btn-secondary\">End</button>'
                           + '</div>';

                      html += '<div id=\"walletSummaryRow\" style=\"margin-top: 10px; color: white; font-size: 20px; position: absolute; bottom: 18px;\">'
                           + '  <span style=\"margin-right: 15px; color: black;\"><b>Main Wallet:</b> ₹' + mainWallet + '</span>'
                           + '  <span style=\"margin-right: 15px; color: black;\"><b>Due:</b> ₹' + aepsAmount + '</span>'
                           + '</div>';

                      \$('#walletResults').html(html);
                      \$('#submit-order-btn, #sendQuotationBtn, #printCartBtn','#saveSaleBtn').addClass('disabled').css('pointer-events', 'none');
                          // Pagination Logic
                          var \$rows      = \$('#walletTransactionTable tbody tr');
                          var perPage    = 10;
                          var pageCount  = Math.ceil(\$rows.length / perPage);
                          var current    = 1;

                          function renderPage(page) {
                              if (page < 1) page = 1;
                              if (page > pageCount) page = pageCount;
                              current = page;
                              \$rows.hide();

                              var start = (page - 1) * perPage;
                              var end   = start + perPage;
                              \$rows.slice(start, end).show();
                          }
                          renderPage(1);

                          \$(document).off('click', '#walletFirst').on('click', '#walletFirst', function(){ renderPage(1); });
                          \$(document).off('click', '#walletPrev').on('click', '#walletPrev',   function(){ renderPage(current-1); });
                          \$(document).off('click', '#walletNext').on('click', '#walletNext',   function(){ renderPage(current+1); });
                          \$(document).off('click', '#walletLast').on('click', '#walletLast',   function(){ renderPage(pageCount); });
                      } else {
                          \$('#walletResults').html(`
                              <div style=\"background: rgba(255, 193, 7, 0.05); border: 1px solid rgba(255, 193, 7, 0.2); border-radius: 12px; padding: 40px; text-align: center;\">
                                 <i class=\"fas fa-search-minus fa-3x mb-3\" style=\"color: #ffc107;\"></i>
                                 <h4 style=\"color: #fff; font-weight: 700;\">No Customer Data Found</h4>
                                 <p style=\"color: #8a93a2; width: 300px; margin: 0 auto;\">No wallet record exists for the phone number: <strong>\${phone}</strong></p>
                              </div>
                          `);
                      }
                  },
                  error: function () {
                      \$('#walletResults').html(`
                          <div style=\"background: rgba(220, 53, 69, 0.05); border: 1px solid rgba(220, 53, 69, 0.2); border-radius: 12px; padding: 40px; text-align: center;\">
                             <i class=\"fas fa-exclamation-triangle fa-3x mb-3\" style=\"color: #dc3545;\"></i>
                             <h4 style=\"color: #fff; font-weight: 700;\">Service Error</h4>
                             <p style=\"color: #8a93a2; width: 300px; margin: 0 auto;\">Could not retrieve wallet data. Please check your connection or try again later.</p>
                          </div>
                      `);
                  }
              });
           }

