           function submitTradeAdjustment() {
               const amount = \$('#trade_adj_amount').val();
               const type = \$('input[name=\"trade_type\"]:checked').val();
               const desc = \$('#trade_adj_description').val();
               
               if(!amount || amount <= 0) {
                   alert(\"Please enter a valid amount.\");
                   return;
               }

               \$.ajax({
                   url: 'index.php?route=extension/purpletree_pos/pos/home|adjustTrade',
                   type: 'POST',
                   data: {
                       customer_id: currentWalletCustomerId,
                       amount: amount,
                       type: type,
                       wallet_type: 'aeps',
                       description: desc
                   },
                   dataType: 'json',
                   beforeSend: function() { \$('#submitTradeAdjBtn').attr('disabled', true).text('Processing...'); },
                   success: function(res) {
                       if(res && res.status === 'success') {
                           \$('#tradeAdjustmentModal').modal('hide');
                           loadWalletData(\$('#wallet_phone_search').val()); 
                       } else {
                           alert(res.message || \"Adjustment failed.\");
                       }
                   },
                   complete: function() { \$('#submitTradeAdjBtn').attr('disabled', false).text('Submit Adjustment'); },
                   error: function() { alert(\"An error occurred while processing the request.\"); }
               });
           }

           function submitDueAdjustment() {
               const amount = \$('#due_adj_amount').val();
               const type = \$('input[name=\"due_type\"]:checked').val();
               const desc = \$('#due_adj_description').val();
               
               if(!amount || amount <= 0) {
                   alert(\"Please enter a valid amount.\");
                   return;
               }

               \$.ajax({
                   url: 'index.php?route=extension/purpletree_pos/pos/home|adjustDue',
                   type: 'POST',
                   data: {
                       customer_id: currentWalletCustomerId,
                       amount: amount,
                       type: type,
                       wallet_type: 'main',
                       description: desc
                   },
                   dataType: 'json',
                   beforeSend: function() { \$('#submitDueAdjBtn').attr('disabled', true).text('Processing...'); },
                   success: function(res) {
                       if(res && res.status === 'success') {
                           \$('#dueAdjustmentModal').modal('hide');
                           loadWalletData(\$('#wallet_phone_search').val()); 
                       } else {
                           alert(res.message || \"Adjustment failed.\");
                       }
                   },
                   complete: function() { \$('#submitDueAdjBtn').attr('disabled', false).text('Submit Adjustment'); },
                   error: function() { alert(\"An error occurred while processing the request.\"); }
               });
           }


          function submitTaxExemptDetails() {

    const orderId    = \$('#tax_exempt_order_id').val().trim();
    const gst        = \$('#tax_exempt_gst').val();
    const taxPercent = \$('#tax_exempt_percentage').val().trim();

    // Receiver Details
    const recvName    = \$('#receiver_name').val().trim();
    const recvAddress = \$('#receiver_address').val().trim();
    const recvState   = \$('#receiver_state').val().trim();
    const recvMobile  = \$('#receiver_mobile').val().trim();
    const recvGstin   = \$('#receiver_gstin').val().trim();
    const recvPan     = \$('#receiver_pan').val().trim();

    // Consignee Details
    const consName    = \$('#consignee_name').val().trim();
    const consAddress = \$('#consignee_address').val().trim();
    const consState   = \$('#consignee_state').val().trim();
    const consMobile  = \$('#consignee_mobile').val().trim();
    const consGstin   = \$('#consignee_gstin').val().trim();
    const consPan     = \$('#consignee_pan').val().trim();

    if (!orderId || !taxPercent) {
        \$('#tax_exempt_error').show();
        return;
    }

    \$('#tax_exempt_error').hide();

    const url =
        'index.php?route=extension/purpletree_pos/pos/home|updateTaxExempt'
        + '&order_id=' + encodeURIComponent(orderId)
        + '&tax_percentage=' + encodeURIComponent(taxPercent)
        + '&gst_percentage=' + encodeURIComponent(gst)
        
        // Append Receiver Params
        + '&receiver_name=' + encodeURIComponent(recvName)
        + '&receiver_address=' + encodeURIComponent(recvAddress)
        + '&receiver_state=' + encodeURIComponent(recvState)
        + '&receiver_mobile=' + encodeURIComponent(recvMobile)
        + '&receiver_gstin=' + encodeURIComponent(recvGstin)
        + '&receiver_pan=' + encodeURIComponent(recvPan)

        // Append Consignee Params
        + '&consignee_name=' + encodeURIComponent(consName)
        + '&consignee_address=' + encodeURIComponent(consAddress)
        + '&consignee_state=' + encodeURIComponent(consState)
        + '&consignee_mobile=' + encodeURIComponent(consMobile)
        + '&consignee_gstin=' + encodeURIComponent(consGstin)
        + '&consignee_pan=' + encodeURIComponent(consPan);

   
    window.open(url, '_blank');

    // Close modal
    \$('#taxExemptModal').modal('hide');
}



          function submitQuotation() {
              const name = \$('#quote_customer_name').val().trim();
              const phone = \$('#quote_customer_phone').val().trim();
              
              let hasError = false;
              if (!name) {
                  \$('#quote_name_error').show();
                  hasError = true;
              } else {
                  \$('#quote_name_error').hide();
              }

              if (!phone || phone.length !== 10 || !/^\\d{10}\$/.test(phone)) {
                  \$('#quote_phone_error').show();
                  hasError = true;
              } else {
                  \$('#quote_phone_error').hide();
              }

              if (hasError) return;

              const products = getCartProductsFromDOMSync();
              if (!products) return;

              const btn = document.getElementById('submitQuoteBtn');
              btn.disabled = true;
              btn.innerText = 'Submitting...';

              // Calculate totals directly from cart rows (Matching system logic)
              let netTotal = 0;
              let totalTax = 0;
              const cartRows = document.querySelectorAll('.cart-row');
              cartRows.forEach(function (row) {
                  if (row.classList.contains('excluded-row')) return;
                  const qtyInput = row.querySelector('.qty-input');
                  if (!qtyInput) return;
                  const quantity = parseInt(qtyInput.value) || 0;
                  const unitPrice = parseFloat(row.dataset.price) || 0;
                  const discountPercent = 3; // Hardcoded in updateCartTotals
                  let lineSubtotal = unitPrice * quantity;
                  let lineSubtotalAF = (lineSubtotal * discountPercent / 100);
                  netTotal += lineSubtotal;
                  totalTax += lineSubtotalAF;
              });
              
              const finalTotal = netTotal;
              const discount = totalTax;

               let activeQuoteId = '';
               const currentQuotationOrder = sessionStorage.getItem('currentQuotationOrder');
               if (currentQuotationOrder) {
                   try {
                       const q = JSON.parse(currentQuotationOrder);
                       // Robust ID capture: check multiple possible fields
                       activeQuoteId = q?.quote_info?.quote_id || q?.quote_info?.order_id || q?.quote_id || q?.order_id || '';
                   } catch (e) {}
               }

               const quotationData = {
                   quote_id: activeQuoteId,
                   invoice_number: (function() {
                       const prefix = 'SGC-';
                       const today = new Date();
                       const year = today.getFullYear();
                       const month = String(today.getMonth() + 1).padStart(2, '0');
                       const day = String(today.getDate()).padStart(2, '0');
                       const datePart = `\${year}\${month}\${day}`;
                       const randomPart = String(Math.floor(Math.random() * 1000000)).padStart(6, '0');
                       return prefix + datePart + randomPart;
                   })(),
                   products: products,
                   net_total: netTotal,
                   discount: discount,
                   total_tax: totalTax,
                   final_total: finalTotal,
                   customer_name: name,
                   telephone: phone,
                   email: ''
               };

               console.log(\"Quotation Data Final Payload:\", quotationData);

               \$.ajax({
                   url: 'index.php?route=extension/purpletree_pos/pos/home|addQuoteOrder',
                   type: 'POST',
                   dataType: 'json',
                   contentType: 'application/json',
                   data: JSON.stringify({ quotation_details: quotationData }),
                   success: function(res) {
                       if (res.status === 'success') {
                           successMessage(res.message || 'Quotation sent successfully!', 4000);
                           \$('#quotationModal').modal('hide');
                           
                           // Professional Completion Flow: Capture the ID (either returned or existing)
                           const newQuoteId = res.quote_id || res.order_id || activeQuoteId;
                           if (newQuoteId) {
                               localStorage.setItem('last_quote_id', newQuoteId);
                           }
                           
                           // Trigger Print & WhatsApp logic
                           setTimeout(() => {
                               if (typeof printDraftInvoice === 'function') {
                                   printDraftInvoice();
                               }
                           }, 500);

                           // Clear session and local caches
                           sessionStorage.clear();
                           localStorage.removeItem(\"pos_cart\");
                           emptyCart();
                           refreshPage();
                       } else {
                           alert(res.message || 'Failed to send quotation');
                           btn.disabled = false;
                           btn.innerText = 'Submit';
                       }
                   },
                  error: function() {
                      alert('Error sending quotation request.');
                  },
                  complete: function() {
                      btn.disabled = false;
                      btn.innerText = 'Submit';
                  }
              });
          }

    function openPrintDetailsModal() {
        const modalEl = document.getElementById('printDetailsModal');
        if (!modalEl) return;

        // Clear previous values - user must enter them each time
        const orderIdInput = modalEl.querySelector('#printDetailsOrderId');
        const dateInput = modalEl.querySelector('#printDetailsDate');

        if (orderIdInput) {
            orderIdInput.value = '';
        }
        if (dateInput) {
            dateInput.value = '';
        }

        const modal = new bootstrap.Modal(modalEl, { backdrop: 'static' });
        modal.show();
    }

    function confirmPrintDetailsAndSubmit() {
        const modalEl = document.getElementById('printDetailsModal');
        if (!modalEl) return;

        const orderId = (modalEl.querySelector('#printDetailsOrderId')?.value || '').trim();
        const orderDate = modalEl.querySelector('#printDetailsDate')?.value || '';

        if (!orderId) {
            alert('Please enter Order ID.');
            return;
        }

        const bsModal = bootstrap.Modal.getInstance(modalEl);
        if (bsModal) bsModal.hide();

        submitPrintDetails(orderId, orderDate);
    }

    function submitPrintDetails(orderId, orderDate) {
        orderId = orderId || localStorage.getItem('last_order_id') || '';
        orderDate = orderDate || new Date().toISOString().split('T')[0];

            const rawProducts = getCartProductsFromDOMSync();
            if (!rawProducts || rawProducts.length === 0) {
                alert('Cart is empty');
                return;
            }
        
            // normalize products for twig
            const products = rawProducts.map(p => {
                const qty = parseInt(p.quantity || 1);
                const price = parseFloat(p.price || 0);
        
                return {
                    name: p.name,
                    quantity: qty,
                    price: price,
                    total: price * qty,
                    excluded: (p.excluded == 1 || String(p.excluded).toLowerCase() === 'true') ? 1 : 0
                };
            });
        
            let subTotal = 0;
            let totalTax = 0;

            document.querySelectorAll('.cart-row').forEach(row => {
               if (row.classList.contains('excluded-row')) return;

               const qty = parseInt(row.querySelector('.qty-input')?.value || 0);
               const price = parseFloat(row.dataset.price || 0);

               const lineTotal = price * qty;
               subTotal += lineTotal;

               // Try to read gst from stored product data, fallback to DOM GST cell
               let prod = null;
               try { prod = decodeProduct(row.dataset.product); } catch (e) { prod = null; }
               let gstPercent = 0;
               if (prod && prod.gst_percent) gstPercent = parseFloat(prod.gst_percent) || 0;
               if (!gstPercent) {
                  const gstCell = row.querySelector('.gst-percent');
                  if (gstCell) gstPercent = parseFloat(gstCell.textContent.replace('%','')) || 0;
               }

               const lineGst = (gstPercent / 100) * lineTotal;
               totalTax += lineGst;
            });

            const payload = {
               products: products,
               net_total: subTotal,
               discount: totalTax,    // show discount equal to total tax (display requirement)
               total_tax: totalTax,
               final_total: subTotal + totalTax
            };
        
            \$.ajax({
                url: 'index.php?route=extension/purpletree_pos/pos/home|printCart'
                    + '&order_id=' + encodeURIComponent(orderId)
                    + '&date=' + encodeURIComponent(orderDate),
                type: 'POST',
                contentType: 'application/json',
                dataType: 'json',
                data: JSON.stringify({ print_details: payload }),
                beforeSend: function() { showPremiumLoader(); },
                complete: function() { hidePremiumLoader(); },
        
                success: function (res) {
                    if (res.status !== 'success') {
                        alert('Print failed');
                        return;
                    }
        
                    /* ---------- SAME IFRAME LOGIC AS invoice ---------- */
                    let iframe = document.createElement('iframe');
                    iframe.style.position = 'fixed';
                    iframe.style.right = '0';
                    iframe.style.bottom = '0';
                    iframe.style.width = '0';
                    iframe.style.height = '0';
                    iframe.style.border = '0';
                    document.body.appendChild(iframe);
        
                    iframe.onload = function () {
                        iframe.contentWindow.focus();
                        iframe.contentWindow.print();
        
                        // Send order and date to backend (WhatsApp API) after print.
                        sendPrintDetailsWhatsApp(orderId, orderDate);

                        
                    };
        
                    iframe.contentDocument.open();
                    iframe.contentDocument.write(res.html);
                    iframe.contentDocument.close();
                },
        
                error: function () {
                    alert('Error printing cart');
                }
            });
        }

        function sendPrintDetailsWhatsApp(orderId, orderDate) {
            if (!orderId) return;

            let rawPhone =
                \$('#customerMobileInput').val()?.trim() ||
                (JSON.parse(sessionStorage.getItem('currentCustomerData') || '{}').telephone || '');

            rawPhone = rawPhone.replace(/\\s+/g, '').replace(/^\\+/, '');
            if (rawPhone.startsWith('0')) rawPhone = rawPhone.substring(1);
            if (rawPhone && !rawPhone.startsWith('91')) rawPhone = '91' + rawPhone;

            if (!rawPhone) {
                console.warn('Customer phone not found, skipping WhatsApp send');
                return;
            }

            \$.ajax({
                url:
                    \"index.php?route=extension/purpletree_pos/pos/home|Order_sendwhatsapp\"
                    + \"&order_id=\" + encodeURIComponent(orderId)
                    + \"&phone=\" + encodeURIComponent(rawPhone)
                    + \"&date=\" + encodeURIComponent(orderDate || ''),
                type: \"GET\",
                dataType: \"json\",
                success: function (res) {
                    console.log('WhatsApp sent:', res);
                },
                error: function () {
                    console.warn('WhatsApp send failed');
                }
            });
        }

 
