         var totalReceivedAmount = 0;
         
         var globalAdvanceAmount = 0;
         var globalDueAmount = 0;
         
         // ============================================
         // UPDATED: Remove togglePaymentInput function and replace with this
         // ============================================
         function handlePaymentInput(type) {
           updateTotals();
         }
         
         // ============================================
         // UPDATED ADVANCE CHECKBOX HANDLER - WITHOUT Cash/UPI Checkboxes
         // ============================================
         function handleDueAmountCheckbox() {
             const useDA = document.getElementById('dueAmountInvoice');
             const daWrapper = document.getElementById('dueAmountWrapper');
             const daInput = document.getElementById('dueAmountInput');
             
             if (useDA && useDA.checked) {
                 if (daWrapper) daWrapper.style.display = 'block';
             } else {
                 if (daWrapper) daWrapper.style.display = 'none';
                 if (daInput) daInput.value = ''; // Reset value to empty string to show placeholder
             }
             updateTotals();
         }
         
         function handleAdvanceCheckbox() {
             const useAdvance      = document.getElementById('advancedAmountInvoice')?.checked || false;
             const advanceInput    = document.getElementById('advanceAmount');
             const advanceWrapper  = document.getElementById('advanceWrapper');
             const desc            = document.getElementById('advanceAmountDesc');
             const cashInput       = document.getElementById('cashAmount');
             const upiInput        = document.getElementById('upiAmount');
            
         
             const totalDue        = grandTotalAmount || 0;
             const availableAdvance = globalAdvanceAmount || 0;
         
             // reset cash/upi if needed
             if (!cashInput || !upiInput) return;
         
             if (!useAdvance || availableAdvance <= 0) {
                 // Advance NOT used
                 if (advanceWrapper) advanceWrapper.style.display = 'none';
                 if (desc)          desc.style.display = 'none';
                 if (advanceInput)  advanceInput.value = '';
         
               
         
                 cashInput.readOnly = false;
                 cashInput.style.backgroundColor = '';
                 cashInput.style.cursor = '';
                 upiInput.readOnly  = false;
                 upiInput.style.backgroundColor = '';
                 upiInput.style.cursor = '';
         
                 // Only cash + UPI decide totals
                 updateTotals();
                 return;
             }
         
             // Advance is available and checkbox checked
             const advUsed = Math.min(availableAdvance, totalDue);
         
            if (advanceWrapper) advanceWrapper.style.display = 'block';
         
         
             if (advanceInput) {
                 advanceInput.value  = advUsed.toFixed(2);
                 advanceInput.readOnly = true;
             }
         
             const remainingDue = Math.max(totalDue - advUsed, 0);
             let text = '';
             if (advUsed >= totalDue) {
                 const balAdv = availableAdvance - advUsed;
                 text = 'Balance ' + balAdv.toFixed(2);
             } else {
                 text = 'Remaining Pending ' + remainingDue.toFixed(2) +
                        ', Balance ' + (availableAdvance - advUsed).toFixed(2);
             }
             if (desc) {
                 desc.style.display = 'block';
                 desc.innerHTML = text;
                 desc.style.marginTop = '-5px'; // Adjust description margin if needed
             }
         
             // If advance fully covers the bill, disable cash/upi
             if (advUsed >= totalDue) {
                 cashInput.value = '';
                 upiInput.value  = '';
                 cashInput.readOnly = true;
                 upiInput.readOnly  = true;
                 cashInput.style.backgroundColor = '#e9ecef';
                 cashInput.style.cursor = 'not-allowed';
                 upiInput.style.backgroundColor = '#e9ecef';
                 upiInput.style.cursor = 'not-allowed';
             } else {
                 cashInput.readOnly = false;
                 upiInput.readOnly  = false;
                 cashInput.style.backgroundColor = '';
                 cashInput.style.cursor = '';
                 upiInput.style.backgroundColor = '';
                 upiInput.style.cursor = '';
             }
         
             // Recompute totals with advance considered
             updateTotals();
         }
         
         
         // Helper: read numeric from a â‚¹-formatted input
         function parseMoney(val) {
             if (!val) return 0;
             return parseFloat(String(val).replace(/[^0-9.-]/g, '')) || 0;
         }
