             const pendingInput = document.getElementById('pendingAmount');
             if (pendingInput && pendingInput.value) {
                 return parseMoney(pendingInput.value);
             }
             return grandTotalAmount || 0;
         }
         
         function getOtherPayments() {
             let cash = 0, upi = 0;
             const cashInput = document.getElementById('cashAmount');
             const upiInput  = document.getElementById('upiAmount');
         
             if (cashInput && cashInput.value !== '') cash = parseFloat(cashInput.value) || 0;
             if (upiInput  && upiInput.value  !== '') upi  = parseFloat(upiInput.value)  || 0;
         
             return cash + upi;
         }
         
         
         
         
