             el.value = (typeof format === 'function') ? format(Math.max(val || 0, 0), code) : Math.max(val || 0, 0).toFixed(2);
         }
         // ============================================
         // UPDATED updateTotals function
         // ============================================
         
         
         function updateTotals() {
             var cashInput   = document.getElementById('cashAmount');
             var upiInput    = document.getElementById('upiAmount');
             var totalRecEl  = document.getElementById('totalReceived');
             var pendEl      = document.getElementById('pendingAmount');
             var retEl       = document.getElementById('returnableBalance');
             var advChk      = document.getElementById('advancedAmountInvoice');
             var advInput    = document.getElementById('advanceAmount');
             var upiRefInput = document.getElementById('upiReference');  
         
             var daChk       = document.getElementById('dueAmountInvoice');
             var daInput     = document.getElementById('dueAmountInput');
             var gtEl        = document.getElementById('grandTotal');
         
             var cashVal = cashInput ? (parseFloat(cashInput.value) || 0) : 0;
             var upiVal  = upiInput  ? (parseFloat(upiInput.value)  || 0) : 0;
             
             // Professional visibility logic for UPI Reference & Generate Button
             const btnGen = document.getElementById('btnGenerateUpiQr');
             const qrSelContainer = document.getElementById('qrSelectionContainer');
             const qrContent = document.getElementById('upiQrContent');
             const qrPlaceholderAmt = document.getElementById('upiQrAmountPlaceholder');

             if (upiVal > 0) {
                 if (upiRefInput) upiRefInput.style.display = 'block';
                       if (btnGen) btnGen.style.display = 'block';
                 if (qrPlaceholderAmt) qrPlaceholderAmt.textContent = upiVal.toFixed(2);
                 // We don't automatically unblur here, that happens in generateUpiQrCode success
             } else {
                 if (upiRefInput) {
                     upiRefInput.style.display = 'none';
                     upiRefInput.value = '';
                 }
                    if (btnGen) btnGen.style.display = 'none';
                 if (qrSelContainer) qrSelContainer.style.display = 'none';
                 if (qrContent) qrContent.style.display = 'block';
                 if (qrPlaceholderAmt) qrPlaceholderAmt.textContent = '0.00';
                 
                 // Re-blur and reset if amount is 0/deleted
                 const content = document.getElementById('upiQrContent');
                 const qrImg = document.getElementById('upiQrImg');
                 if (content) {
                     content.classList.remove('upi-qr-unblur');
                     content.classList.add('upi-qr-blur');
                 }
                 if (qrImg) {
                     qrImg.src = \"https://www.hallmarknameplate.com/wp-content/uploads/2022/08/qr-code-print5-293x300.png\";
                     qrImg.style.opacity = '0.8';
                 }
             }
             
            //  // Ensure Generate Button is ALWAYS visible if UPI is active or just always visible for clarity
            //  if (btnGen) btnGen.style.display = 'block';

              var daVal = (daChk && daChk.checked) ? (parseFloat(daInput?.value) || 0) : 0;
              
              // Resolve currency code ONCE at function scope
              var currentCurrency = (typeof posData !== 'undefined' && posData.currency_code) ? posData.currency_code : 'INR';
              
              // ADVANCED DA SETTLEMENT LOGIC
              var includeDAChk = document.getElementById('includeDAInTotal');
              var includeDAInput = document.getElementById('includeDAAmount');
              var daSpan = document.getElementById('dueAmountSpan');
              var daSummaryInput = document.getElementById('dueAmountSummary');
              
              var enteredDA = 0;
              var originalDA = daSpan ? parseFloat(daSpan.getAttribute('data-original')) || 0 : 0;
              
              if (includeDAChk && includeDAChk.checked) {
                  if (includeDAInput) includeDAInput.disabled = false;
                  enteredDA = includeDAInput ? (parseFloat(includeDAInput.value) || 0) : 0;
                  
                  if (enteredDA > originalDA) {
                      enteredDA = originalDA;
                      if (includeDAInput) includeDAInput.value = enteredDA;
                  }

                  if (daSpan) daSpan.textContent = (originalDA - enteredDA).toFixed(2);
                  if (daSummaryInput) daSummaryInput.value = format(enteredDA, currentCurrency);
              } else {
                  if (includeDAInput) {
                      includeDAInput.disabled = true;
                      includeDAInput.value = '';
                  }
                  if (daSpan) daSpan.textContent = originalDA.toFixed(2);
                  if (daSummaryInput) daSummaryInput.value = format(0, currentCurrency);
              }
              
              // Ensure grandTotalAmount is a valid number
              var baseGrandTotal = parseFloat(grandTotalAmount) || 0;
              var effectiveGrandTotal = baseGrandTotal + enteredDA;
              
              // Adjusted grand total for payments
              var adjustedGrandTotal = Math.max(effectiveGrandTotal - daVal, 0);
              if (gtEl) gtEl.value = format(effectiveGrandTotal, currentCurrency);
          
              var advUsed = 0;
              if (advChk && advChk.checked && globalAdvanceAmount > 0) {
                  advUsed = Math.min(globalAdvanceAmount, adjustedGrandTotal);
                  if (advInput) advInput.value = advUsed.toFixed(2);
              } else if (advInput) {
                  advInput.value = '';
              }
          
              var alreadyPaid = window.alreadyPaidAmount || 0;
              var totalReceivedAmount = alreadyPaid + advUsed + cashVal + upiVal;
          
              var pendingAmount     = Math.max(adjustedGrandTotal - totalReceivedAmount, 0);
              var returnableBalance = Math.max(totalReceivedAmount - adjustedGrandTotal, 0);
          
              // Return Amount as Cash Logic
              var returnAsCashChk = document.getElementById('returnAsCash');
              if (returnAsCashChk && returnAsCashChk.checked && returnableBalance > 0) {
                  totalReceivedAmount -= returnableBalance;
                  returnableBalance = 0;
              }
          
              if (totalRecEl) totalRecEl.value = format(totalReceivedAmount, currentCurrency);
              if (pendEl)     pendEl.value     = format(pendingAmount,     currentCurrency);
              if (retEl)      retEl.value      = returnableBalance > 0 ? returnableBalance.toFixed(0) : '';
         }
         
         
