         function updateTotalsWithCoupon(discount, couponCode) {
             let totals = JSON.parse(sessionStorage.getItem(\"totals\")) || [];
             
             // Remove existing coupon if any
             totals = totals.filter(item => item.code !== 'coupon');
             
             // Add coupon discount before grand total
             const grandTotalIndex = totals.findIndex(item => item.code === 'total');
             const couponItem = {
                 'code': 'coupon',
                 'title': `Coupon (\${couponCode})`,
                 'value': -discount,
                 'sort_order': 8,
                 'removable': true,
                 'id': 'coupon',
                 'custom_title': 'coupon'
             };
             
             if (grandTotalIndex > -1) {
                 totals.splice(grandTotalIndex, 0, couponItem);
                 
                 // Update grand total
                 const currentGrandTotal = parseFloat(totals[grandTotalIndex + 1].value);
                 totals[grandTotalIndex + 1].value = currentGrandTotal - discount;
             } else {
                 totals.push(couponItem);
             }
             
             sessionStorage.setItem(\"totals\", JSON.stringify(totals));
             
             // Update grand total in session
             let grandTotal = JSON.parse(sessionStorage.getItem(\"grand_total\"));
             if (grandTotal) {
                 grandTotal.value = parseFloat(grandTotal.value) - discount;
                 sessionStorage.setItem(\"grand_total\", JSON.stringify(grandTotal));
             }
             
             // Refresh cart display
             getCartProductHTML();
         }
         
         function removeCoupon() {
             const couponBtn   = document.getElementById('couponBtnInvoice');
             const couponInput = document.getElementById('couponCodeInvoice');
             const couponMsgEl = document.getElementById('couponMessage');   // NEW
         
             // Reset button state
             couponBtn.textContent = 'Apply';
             couponBtn.classList.remove('remove');
             couponInput.disabled = false;
             couponInput.value = '';
         
             // NEW: clear the text shown below the checkbox
             if (couponMsgEl) {
                 couponMsgEl.textContent = '';
             }
             
             // Get stored coupon details
             const couponApplied = JSON.parse(sessionStorage.getItem('couponApplied'));
             
             if (couponApplied) {
                 // Restore original total
                 const originalTotal =
                     parseFloat(sessionStorage.getItem('originalGrandTotal')) ||
                     couponApplied.originalTotal;
                 
                 if (originalTotal) {
                     document.getElementById('grandTotal').value =
                         format(originalTotal, posData.currency_code);
                     
                     // keep global total in sync
                     grandTotalAmount = originalTotal;
                 }
                 
                 // Remove coupon from totals
                 let totals = JSON.parse(sessionStorage.getItem(\"totals\")) || [];
                 totals = totals.filter(item => item.code !== 'coupon');
                 
                 // Restore grand total
                 const grandTotalItem = totals.find(item => item.code === 'total');
                 if (grandTotalItem) {
                     grandTotalItem.value = originalTotal;
                 }
                 
                 sessionStorage.setItem(\"totals\", JSON.stringify(totals));
                 
                 // Update grand total in session
                 sessionStorage.setItem(\"grand_total\", JSON.stringify({
                     'code': 'total',
                     'title': 'Total',
                     'value': originalTotal,
                     'sort_order': 9
                 }));
                 
                 // Clear coupon data
                 sessionStorage.removeItem('couponApplied');
                 sessionStorage.removeItem('originalGrandTotal');
                 
                 // Refresh cart display
                 getCartProductHTML();
                 
                 // Recalculate pending / received / returnable
                 updateTotals();
                 
                 successMessage('Coupon removed successfully', 2000);
             }
         }
         
         
         // Updated applyCreditPoints function
         function applyCreditPoints(creditPoints) {
             // Ñ‚ÂœÂ… remove the division line
             creditPoints = creditPoints / 2;
         
             // PROFESSIONAL FIX: Always use grandTotalAmount as base
             let grandTotal = grandTotalAmount || 0;

             
             if (!sessionStorage.getItem('originalGrandTotal')) {
                 sessionStorage.setItem('originalGrandTotal', grandTotal.toFixed(2));
             }
             
             let discount = Math.min(creditPoints, grandTotal);
             let newGrandTotal = Math.max(grandTotal - discount, 0);
             
             document.getElementById('grandTotal').value = format(newGrandTotal, posData.currency_code);
             
             // NEW: Keep global total in sync
             grandTotalAmount = newGrandTotal;
             
             sessionStorage.setItem('credit_points_used', JSON.stringify(discount));
             
             let totals = JSON.parse(sessionStorage.getItem(\"totals\")) || [];
             totals = totals.filter(item => item.code !== 'credit_points');
             
             const grandTotalIndex = totals.findIndex(item => item.code === 'total');
             const creditItem = {
                 'code': 'credit_points',
                 'title': 'Credit Points Used',
                 'value': -discount,
                 'sort_order': 8,
                 'removable': true,
                 'id': 'credit_points',
                 'custom_title': 'credit_points'
             };
             
             if (grandTotalIndex > -1) {
                 totals.splice(grandTotalIndex, 0, creditItem);
                 totals[grandTotalIndex-1].value = newGrandTotal;
             } else {
                 totals.push(creditItem);
             }
             
             sessionStorage.setItem(\"totals\", JSON.stringify(totals));
             
             sessionStorage.setItem(\"grand_total\", JSON.stringify({
                 'code': 'total',
                 'title': 'Total',
                 'value': newGrandTotal,
                 'sort_order': 9
             }));
             
             getCartProductHTML();
         }
         
         // Updated removeCreditPoints function
         function removeCreditPoints() {
             // Restore original total
             let originalGrandTotal = sessionStorage.getItem('originalGrandTotal');
             
             if (originalGrandTotal) {
                 document.getElementById('grandTotal').value = format(
                     parseFloat(originalGrandTotal), 
                     posData.currency_code
                 );
                 
                 // Remove credit points from totals
                 let totals = JSON.parse(sessionStorage.getItem(\"totals\")) || [];
                 totals = totals.filter(item => item.code !== 'credit_points');
                 
                 // Restore grand total
                 const grandTotalItem = totals.find(item => item.code === 'total');
                 if (grandTotalItem) {
                     grandTotalItem.value = parseFloat(originalGrandTotal);
                 }
                 
                 // NEW: restore global total
                 grandTotalAmount = parseFloat(originalGrandTotal);
                 
                 sessionStorage.setItem(\"totals\", JSON.stringify(totals));
                 
                 // Update grand total in session
                 sessionStorage.setItem(\"grand_total\", JSON.stringify({
                     'code': 'total',
                     'title': 'Total',
                     'value': parseFloat(originalGrandTotal),
                     'sort_order': 9
                 }));
                 
                 // Clear credit points data
                 sessionStorage.removeItem('credit_points_used');
                 
                 // Refresh display
                 getCartProductHTML();
             }
         }
         
         // Updated initializeCouponFunctionality
         function initializeCouponFunctionality() {
             const creditLimitCheckbox = document.getElementById('creditLimitInvoice');
             const useCouponCheckbox = document.getElementById('useCouponInvoice');
             const couponInput = document.getElementById('couponCodeInvoice');
             const couponBtn = document.getElementById('couponBtnInvoice');
         
             // Handle credit limit checkbox change
             if (creditLimitCheckbox) {
                 creditLimitCheckbox.addEventListener('change', function() {
                     if (this.checked) {
                         // Disable coupon controls
                         useCouponCheckbox.disabled = true;
                         useCouponCheckbox.checked = false;
                         couponInput.disabled = true;
                         couponBtn.disabled = true;
                         couponInput.value = '';
                         
                         // Reset button if it was in Remove state
                         if (couponBtn.textContent === 'Remove') {
                             removeCoupon();
                         }
                         
                         
                         
                         const creditPoints = parseFloat(
                             document.getElementById('creditLimitSpan').textContent
                         ) || 0;
                         
                         if (creditPoints > 0) {
                             applyCreditPoints(creditPoints);
                         } 
                         else {
                             errorMessage('No credit points available', 2000);
                             this.checked = false;
                             useCouponCheckbox.disabled = false;
                         }
                     } else {
                         // Enable coupon checkbox
                         useCouponCheckbox.disabled = false;
                         removeCreditPoints();
                     }
                 });
             }
         
             // Handle coupon checkbox change
             if (useCouponCheckbox) {
                 useCouponCheckbox.addEventListener('change', function() {
                     if (this.checked) {
                         // Enable coupon input and button
                         couponInput.disabled = false;
                         couponBtn.disabled = false;
                         
                         // Disable credit limit checkbox
                         creditLimitCheckbox.disabled = true;
                         creditLimitCheckbox.checked = false;
                         
                         // Remove credit points if applied
                         removeCreditPoints();
                     } else {
                         // Disable coupon input and button
                         couponInput.disabled = true;
                         couponBtn.disabled = true;
                         couponInput.value = '';
                         
                         // Reset button if it was in Remove state
                         if (couponBtn.textContent === 'Remove') {
                             removeCoupon();
                         }
                         
                         // Enable credit limit checkbox
                         creditLimitCheckbox.disabled = false;
                     }
                 });
             }
         }
         
       
         
