         // Add these functions here, before showAddCustomerModal()
         function initializeCreditLimitFunctionality() {
             const creditLimitCheckbox = document.getElementById('creditLimitInvoice');
             const useCouponCheckbox   = document.getElementById('useCouponInvoice');
             const couponInput         = document.getElementById('couponCodeInvoice');
             const couponBtn           = document.getElementById('couponBtnInvoice');
             
             if (creditLimitCheckbox) {
                 creditLimitCheckbox.addEventListener('change', function() {
                     if (this.checked) {
                         // Get available credit points from the span
                         const creditPointsText = document.getElementById('creditLimitSpan').textContent.trim();
                         const creditPoints     = parseFloat(creditPointsText) || 0;
                         
                         if (creditPoints <= 0) {
                             errorMessage('No credit points available', 2000);
                             this.checked = false;
                             return;
                         }
                         
                         // Disable coupon controls
                         useCouponCheckbox.disabled = true;
                         useCouponCheckbox.checked  = false;
                         couponInput.disabled       = true;
                         couponBtn.disabled         = true;
                         couponInput.value          = '';
                         
                         // Remove coupon if applied
                         if (couponBtn.textContent === 'Remove') {
                             removeCoupon();
                         }
         
                         // Apply credit points discount
                         applyCreditPoints(creditPoints);
                         successMessage(`Credit points (\${creditPoints}) applied successfully!`, 2000);
                         const redeemPointsMessage = document.getElementById('RedeemPointsMessage');
             if (redeemPointsMessage) {
                 redeemPointsMessage.innerHTML = `Credit points (\${creditPoints}) applied successfully!`;
                 redeemPointsMessage.style.color = '#28a745'; // Green color for success
                 redeemPointsMessage.style.display = 'inline-block';
                 
                 
             }
         
                         // NEW: recalc payment summary (pending / received / returnable)
                         updateTotals();
                     } else {
                         // Enable coupon checkbox
                         useCouponCheckbox.disabled = false;
                         
                         // Remove credit points discount
                         removeCreditPoints();
                         successMessage('Credit points removed', 2000);
                         
                         // FIX: Clear success message
                         const redeemPointsMessage = document.getElementById('RedeemPointsMessage');
                         if (redeemPointsMessage) {
                             redeemPointsMessage.innerHTML = '';
                             redeemPointsMessage.style.display = 'none';
                         }
         
                         // NEW: recalc payment summary after removing credits
                         updateTotals();
                     }
                 });
             }
         }
         
         function applyCreditPoints(creditPoints) {
             creditPoints = creditPoints / 2;
             // PROFESSIONAL FIX: Always use grandTotalAmount as base
             let grandTotal = grandTotalAmount || 0;

             
             // Store original total if not already saved
             if (!sessionStorage.getItem('originalGrandTotal')) {
                 sessionStorage.setItem('originalGrandTotal', grandTotal.toFixed(2));
             }
             
             // Calculate discount (cannot exceed grand total)
             let discount      = Math.min(creditPoints, grandTotal);
             let newGrandTotal = Math.max(grandTotal - discount, 0);
             
             // Update display
             document.getElementById('grandTotal').value = format(newGrandTotal, posData.currency_code);
         
             // NEW: keep global total used by updateTotals in sync
             grandTotalAmount = newGrandTotal;
             
             // Store credit points usage
             sessionStorage.setItem('credit_points_used', JSON.stringify(discount));
             
             // Update totals in session
             let totals = JSON.parse(sessionStorage.getItem(\"totals\")) || [];
             
             // Remove existing credit points if any
             totals = totals.filter(item => item.code !== 'credit_points');
             
             // Add credit points discount before grand total
             const grandTotalIndex = totals.findIndex(item => item.code === 'total');
             const creditItem = {
                 'code':         'credit_points',
                 'title':        'Credit Points Used',
                 'value':        -discount,
                 'sort_order':   8,
                 'removable':    true,
                 'id':           'credit_points',
                 'custom_title': 'credit_points'
             };
             
             if (grandTotalIndex > -1) {
                 totals.splice(grandTotalIndex, 0, creditItem);
                 totals[grandTotalIndex + 1].value = newGrandTotal;
             } else {
                 totals.push(creditItem);
             }
             
             sessionStorage.setItem(\"totals\", JSON.stringify(totals));
             
             // Update grand total
             sessionStorage.setItem(\"grand_total\", JSON.stringify({
                 'code':       'total',
                 'title':      'Total',
                 'value':      newGrandTotal,
                 'sort_order': 9
             }));
             
             // Refresh display
             getCartProductHTML();
         }
         function removeCreditPoints() {
             // Restore original total
             let originalGrandTotal = sessionStorage.getItem('originalGrandTotal');
             
             if (originalGrandTotal) {
                 const original = parseFloat(originalGrandTotal);
         
                 // Update TOTAL box
                 document.getElementById('grandTotal').value =
                     format(original, posData.currency_code);
         
                 // NEW: sync global total used by updateTotals
                 grandTotalAmount = original;
                 
                 // Remove credit points from totals
                 let totals = JSON.parse(sessionStorage.getItem(\"totals\")) || [];
                 totals = totals.filter(item => item.code !== 'credit_points');
                 
                 // Restore grand total
                 const grandTotalItem = totals.find(item => item.code === 'total');
                 if (grandTotalItem) {
                     grandTotalItem.value = original;
                 }
                 
                 sessionStorage.setItem(\"totals\", JSON.stringify(totals));
                 
                 // Update grand total in session
                 sessionStorage.setItem(\"grand_total\", JSON.stringify({
                     'code': 'total',
                     'title': 'Total',
                     'value': original,
                     'sort_order': 9
                 }));
                 
                 // Clear credit points data
                 sessionStorage.removeItem('credit_points_used');
                 sessionStorage.removeItem('originalGrandTotal');
                 
                 // Refresh display
                 getCartProductHTML();
         
                 // NEW: recompute pending / received / returnable
                 updateTotals();
             }
         }
         
         
