         // Modal button event handlers
         function attachModalEventHandlers() {
           const sendOtpBtn = document.getElementById('sendOtpBtn');
           const verifyOtpBtn = document.getElementById('verifyOtpBtn');
           const addCustomerBtn = document.getElementById('addCustomerBtn');
           
           const phoneSection = document.getElementById('phoneSection');
           const otpSection = document.getElementById('otpSection');
           const otpSuccessMessage = document.getElementById('otpSuccessMessage');
           const customerDetailsSection = document.getElementById('customerDetailsSection');
           
           const addCustomerError = document.getElementById('addCustomerError');
           const addCustomerSuccess = document.getElementById('addCustomerSuccess');
         
           function clearMessages() {
             addCustomerError.style.display = 'none';
             addCustomerSuccess.style.display = 'none';
             otpSuccessMessage.style.display = 'none';
           }
         
         // ================================
         // STEP 1: Verify Telephone via API
         // ================================
         
         
         
         
         var existingCustomerDetails = null;
         
         sendOtpBtn.addEventListener('click', function () {
           clearMessages();
         
           const mobile = \$('#newtelephone').val();
           //console.log('Mobile value:', mobile, 'Length:', mobile.length);
         
           if (mobile === \"\") {
             addCustomerError.textContent = 'Please enter a mobile number.';
             addCustomerError.style.display = 'block';
             return;
           }
         
           if (mobile.length !== 10 || !/^\\d{10}\$/.test(mobile)) {
             addCustomerError.textContent = 'Enter a valid 10-digit mobile number.';
             addCustomerError.style.display = 'block';
             return;
           }
         
           // Disable button to prevent double clicks
           sendOtpBtn.disabled = true;
           sendOtpBtn.textContent = 'Sending...';
         
           // Step 1: Check if telephone already exists
           \$.ajax({
             url: 'https://myteknoland.com/JEWELLERY/index.php?route=ws/common.verify_telephone',
             type: 'POST',
             dataType: 'json',
             data: { telephone: mobile },
             success: function (response) {
               sendOtpBtn.disabled = false;
               sendOtpBtn.textContent = 'Send OTP';
               //console.log('Verify Telephone API Response:', response);
         
               if (response.success === '0') {
                 // Telephone not found Ñ‚Â€Â” send OTP
                 sendOtpToCustomer(mobile);
               } 
               
           
             
             else if (response.success === '1') {
             // Ñ‚ÂœÂ… Customer already exists
             addCustomerSuccess.textContent = 'Customer already exists';
             addCustomerSuccess.style.display = 'block';
             
             // Store whole response for reuse
             var ExistingCustomerResponse = response;
             //console.log(JSON.stringify(ExistingCustomerResponse)); // Debug
             
                 if (ExistingCustomerResponse) {
                   // Ñ‚ÂœÂ… Update Customer Info section dynamically
                   \$('#customerNameInput').val(ExistingCustomerResponse.customer);
                   \$('#customerMobileInput').val(ExistingCustomerResponse.telephone);
                   \$('#customerEmailInput').val(ExistingCustomerResponse.email || '');
                    \$('#creditLimitSpan').text(ExistingCustomerResponse.rewards || '0.00');
                    
                     globalAdvanceAmount = parseFloat(ExistingCustomerResponse.wallet.trade) || 0;
         globalAdvanceAmount = parseFloat(globalAdvanceAmount.toFixed(2)); 
                   \$('#advancedAmountSpan').text(ExistingCustomerResponse.wallet.trade || '0.00');
                  
                 }
         
             // Clear OTP ref
             sessionStorage.removeItem('otp_ref');
         
             // Hide modal after short delay for smooth UX
             setTimeout(() => {
               const modal = bootstrap.Modal.getInstance(document.getElementById('addCustomerModal'));
               modal.hide();
               addCustomerSuccess.style.display = 'none';
             }, 1200);
         }
         
               
               else {
                 addCustomerError.textContent = response.message || 'This mobile number cannot be verified.';
                 addCustomerError.style.display = 'block';
               }
             },
             error: function (xhr, status, error) {
               sendOtpBtn.disabled = false;
               sendOtpBtn.textContent = 'Send OTP';
               console.error('AJAX Error:', error, xhr.responseText);
               //console.log(xhr.responseText);
               addCustomerError.textContent = 'Error verifying mobile number. Please try again.';
               addCustomerError.style.display = 'block';
             }
           });
         });
         
           // ============================
           // STEP 2: Send OTP via API
           // ============================
           function sendOtpToCustomer(mobile) {
             \$.ajax({
               url: 'https://myteknoland.com/JEWELLERY/index.php?route=ws/common.send_otp',
               type: 'POST',
               dataType: 'json',
               data: { telephone: mobile },
               success: function (response) {
                 if (response.success === '1' || response.success === '2') {
                   // Store otp_ref in session for later verification
                   //Unset session first
                   sessionStorage.removeItem('otp_ref');
                   sessionStorage.setItem('otp_ref', response.otp_ref);
                   
                   otpSection.style.display = 'block';
                   sendOtpBtn.style.display = 'none';
                   verifyOtpBtn.style.display = 'inline-block';
         
                   addCustomerSuccess.textContent = 'OTP sent successfully!';
                   addCustomerSuccess.style.display = 'block';
                 } else {
                   addCustomerError.textContent = response.message || 'Failed to send OTP. Try again.';
                   addCustomerError.style.display = 'block';
                 }
               },
               error: function () {
                 addCustomerError.textContent = 'Error sending OTP. Please try again.';
                 addCustomerError.style.display = 'block';
               }
             });
           }
         
           // ============================
           // STEP 3: Verify OTP via API
           // ============================
           verifyOtpBtn.addEventListener('click', function () {
             clearMessages();
         
             const mobile = document.getElementById('newtelephone').value.trim();
             const otp = document.getElementById('otp').value.trim();
             const otp_ref = sessionStorage.getItem('otp_ref');
             
             if (!otp) {
               addCustomerError.textContent = 'Please enter OTP.';
               addCustomerError.style.display = 'block';
               return;
             }
         
             \$.ajax({
               url: 'https://myteknoland.com/JEWELLERY/index.php?route=ws/common.verify_otp',
               type: 'POST',
               dataType: 'json',
               data: {
                 telephone: mobile,
                 otp: otp,
                 otp_ref: otp_ref
               },
               success: function (response) {
                 if (response.success === '1') {
                   otpSection.style.display = 'none';
                   verifyOtpBtn.style.display = 'none';
                   otpSuccessMessage.style.display = 'block';
         
                   setTimeout(() => {
                     otpSuccessMessage.style.display = 'none';
                     customerDetailsSection.style.display = 'block';
                   }, 1200);
                   
                    //Unset session first
                   sessionStorage.removeItem('otp_ref');
                   sessionStorage.setItem('otp_ref', response.otp_ref);
                 } else {
                   addCustomerError.textContent = response.message || 'Invalid OTP. Please try again.';
                   addCustomerError.style.display = 'block';
                 }
               },
               error: function () {
                 addCustomerError.textContent = 'Error verifying OTP. Please try again.';
                 addCustomerError.style.display = 'block';
               }
             });
           });
         
