         function showErrorFeedback(message) {
             const searchInput = document.getElementById('pos_search');
             if (searchInput) {
                 searchInput.style.borderColor = '#dc3545';
                 searchInput.style.backgroundColor = '#f8d7da';
                 searchInput.style.transition = 'all 0.3s ease';
                 
                 setTimeout(function() {
                     searchInput.style.borderColor = '';
                     searchInput.style.backgroundColor = '';
                 }, 1000);
             }
             
             console.warn('âŒ', message);
             showToast('âŒ ' + message, 'error');
         }
         
         function showToast(message, type) {
             type = type || 'info';
             
             // Check if toast container exists
             let toastContainer = document.getElementById('toast-container');
             if (!toastContainer) {
                 toastContainer = document.createElement('div');
                 toastContainer.id = 'toast-container';
                 toastContainer.style.cssText = 'position: fixed; top: 20px; right: 20px; z-index: 9999;';
                 document.body.appendChild(toastContainer);
             }
             
             // Create toast
             const toast = document.createElement('div');
             toast.className = 'toast toast-' + type;
             toast.style.cssText = 'background-color: ' + (type === 'success' ? '#28a745' : '#dc3545') + '; color: white; padding: 15px 20px; margin-bottom: 10px; border-radius: 5px; box-shadow: 0 4px 6px rgba(0,0,0,0.1); animation: slideIn 0.3s ease; max-width: 300px;';
             toast.textContent = message;
             
             toastContainer.appendChild(toast);
             
             // Remove toast after 3 seconds
             setTimeout(function() {
                 toast.style.animation = 'slideOut 0.3s ease';
                 setTimeout(function() {
                     toast.remove();
                 }, 300);
             }, 3000);
         }
         
         // ============================================
         // MANUAL SEARCH FUNCTION
         // ============================================
         function performSearch() {
             const searchTerm = \$('#pos_search').val().trim();
             //console.log(\"Search--------------------\",searchTerm);
             if (!searchTerm) return;
         
             const url =
                 'index.php?route=extension/purpletree_pos/pos/home|searchProducts&term=' +
                 encodeURIComponent(searchTerm);
                 
                 //console.log(\"url----------------\", url);
         
             \$.ajax({
                 url: url,
                 type: 'get',
                 dataType: 'json',
                 success: function (products) {
         
                     console.log('Search API result:', products);
         
                     if (!products || products.length === 0) {
                         showErrorFeedback('No products found');
                         return;
                     }
         
                     if (products.length === 1) {
                         allProductsCount.push(products[0]);
                         localStorage.setItem(\"allProductsCount\",JSON.stringify(allProductsCount));
                         addProductToCart(products[0]);
                         console.log(\"performSearch\");
                         \$('#pos_search').val('');
                         const input = document.getElementById(\"pos_search\");
                         input.focus();
                         return;
                     }
         
                     displaySearchResults(products);
                 }, error: function (e) {
                     //console.log(\"error\", e);
                 }
             });
         }
         
         
