         function submitHoldCart() {
             var descInput = document.getElementById(\"holdCartDescription\");
             var description = descInput ? descInput.value.trim() : \"\";
         
             if (!description) {
                 //console.log(\"Please enter cart hold description.\");
                 return;
             }
         
             // Take current cart from localStorage
             var posCart = JSON.parse(localStorage.getItem(\"pos_cart\") || \"[]\");
             if (!posCart || posCart.length === 0) {
                 alert(\"Cart is empty. Cannot hold.\");
                 return;
             }
         
             // Load existing holds
             var allHolds = JSON.parse(localStorage.getItem(HOLD_CART_KEY) || \"[]\");
         
             // Simple hold object: only id, description, and pos_cart snapshot
             var holdId = Date.now();
             var newHold = {
                 id: holdId,
                 description: description,
                 cart: posCart      // store pos_cart only
             };
         
             allHolds.push(newHold);
             localStorage.setItem(HOLD_CART_KEY, JSON.stringify(allHolds));
             console.log(\"submitholdcart\", JSON.stringify(allHolds));
              // Show cards
             renderHoldCartList();
             //console.log('hold area working???')
             // Clear cart UI + storage
             clearCartAreaUI();
             localStorage.removeItem(\"pos_cart\");
         
             if (typeof updateCartTotals === \"function\") {
                 updateCartTotals();
             }
             if (typeof updateInvoiceRightColumn === \"function\") {
                 updateInvoiceRightColumn();
             }
         
            
         
             closeHoldCartPopup();
         }
