         function restoreHoldCart(holdId) {
             var allHolds = JSON.parse(localStorage.getItem(HOLD_CART_KEY) || \"[]\");
             
             //console.log(\"restore----------hold ------------\" ,allHolds);
             var selectedHold = allHolds.find(function (h) { return h.id === holdId; });
             //console.log(\"restore\", allHolds);
             //console.log(\"hold id\", holdId);
             if (!selectedHold) {
                 //console.log(\"Hold not found.\");
                 return;
             }
             localStorage.setItem('currentSimpleHoldId', String(holdId));
         
             // 1) Write raw cart rows back to the POS cart key
             localStorage.setItem(\"pos_cart\", JSON.stringify(selectedHold.cart || []));
          if (typeof refreshPage === \"function\") {
                 // refreshPage() already calls: setPosTax, getCartProductHTML, posFuntions.posProduct(...)
                 // and internally rebuilds CartObj based on localStorage[\"poscart\"]. [file:4]
                 refreshPage();
             }
             
             // 3) Clear your simple cart UI and rebuild from CartObj products
             clearCartAreaUI();
             
             
             
             
             if (typeof CartObj !== \"undefined\" && typeof CartObj.getProducts === \"function\") {
                 var products = CartObj.getProducts(); // full product objects with name, price, etc. [file:4]
                 //console.log(\"cart---------------------CartObj-products\", products);
                 products.forEach(function (p) {
                     addProductRowToCartArea({
                         cart_id:p.cart_id,
                         product_id: p.product_id,
                         name: p.name,
                         heading_title: p.name,
                         price: parseFloat(p.price),
                         pos_quantity: p.pos_quantity,
                         posquantity: p.pos_quantity,
                         excluded:p.excluded,
                         gst_percent: p.gst_percent || 0,
                         tax_class_id: p.tax_class_id || 0
                     });
                 });
             }
         
             if (typeof updateCartTotals === \"function\") {
                 updateCartTotals();
             }
             if (typeof updateInvoiceRightColumn === \"function\") {
                 updateInvoiceRightColumn();
                 
             }
             if (typeof updateLiveTaxDetails === \"function\"){
                 updateLiveTaxDetails();
             }
             
         }
         function deleteHoldCart(holdId) {
             var allHolds = JSON.parse(localStorage.getItem(HOLD_CART_KEY) || \"[]\");
         
             // remove from array
             allHolds = allHolds.filter(function (h) { return h.id !== holdId; });
         
             if (allHolds.length) {
                 localStorage.setItem(HOLD_CART_KEY, JSON.stringify(allHolds));
             } else {
                 localStorage.removeItem(HOLD_CART_KEY);
             }
         
             // remove only that card from DOM
             var container = document.getElementById(\"holdCartList\");
             if (container) {
                 var card = container.querySelector(
                     \".hold-cart-card[data-hold-id='\" + holdId + \"']\"
                 );
                 if (card) {
                     container.removeChild(card);
                 }
             }
         }
         
         
         
         
