         // Product autocomplete search function
         function search_product_info(input) {
             var searchTerm = input.value.trim().toLowerCase();
             
             if (searchTerm.length === 0) {
                 \$('#product_autocomplete_list').empty().hide();
                 return;
             }
             
             // Get products from localStorage (pos_cart)
             let cartProducts = [];
             if (localStorage.getItem(\"pos_cart\") !== null) {
                 cartProducts = JSON.parse(localStorage.getItem(\"pos_cart\"));
             }
             
             // Create a unique set of product names (avoid duplicates)
             let uniqueProductNames = new Set();
             cartProducts.forEach(product => {
                 if (product.name && product.name.toLowerCase().includes(searchTerm)) {
                     uniqueProductNames.add(product.name);
                 }
             });
             
             // Display results
             \$('#product_autocomplete_list').empty().show();
             
             if (uniqueProductNames.size > 0) {
                 uniqueProductNames.forEach(name => {
                     let item = `
                     <li class=\"dropdown-item\" 
                         onclick=\"selectProductByName('\${name.replace(/'/g, \"\\\\'\")}')\"
                         style=\"cursor:pointer; padding:8px 12px; border-bottom:1px solid #2a3040; color: #fff;\">
                         \${name}
                     </li>`;
                     \$('#product_autocomplete_list').append(item);
                 });
             } 
            //  else {
            //      \$('#product_autocomplete_list').html('<li class=\"dropdown-item\" style=\"padding:8px 12px; color: #8a93a2;\">No products found</li>');
            //  }
         }
         
         // Select product from dropdown by name
         function selectProductByName(productName) {
             \$('#quick_add_name').val(productName);
             \$('#product_autocomplete_list').hide();
         }
         
         // Hide dropdown when clicking outside
         \$(document).on('click', function (e) {
             if (!\$(e.target).closest('#product_autocomplete_list').length && 
                 !\$(e.target).closest('#quick_add_name').length) {
                 \$('#product_autocomplete_list').hide();
             }
             if (!\$(e.target).closest('#category_autocomplete_list').length && 
                 !\$(e.target).closest('#manage_product_category').length) {
                 \$('#category_autocomplete_list').hide();
             }
         });
         
         // Category autocomplete search function
         function search_category_info(input) {
             var searchTerm = input.value.trim();
             
             if (searchTerm.length === 0) {
                 \$('#category_autocomplete_list').empty().hide();
                 return;
             }
             
             // Call API for category autocomplete
             \$.ajax({
                 url: 'index.php?route=extension/purpletree_pos/pos/home|categoryAutocomplete&filter=' + encodeURIComponent(searchTerm),
                 type: 'GET',
                 dataType: 'json',
                 
                 success: function(json) {
                     \$('#category_autocomplete_list').empty();
                     
                     if (json && json.length > 0) {
                         // Store categories in session for selection handling
                         sessionStorage.setItem(\"categorySData\", JSON.stringify(json));
                         
                         \$.each(json, function(key, val) {
                             if (val.name || val.category_name) {
                                 let categoryName = val.name || val.category_name;
                                 let categoryId = val.category_id || val.id;
                                 
                                 let item = `
                                 <li class=\"dropdown-item\"
                                     onclick=\"selectCategoryByName('\${categoryName.replace(/'/g, \"\\\\'\")}', \${categoryId})\"
                                     style=\"cursor:pointer; padding:10px 12px; border-bottom:1px solid #2a3040; color: #fff;\">
                                     \${categoryName}
                                 </li>`;
                                 
                                 \$('#category_autocomplete_list').append(item);
                             }
                         });
                         
                         \$('#category_autocomplete_list').show();
                     } else {
                         // Show \"No results\" message if no categories found
                         let item = `
                         <li class=\"dropdown-item\" style=\"cursor:default; padding:10px 12px; color: #8a93a2;\">
                             No categories found
                         </li>`;
                         \$('#category_autocomplete_list').append(item).show();
                     }
                 },
                 
                 error: function() {
                     // Fallback to local search if API fails
                     var searchTermLC = searchTerm.toLowerCase();
                     
                     // Get categories from globalPOS if available, or posData
                     let categories = [];
                     if (typeof posData !== 'undefined' && posData.allCategoriesDescription) {
                         categories = posData.allCategoriesDescription;
                     } else if (typeof globalPOS !== 'undefined' && globalPOS.allCategoriesDescription) {
                         categories = globalPOS.allCategoriesDescription;
                     }
                     
                     // Create a unique set of category names
                     let uniqueCategoryNames = new Set();
                     \$.each(categories, function(index, cateDesc) {
                         if (cateDesc.name && cateDesc.name.toLowerCase().includes(searchTermLC)) {
                             uniqueCategoryNames.add(cateDesc.name);
                         }
                     });
                     
                     // Display results
                     \$('#category_autocomplete_list').empty().show();
                     
                     if (uniqueCategoryNames.size > 0) {
                         uniqueCategoryNames.forEach(name => {
                             let item = `
                             <li class=\"dropdown-item\" 
                                 onclick=\"selectCategoryByName('\${name.replace(/'/g, \"\\\\'\")}')\"
                                 style=\"cursor:pointer; padding:10px 12px; border-bottom:1px solid #2a3040; color: #fff;\">
                                 \${name}
                             </li>`;
                             \$('#category_autocomplete_list').append(item);
                         });
                     } else {
                         \$('#category_autocomplete_list').hide();
                     }
                 }
             });
         }
         
