         let currentVal = \"0\";
    const screen = document.getElementById('display');

    function input(val) {
        if (currentVal === \"0\" && val !== '.') {
            currentVal = val;
        } else {
            currentVal += val;
        }
        update();
    }

    function clearDisplay() {
        currentVal = \"0\";
        update();
    }

    function calculate() {
        try {
            currentVal = eval(currentVal).toString();
        } catch {
            currentVal = \"Error\";
        }
        update();
    }

        document.addEventListener(\"keydown\", function(event) {
            
            if (
                event.target.tagName === \"INPUT\" ||
                event.target.tagName === \"TEXTAREA\" ||
                event.target.isContentEditable
            ) {
                return;
            }
    
        let key = event.key;

        if (!isNaN(key) || key === \".\" || key === \"+\" || key === \"-\" || key === \"*\" || key === \"/\") {
            input(key);
        } else if (key === \"Enter\") {
            calculate();
        } else if (key === \"Backspace\") {
            screen.innerText = screen.innerText.slice(0, -1) || \"0\";
        } else if (key === \"Escape\") {
            clearDisplay();
        }
    });
    
    function update() {
        screen.innerText = currentVal;
    }
    
    function liveUpdate() {
        // 1. Grab values instantly on input change
        const rawPrice = parseFloat(document.getElementById('userPrice').value) || 0;
        const additionalPercent = parseFloat(document.getElementById('userAdditional').value) || 0;

        // 2. Logic: Wholesale is Price divided by 5
        const baseCalc = rawPrice / 5;
        const wholesale = baseCalc;

        // 3. Logic: Retail is base + the additional percentage
        const percentageValue = baseCalc * (additionalPercent / 100);
        const retail = baseCalc + percentageValue;

        // 4. Update the UI with 2 decimal places
        document.getElementById('wholesaleResult').value = wholesale.toFixed(2);
        document.getElementById('retailResult').value = retail.toFixed(2);
    }
    
