      <style>
         /* Premium Loading Indicator */
         .pos-loader-overlay {
             display: none;
             position: fixed;
             top: 0;
             left: 0;
             width: 100%;
             height: 100%;
             background: rgba(0, 0, 0, 0.4);
             backdrop-filter: blur(4px);
             z-index: 11000;
             justify-content: center;
             align-items: center;
             flex-direction: column;
         }
         .pos-loader-spinner {
             width: 60px;
             height: 60px;
             border: 5px solid rgba(201, 162, 77, 0.1);
             border-top: 5px solid #C9A24D;
             border-radius: 50%;
             animation: pos-spin 1s cubic-bezier(0.68, -0.55, 0.265, 1.55) infinite;
             box-shadow: 0 0 20px rgba(201, 162, 77, 0.3);
         }
         .pos-loader-text {
             margin-top: 15px;
             color: #C9A24D;
             font-weight: 700;
             font-size: 14px;
             letter-spacing: 2px;
             text-transform: uppercase;
             text-shadow: 0 2px 4px rgba(0,0,0,0.5);
         }
         @keyframes pos-spin {
             0% { transform: rotate(0deg); }
             100% { transform: rotate(360deg); }
         }

         /* MAIN CONTAINER - This is your #posproduct */
         /* Disabled Opacity Rule */
         button:disabled, button.disabled {
             opacity: 0.5 !important;
         }

         .box {
         flex: 1; /* equal width */
         border-left: 1px solid white; /* border between boxes */
         padding: 0.5rem 1rem; /* consistent vertical and horizontal padding */
         text-align: center;
         display: flex;
         align-items: center;
         justify-content: center;
         height: 27px; /* consistent height */
         box-sizing: border-box;
         text-transform: uppercase;
         font-weight: 600;
         font-size: 0.9rem;
         }
         /* Remove left border for the first box */
         .box:first-child {
         border-left: none;
         }
         .pos-sidebar-body::-webkit-scrollbar {
         display: none;
         }
         .pos-sidebar::-webkit-scrollbar {
         display: none;
         }
         #posproduct {
         display: grid;
         grid-template-columns: repeat(4, 1fr);
         gap: 15px;
         padding: 15px;
         background: #0a0a0a;
         width: 100%;
         }
         .pos-content::-webkit-scrollbar {
         display: none;
         }
         /* Product Card Container */
         .product-container,
         .product-area {
         background: #1a1a1a !important;
         border-radius: 4px;
         overflow: hidden;
         transition: transform 0.2s ease, box-shadow 0.2s ease;
         cursor: pointer;
         border: 1px solid #2a2a2a;
         position: relative;
         display: flex;
         flex-direction: column;
         width: 100%;
         max-width: 100%;
         box-sizing: border-box;
         }
         .product-container:hover,
         .product-area:hover {
         transform: translateY(-3px);
         box-shadow: 0 5px 15px rgba(255, 255, 255, 0.1);
         border-color: #333;
         }
         /* Info Icon */
         .prod-info {
         position: absolute;
         top: 10px;
         right: 10px;
         color: #00bcd4;
         background: rgba(0, 0, 0, 0.7);
         width: 28px;
         height: 28px;
         display: flex;
         align-items: center;
         justify-content: center;
         border-radius: 50%;
         font-size: 14px;
         cursor: pointer;
         z-index: 99;
         transition: all 0.2s ease;
         }
         .prod-info:hover {
         background: rgba(0, 0, 0, 0.9);
         transform: scale(1.1);
         color: #00d9ff;
         }
         /* Product Link */
         .product {
         text-decoration: none;
         display: flex;
         flex-direction: column;
         flex: 1;
         color: inherit;
         width: 100%;
         }
         /* Image Container */
         .product .img {
         width: 100%;
         height: 160px;
         overflow: hidden;
         background: #000;
         padding: 0;
         display: block;
         }
         .product .img img {
         width: 100%;
         height: 100%;
         object-fit: cover;
         transition: transform 0.3s ease;
         display: block;
         }

         /* UPI QR Blur Effect */
         .upi-qr-blur {
             filter: blur(3px);
             transition: filter 0.5s ease;
             pointer-events: none;
             user-select: none;
         }
         .upi-qr-unblur {
             filter: blur(0);
         }
         .upi-qr-container {
             background: #fff;
             border: 1px solid #ddd;
             border-radius: 8px;
             padding: 10px;
             display: inline-block;
             margin-top: 10px;
             box-shadow: 0 4px 10px rgba(0,0,0,0.1);
         }
         .product:hover .img img {
         transform: scale(1.05);
         }
         /* Text Container */
         .product .text {
         padding: 10px 12px;
         background: #1a1a1a;
         display: flex;
         flex-direction: column;
         flex: 1;
         }
         /* Title */
         .product .text .title {
         text-align: left;
         color: #fff;
         font-size: 10px;
         font-weight: 650;
         text-transform: uppercase;
         margin: 0 0 5px 0;
         letter-spacing: 0.3px;
         line-height: 1.3;
         min-height: 32px;
         display: -webkit-box;
         -webkit-line-clamp: 2;
         line-clamp: 2;
         -webkit-box-orient: vertical;
         overflow: hidden;
         }
         /* Description */
         .product .text .desc {
         color: #888;
         font-size: 8px;
         margin: 0 0 8px 0;
         line-height: 1.3;
         display: -webkit-box;
         -webkit-line-clamp: 2;
         line-clamp: 2;
         -webkit-box-orient: vertical;
         overflow: hidden;
         }
         /* Price */
         .product .text .price {
         color: #fff;
         font-size: 15px;
         font-weight: 700;
         margin: 0;
         margin-top: auto;
         }
         .price-new {
         color: #fff;
         font-size: 15px;
         font-weight: 700;
         }
         .pts-price-old {
         color: #666;
         font-size: 12px;
         text-decoration: line-through;
         margin-left: 5px;
         }
         /* Old CSS (if you have it, remove it) */
         #posproduct .pos-product {
         width: 300px;
         height: 300px;
         object-fit: contain;
         }
         .pos-product {
         display: none !important;
         }
         /* Responsive - 3 columns for tablets */
         @media (max-width: 1200px) {
         #posproduct {
         grid-template-columns: repeat(3, 1fr);
         gap: 12px;
         }
         }
         /* Responsive - 2 columns for mobile */
         @media (max-width: 900px) {
         #posproduct {
         grid-template-columns: repeat(2, 1fr);
         gap: 10px;
         }
         .product .img {
         height: 140px;
         }
         }
         @media (max-width: 600px) {
         #posproduct {
         grid-template-columns: repeat(2, 1fr);
         gap: 8px;
         padding: 10px;
         }
         .product .img {
         height: 120px;
         }
         .product .text {
         padding: 8px 10px;
         }
         .product .text .title {
         font-size: 12px;
         min-height: 28px;
         }
         .product .text .desc {
         font-size: 10px;
         }
         .price-new,
         .product .text .price {
         font-size: 13px;
         }
         }
         /* Mobile Sidebar Adjustments */
         @media (max-width: 768px) {
         .pos-sidebar {
         position: fixed;
         width: 100%;
         height: 100vh;
         top: 0;
         right: -100%;
         background: #111;
         transition: right 0.3s ease;
         z-index: 1000;
         }
         .pos-mobile-sidebar-toggled .pos-sidebar {
         right: 0;
         }
         .pos-content {
         height: 100vh;             /* Fill full viewport height */
         max-height: 100vh;         /* Restrict max height */
         padding: 0 !important;
         margin: 0 !important;
         box-sizing: border-box;
         overflow: auto; 
         scrollbar-width: none; 
         -ms-overflow-style: none;
         }
         .pos-menu {
         display: none;
         }
         .btn, .nav-link {
         font-size: 14px;
         padding: 10px;
         }
         #posproduct {
         grid-template-columns: repeat(2, 1fr);
         }
         .product .img {
         height: 180px;
         }
         .product .text .title {
         font-size: 12px;
         }
         .pos-fixed-bottom {
         position: fixed;
         bottom: 0;
         left: 0;
         width: 100%;
         background: #000;
         z-index: 2000;
         }
         body, html {
         overflow-x: hidden;
         }
         .modal-dialog {
         max-width: 95%;
         margin: 10px auto;
         }
         }
         /* Cart Product Styling - Image 2 Style */
         .pos-order-product {
         display: flex;
         padding: 15px 0;
         border-bottom: 1px solid rgba(255,255,255,0.1);
         position: relative;
         }
         .pos-order-product-img {
         width: 80px;
         height: 80px;
         margin-right: 15px;
         flex-shrink: 0;
         }
         .pos-order-product-img .img {
         width: 100%;
         height: 100%;
         background-size: cover;
         background-position: center;
         border-radius: 4px;
         }
         .pos-order-product-info {
         flex: 1;
         display: flex;
         flex-direction: column;
         }
         .pos-order-product-price {
         margin-left: 15px;
         min-width: 80px;
         text-align: right;
         }
         .pos-search-div.mb-3 {
         position: sticky !important;
         top: 0 !important;
         z-index: 999 !important;
         height: 74px !important; /* consistent fixed height */
         overflow: hidden !important; /* prevent scroll */
         box-sizing: border-box;
         }
         /* Remove confirmation styling */
         .pos-remove-confirmation {
         position: absolute;
         top: 10px;
         left: 0;
         right: 0;
         bottom: 0;
         background: rgba(0,0,0,0.95);
         display: flex;
         align-items: center;
         justify-content: center;
         color: #fff;
         padding: 15px;
         border-radius: 4px;
         }
         /* Quantity button adjustments */
         .pos-order-product .btn-secondary {
         background: #2a2a2a;
         border-color: #2a2a2a;
         color: #fff;
         }
         .pos-order-product .btn-secondary:hover {
         background: #3a3a3a;
         border-color: #3a3a3a;
         }
         .w-40px {
         width: 40px !important;
         }
         .modal-pos-product + .option-list select.form-control {
         background-color: #f0f0f0;
         color: #000;
         border: 1px solid #ccc;
         }
         /* Cart item removal overlay */
         .pos-cart-item,
         .cart-product-row {
         position: relative;
         }
         .pos-remove-confirmation {
         position: absolute;
         top: 10px;
         left: 0;
         right: 0;
         bottom: 0;
         display: flex;
         align-items: center;
         justify-content: center;
         z-index: 50;
         }
         .remove-overlay {
         position: absolute;
         top: -25;
         left: 0;
         right: 0;
         bottom: 0;
         background-color: rgba(255, 255, 255, 0.15);
         backdrop-filter: blur(3px);
         }
         .remove-dialog {
         margin-top: -15px;
         position: relative;
         z-index: 51;
         text-align: center;
         padding: 20px;
         }
         .remove-icon {
         margin-bottom: 10px;
         }
         .remove-icon i {
         font-size: 25px;
         color: #fff;
         }
         .remove-text {
         color: #fff;
         font-size: 10px;
         font-weight: 600;
         margin-bottom: 6px;
         letter-spacing: 0.5px;
         text-transform: uppercase;
         }
         .remove-buttons {
         display: flex;
         gap: 30px;
         justify-content: center;
         }
         .btn-remove-no,
         .btn-remove-yes {
         padding: 3px 25px;
         font-size: 13px;
         font-weight: 600;
         text-transform: uppercase;
         border: none;
         cursor: pointer;
         min-width: 70px;
         text-decoration: none;
         display: inline-block;
         }
         .btn-remove-no {
         background-color: #fff;
         color: #333;
         }
         .btn-remove-no:hover {
         background-color: #f0f0f0;
         }
         .btn-remove-yes {
         background-color: rgba(255, 255, 255, 0.2);
         color: #fff;
         border: 1px solid rgba(255, 255, 255, 0.3);
         }
         .btn-remove-yes:hover {
         background-color: rgba(255, 255, 255, 0.3);
         }
         /* Prevent horizontal scroll on product page */
         body, html {
         overflow-x: hidden;
         }
         .product-area, .product-container {
         overflow: hidden !important;
         }
         img {
         pointer-events: none !important;
         user-select: none !important;
         -webkit-user-drag: none !important;
         }
         /* Table Grid Styling */
         .table-grid {
         display: grid;
         grid-template-columns: repeat(auto-fill, minmax(200px, 1fr));
         gap: 15px;
         padding: 20px;
         }
         .table-card {
         background: #1a1a1a;
         border: 2px solid #2a2a2a;
         border-radius: 8px;
         padding: 20px;
         cursor: pointer;
         transition: all 0.3s ease;
         position: relative;
         }
         .table-card:hover {
         border-color: #00bcd4;
         transform: translateY(-2px);
         box-shadow: 0 4px 12px rgba(0, 188, 212, 0.3);
         }
         .table-card.occupied {
         border-color: #f44336;
         }
         .table-card.available {
         border-color: #4caf50;
         }
         .table-header {
         font-size: 12px;
         color: #888;
         margin-bottom: 8px;
         text-transform: uppercase;
         }
         .table-number {
         font-size: 32px;
         font-weight: 700;
         color: #fff;
         margin-bottom: 8px;
         }
         .table-capacity {
         font-size: 14px;
         color: #999;
         }
         .table-status-icon {
         position: absolute;
         top: 15px;
         right: 15px;
         width: 32px;
         height: 32px;
         border-radius: 50%;
         display: flex;
         align-items: center;
         justify-content: center;
         font-size: 18px;
         }
         .table-status-icon.available {
         background: rgba(76, 175, 80, 0.2);
         color: #4caf50;
         }
         .table-status-icon.occupied {
         background: rgba(244, 67, 54, 0.2);
         color: #f44336;
         }
         #customerMobileInput,
         #customerNameInput,
         #customerEmailInput {
         color: #000 !important;
         background-color: #fff !important;
         }
         /* Product autocomplete dropdown styling */
         #product_autocomplete_list {
         background: #0f121a;
         border: 1px solid #2a3040;
         border-radius: 4px;
         margin-top: 4px;
         }
         #product_autocomplete_list .dropdown-item {
         color: #fff;
         transition: background 0.2s ease;
         }
         #product_autocomplete_list .dropdown-item:hover {
         background: #1a1f2e;
         }
         #category_autocomplete_list {
         background: #0f121a;
         border: 1px solid #2a3040;
         border-radius: 4px;
         margin-top: 4px;
         }
         #category_autocomplete_list .dropdown-item {
         color: #fff;
         transition: background 0.2s ease;
         }
         #category_autocomplete_list .dropdown-item:hover {
         background: #1a1f2e;
         }
         /* Prevent browser autofill color override (for Chrome, Edge, Safari) */
         #customerMobileInput:-webkit-autofill,
         #customerNameInput:-webkit-autofill,
         #customerEmailInput:-webkit-autofill {
         -webkit-box-shadow: 0 0 0px 1000px #fff inset !important;
         -webkit-text-fill-color: #000 !important;
         }
         /* On focus, keep background and text readable */
         #customerMobileInput:focus,
         #customerNameInput:focus,
         #customerEmailInput:focus {
         background-color: #fff !important;
         color: #000 !important;
         }
         #table-grid-container {
         display: grid !important;
         grid-template-columns: repeat(4, 1fr) !important;
         gap: 1px !important;
         padding: 0px !important;
         }
         .table-card {
         width: 100%;
         min-height: 160px;
         box-sizing: border-box;
         transition: transform .12s ease, box-shadow .12s ease;
         }
         .table-card:hover { transform: translateY(-3px); box-shadow: 0 6px 18px rgba(0,0,0,0.35); }
         .table-card.disabled { opacity: 0.6; cursor: not-allowed !important; }
         .table-card .order-line { color: #00bc8c; font-size: 11px; margin-top:6px; }
         .table-card .meta { color:#8a93a2; font-size:11px; margin-top:8px; }
         .hold-grid {
