         box-shadow: 0 0 8px rgba(0,0,0,0.2);
         color: #000000 !important;
         }
         /* Invoice button styling */
         .pos-search-div #invoiceBtn {
         background: linear-gradient(180deg, #f5f5f5 0%, #e0e0e0 100%);
         border: 1px solid #999;
         color: #333;
         transition: all 0.2s ease;
         padding: 8px 16px;
