         .pos-search-div .pos-delet-margin-left i {
         font-size: 24px;
         color: #333 !important;
         }
         /* POS SYSTEM Title in header */
         .pos-search-div .pos-system-title {
         background: linear-gradient(180deg, #f0f0f0 0%, #d8d8d8 100%);
         border-right: 2px solid #999;
         display: flex;
         align-items: center;
         font-size: 14px;
         font-weight: 700;
         letter-spacing: 1px;
         color: #222;
         cursor: default;
         }
         .pos-search-div .pos-system-title iconify-icon {
         color: #555;
         }
         
         /* Product Exclusion Toggle Button Styles */
         .exclude-toggle-btn {
             width: 20px;
             height: 20px;
             border-radius: 50%;
             border: 1px solid #333;
             cursor: pointer;
             transition: all 0.3s ease;
             padding: 0;
             display: inline-flex;
             align-items: center;
             justify-content: center;
         }
         
         /* Red state - product is INCLUDED in calculations (initial state) */
         .exclude-toggle-btn.included {
             background-color: #ff4444;
             box-shadow: 0 2px 4px rgba(255, 68, 68, 0.3);
         }
         
         .exclude-toggle-btn.included:hover {
             background-color: #ff6666;
             transform: scale(1.1);
         }
         
         /* Green state - product is EXCLUDED from calculations */
         .exclude-toggle-btn.excluded {
             background-color: #44ff44;
             box-shadow: 0 2px 4px rgba(68, 255, 68, 0.3);
         }
         
         .exclude-toggle-btn.excluded:hover {
             background-color: #66ff66;
             transform: scale(1.1);
         }
         
         /* Excluded row styling - red background and strikethrough */
         .cart-row.excluded-row {
             background-color: #f02d2d !important;
             position: relative;
         }
         
         .cart-row.excluded-row .cart-cell {
             text-decoration: line-through;
             opacity: 0.7;
         }
         
         .cart-row.excluded-row .cart-cell.index,
         .cart-row.excluded-row .cart-cell:last-child {
             text-decoration: none; /* Don't strikethrough index and action buttons */
         }
         
