         display: flex;
         justify-content: space-between;
         align-items: center;
         }
         .search-result-card:hover {
         transform: translateY(-5px);
         box-shadow: 0 8px 20px rgba(139, 115, 85, 0.3);
         border-color: #fff;
         }
         .search-result-info {
         flex: 1;
         color: #fff;
         }
