                  <div class=\"calc-display\" id=\"calcDisplay\">0</div>
                  <div class=\"calc-grid\">
                     <!-- top row -->
                     <button class=\"calc-btn calc-func\" onclick=\"calcAllClear()\">AC</button>
                     <button class=\"calc-btn calc-func\" onclick=\"calcDelete()\">DE</button>
