         \t\t}
         \t
         \t\tfunction getTotal() {
         \t\t\tvar total = 0;
         \t\t\tvar tax = 0;
         \t\t\t\$.each(CartObj.getProducts(),function(key,val){
         \t\t\t\ttotal += (taxObj.calculate(val.price,val.tax_class_id,posData.config_tax))* val.quantity;
         \t\t\t});
         \t\t\tposData.order_total = total + getProvTax();
         \t\t\treturn total;
         \t\t\t
         \t\t}
         \t\t
         \t\tfunction getProvTax() {
             var vatSum = 0;
             var ecoTaxSum = 0;
             
             \$.each(CartObj.getProducts(), function(key, val) {
                 \$.each(val.tax, function(key, subvalue) {
                     // Identify VAT and Eco Tax by name
                     if (subvalue.name.toLowerCase().includes('vat')) {
                         vatSum += subvalue.tax * val.quantity;
                     }
                     if (subvalue.name.toLowerCase().includes('eco')) {
                         ecoTaxSum += subvalue.tax * val.quantity;
                     }
                 });
             });
             
             // Return VAT - Eco Tax (subtract eco tax from VAT)
             return vatSum - ecoTaxSum;
         }
         \t\tfunction getTaxBreakdownByType() {
             var taxSummary = {}; // { tax_name: {amount: X, rate: Y, type: Z, id: W}, ... }
             \$.each(CartObj.getProducts(), function(_, product) {
                 \$.each(product.tax, function(_, taxObj) {
                     // Ensure unique key per tax rate
                     var key = taxObj.name + '|' + taxObj.rate + '|' + taxObj.type;
                     if (!taxSummary[key]) {
                         taxSummary[key] = {
                             name: taxObj.name,
                             amount: 0,
                             rate: taxObj.rate,
                             type: taxObj.type,
                             id: taxObj.tax_rate_id
                         };
                     }
                     taxSummary[key].amount += parseFloat(taxObj.tax) * product.quantity;
                 });
             });
             return taxSummary;
         }
         
