          function format(number, currency, value = '', format = true, decimals = 2) {  
          var currencyData = globalPOS;
          var currencyVal='';
          \tif(typeof currencyData.currency != 'undefined'){
          \t\t\$.each(currencyData.currency,function(key,val){
          \t\t\tif(currency == val.code){
          \t\t\t\tcurrencyVal= val;
          \t\t\t}
          \t\t});
          \t}
          \t
          \tif(currencyVal){
          \t\tsymbol_left = currencyVal.symbol_left;
          \t\tsymbol_right = currencyVal.symbol_right;
          
          \t\tif (!value) {
          \t\t\tvalue = currencyVal.value;
          \t\t}
          \t\t
          \t\tvar amount = value ? parseFloat(number) * value : parseFloat(number);
          \t\t
          \t\t// MAINTAIN DECIMALS: Only round if decimals is 0
          \t\tif (decimals === 0) {
          \t\t\tamount = Math.round(amount);
          \t\t}
          \t\t
          \t\tif (!format) {
          \t\t\treturn amount;
          \t\t}
          
          \t\tvar string = '';
          
          \t\tif (symbol_left) {
          \t\t\tstring += symbol_left;
          \t\t}
          
          \t\t// FORMAT WITH SPECIFIED DECIMAL PLACES
          \t\tstring += number_format(amount, decimals, '.', '');
          
          \t\tif (symbol_right) {
          \t\t\tstring += symbol_right;
          \t\t}
          \t\t
          \t\treturn string;
          \t}\t
          }
         function number_format (number, decimals, dec_point, thousands_sep) {
             // Strip all characters but numerical ones.
             number = (number + '').replace(/[^0-9+\\-Ee.]/g, '');
             var n = !isFinite(+number) ? 0 : +number,
                 prec = !isFinite(+decimals) ? 0 : Math.abs(decimals),
                 sep = (typeof thousands_sep === 'undefined') ? ',' : thousands_sep,
                 dec = (typeof dec_point === 'undefined') ? '.' : dec_point,
                 s = '',
                 toFixedFix = function (n, prec) {
                     var k = Math.pow(10, prec);
                     return '' + Math.round(n * k) / k;
                 };
             // Fix for IE parseFloat(0.55).toFixed(0) = 0;
             s = (prec ? toFixedFix(n, prec) : '' + Math.round(n)).split('.');
             if (s[0].length > 3) {
                 s[0] = s[0].replace(/\\B(?=(?:\\d{3})+(?!\\d))/g, sep);
             }
             if ((s[1] || '').length < prec) {
                 s[1] = s[1] || '';
                 s[1] += new Array(prec - s[1].length + 1).join('0');
             }
             return s.join(dec);
         }
