                        console.log(\"DEBUG: last_order_id:\", val.last_order_id);
                        console.log(\"DEBUG: last_order_amount:\", val.last_order_total);

                        if (val.last_order_id && val.last_order_total) {
                            \$('#lastOrderDisplay').html('Your last order is ' + val.last_order_id + ' with invoice amount of ' + val.last_order_total).show();
                        } else {
                            \$('#lastOrderDisplay').hide();
                        }
          
                          // Dynamic enabling of settlement checkbox
                          if (globalDueAmount > 0) {
                              \$('#includeDAInTotal').prop('disabled', false);
