         \t\t
         \tfunction holdCartArea() {
         
             //console.log(\"holdCartArea CALLED\");
         
             // ===============================
             // ðŸ”¥ FIX CORRUPTED HOLD_CART DATA
             // ===============================
             let hold_cart = JSON.parse(localStorage.getItem(\"hold_cart\") || \"[]\");
         
             hold_cart = hold_cart.map(entry => {
                 if (Array.isArray(entry)) {
                     //console.log(\"Found nested array, fixing:\", entry);
                     return entry[0]; // extract the real object
                 }
                 return entry;
             });
         
             // Save cleaned structure back
             localStorage.setItem(\"hold_cart\", JSON.stringify(hold_cart));
         
             //console.log(\"CLEANED HOLD CART =\", hold_cart);
             // ===============================
         
         
             // Hide tables; show product area
             \$(\"#tablesContent\").hide();
             \$('#invoiceContent').hide();
             \$(\"#posproduct\").hide();
             \$(\"#posCateProduct\").hide();
             \$(\"#pos-popular\").hide();
             \$(\".pos-search-div\").show();
         
             // RESET container completely
             \$('#posproduct').removeClass().addClass(\"hold-grid\").empty();
         
             if (hold_cart.length > 0) {
         
                 \$.each(hold_cart, function (key, val) {
         
                     // SHOW TABLE NAME INSTEAD OF CUSTOMER NAME
                     let table_name = (val.table && val.table.table_name) ? val.table.table_name : \"NO TABLE\";
                     let order_id   = val.table?.order_id || \"\";
                     let text       = val.data?.message || \"\";
                     let messageShort = text.substring(0, 20);
         
                     let html = `
                         <div class=\"hold-card\">
                             <div class=\"title\">\${table_name} 
                                 <span style=\"color:#0ff;font-size:12px;\">#\${order_id}</span>
                             </div>
                             <div class=\"desc\" style=\"margin-left:35px\">\${messageShort}</div>
                             <div class=\"icons\">
                                 <i class=\"fa fa-undo\" onclick=\"holdCartRestore(\${key})\"></i>
                                 <i class=\"fa fa-trash\" style=\"margin-left:65%\" onclick=\"confirmHoldDelete(\${key})\"></i>
                             </div>
                         </div>
                     `;
         
                     \$('#posproduct').append(html);
                 });
         
             } else {
         
                 \$('#posproduct').append(`  
                     <div class=\"hold-card\">No Hold Orders Found</div>
                 `);
             }
         }
         
         
         function holdCartRestore(key) {
             let hold_cart = JSON.parse(localStorage.getItem('hold_cart') || \"[]\");
             
             
             //console.log(\"hold -------------\", hold_cart);
             
             if (!hold_cart.length || !hold_cart[key]) return;
         
             let entry = hold_cart[key];
             //console.log(\"Restoring hold order key: \" + key);
             sessionStorage.setItem(\"current_hold_key\", key);
         
             // 1ï¸âƒ£ Restore products into cart
             localStorage.setItem(\"pos_cart\", JSON.stringify(entry.cart_data));
         
             // 2ï¸âƒ£ Restore customer (optional)
             if (entry.data.id) {
                 sessionStorage.setItem(\"currentCustomerData\", JSON.stringify(entry.data.customerData));
             } else {
                 sessionStorage.removeItem(\"currentCustomerData\");
             }
         
             // 3ï¸âƒ£ Restore table session (VERY IMPORTANT)
             if (entry.table) {
                 sessionStorage.setItem(\"selected_table_id\", entry.table.table_id);
                 sessionStorage.setItem(\"selected_table_name\", entry.table.table_name);
                 sessionStorage.setItem(\"selected_table_members\", entry.table.members);
                 sessionStorage.setItem(\"selected_order_id\", entry.table.order_id);
             }
         
             // 4ï¸âƒ£ Keep hold_cart unchanged (do not remove entry here)
             if (hold_cart.length) {
                 localStorage.setItem(\"hold_cart\", JSON.stringify(hold_cart));
             } else {
                 
             
                 localStorage.removeItem(\"hold_cart\");
             }
         
             // Show hold cart area & update UI
         
             // Hide irrelevant sections, show product area & hold cart container
             \$(\"#tablesContent\").hide();
             \$('#invoiceContent').hide();
             \$(\"#posCateProduct\").hide();
             \$(\"#pos-popular\").hide();
             \$(\".pos-search-div\").show();
         
             \$('#posproduct').show(); // Make sure shown
             \$('#posproduct').removeClass().addClass(\"hold-grid\").empty();
         
             if (hold_cart.length > 0) {
                 \$.each(hold_cart, function (idx, val) {
                     let table_name = (val.table && val.table.table_name) ? val.table.table_name : \"NO TABLE\";
                     let order_id = val.table?.order_id || \"\";
                     let text = val.data?.message || \"\";
                     let messageShort = text.substring(0, 20);
         
                     let html = `
                         <div class=\"hold-card\">
                             <div class=\"title\">\${table_name} 
                                 <span style=\"color:#0ff;font-size:12px;\">#\${order_id}</span>
                             </div>
                             <div class=\"desc\" style=\"margin-left:35px\">\${messageShort}</div>
                             <div class=\"icons\">
                                 <i class=\"fa fa-undo\" onclick=\"holdCartRestore(\${key})\"></i>
                                 <i class=\"fa fa-trash\" style=\"margin-left:65%\" onclick=\"confirmHoldDelete(\${key})\"></i>
                             </div>
                         </div>
                     `;
         
                     \$('#posproduct').append(html);
                 });
             } else {
                 \$('#posproduct').append(`<div class=\"hold-card\">No Hold Orders Found</div>`);
             }
         
             // Update cart UI with restored products
             getCartProductHTML();
         
             // 6ï¸âƒ£ Update POS Header Immediately
             \$(\".pos-sidebar-header .title\").text(entry.table.table_name);
             \$(\".pos-sidebar-header .order span\").text(\"#\" + entry.table.order_id);
         }
         
