         function holdCartDelete(key) {
             let hold_cart = JSON.parse(localStorage.getItem('hold_cart') || '[]');
             if (!hold_cart.length || !hold_cart[key]) return;
         
             // âœ… Remove entry
             hold_cart.splice(key, 1);
         
             if (hold_cart.length > 0) {
                 localStorage.setItem('hold_cart', JSON.stringify(hold_cart));
             } else {
                 localStorage.removeItem('hold_cart');
             }
         
             // ðŸ”„ Check if this was the ACTIVE hold cart before clearing
             let wasActive = sessionStorage.getItem(\"current_hold_key\") == key;
         
             if (wasActive) {
                 // CLEAR CART IF CARD BEING DELETED WAS ACTIVE
                 localStorage.removeItem(\"pos_cart\");
         
                 // CLEAR TABLE SESSION (only if it was active)
                 sessionStorage.removeItem(\"selected_table_id\");
                 sessionStorage.removeItem(\"selected_table_name\");
                 sessionStorage.removeItem(\"selected_table_members\");
                 sessionStorage.removeItem(\"selected_order_id\");
                 sessionStorage.removeItem(\"current_hold_key\");
                 
                 // RESET HEADER (only if it was active)
                 \$(\".pos-sidebar-header .title\").text(\"Table\");
                 \$(\".pos-sidebar-header .order span\").text(\"\");
             }
         
             // âœ… ALWAYS refresh hold cart UI without disrupting display
             // Don't call holdCartArea() or getCartProductHTML() here - let caller handle it
             // This prevents UI conflicts during hold cart browsing
         }
         
