         function unlockPayBtn(btn) {
  btn.disabled = false;
  btn.innerText = btn.dataset.originalText || 'Pay Now';
  btn.dataset.locked = '0';
}

         function getCartProductsFromDOMSync() {
              const rows = document.querySelectorAll('.cart-row[data-product]');
              const products = [];
            
              if (!rows.length) {
                errorMessage('Cart is empty', 2000);
                return null;
              }
            
              for (let row of rows) {
                let product;
                try {
                  product = JSON.parse(decodeURIComponent(row.dataset.product));
                } catch (e) {
                  errorMessage('Invalid cart data. Please re-add product.', 3000);
                  return null;
                }
            
                if (!validateCartProductSingle(product)) {
                  return null; // ❌ HARD STOP
                }
            
                products.push(product);
              }
            
              return products;
            }

         function createNewCustomerIfNeeded() {
           return new Promise((resolve, reject) => {
         
             // If already have customer_id from session, use it
             const customerData = JSON.parse(sessionStorage.getItem('currentCustomerData') || '{}');
             if (customerData.customer_id) {
               return resolve(customerData.customer_id);
             }
         
             // else create from inputs
             const name  = (\$('#customerNameInput').val() || '').trim();
             const phone = (\$('#customerMobileInput').val() || '').trim();
             const email = (\$('#customerEmailInput').val() || '').trim();
         
             if (!name) return reject(\"Please enter customer name.\");
             if (!phone || phone.length !== 10 || !/^\\d{10}\$/.test(phone)) {
               return reject(\"Please enter valid 10-digit mobile number.\");
             }
         
             \$.ajax({
               url: 'index.php?route=extension/purpletree_pos/pos/home|addNewCustomer',
               type: 'POST',
               dataType: 'json',
               contentType: 'application/json',
               processData: false,
               data: JSON.stringify({
                 firstname: name,
                 lastname: \"\",
                 telephone: phone,
                 email: email
               }),
               success: function(res) {
                 if (res.status === \"success\" && res.customer_id) {
                   resolve(res.customer_id);
                 } else {
                   reject(res.message || \"Customer creation failed\");
                 }
               },
               error: function() {
                 reject(\"Customer create request failed\");
               }
             });
         
           });
         }
         
         
         \$(document).on('input change', '#customerNameInput', function () {
             //console.log(\$(this).val());
               if (\$(this).val() !== '') {
                 \$('#nameError').text('');
               }
             });
             
             \$(document).on('input change', '#customerMobileInput', function () {
               if (\$(this).val() !== '') {
                 \$('#phoneError').text('');
               }
             });
             
             // Extra safety: Clear validation messages automatically if fields are filled (even programmatically)
             setInterval(() => {
               if (\$('#customerNameInput').val() !== '') \$('#nameError').text('');
               if (\$('#customerMobileInput').val() !== '') \$('#phoneError').text('');
             }, 400);
         
         
