                rawPhone = rawPhone.substring(1);
            }

            if (rawPhone && !rawPhone.startsWith('91')) {
                rawPhone = '91' + rawPhone;
            }

            if (!rawPhone) {
                console.warn('Customer phone not found, skipping WhatsApp');
                return;
            }

            /* ------------------ WHATSAPP API ------------------ */
            \$.ajax({
                url:
                    \"index.php?route=extension/purpletree_pos/pos/home|Order_sendwhatsapp\"
                    + \"&order_id=\" + encodeURIComponent(orderId)
                    + \"&phone=\" + encodeURIComponent(rawPhone),
