         (function () {
         
           function safeStr(v) { return (v === null || v === undefined) ? '' : String(v); }
           function uid() { return Math.floor(10000 + Math.random() * 90000); }
         
           // ---------------------------------------------------------
           // LOAD TABLES FROM DB
           // ---------------------------------------------------------
           function loadTables() {
             \$.ajax({
               url: 'index.php?route=extension/purpletree_pos/pos/home|getTables',
               type: 'GET',
               dataType: 'json',
               success: function (res) {
                 window.tablesList = res || [];
                 \$('#table-grid-container').html(generateTableBookingGrid(window.tablesList));
               },
               error: function (e) { console.error('Tables API error', e); }
             });
           }
           window.loadTables = loadTables;
         
           // ---------------------------------------------------------
           // RENDER TABLE CARDS (DB ONLY)
           // ---------------------------------------------------------
           function generateTableBookingGrid(tablesData) {
             let html = '';
         
             tablesData.forEach(table => {
         
               const orders = table.orders || [];
               const membersSeated = orders.reduce((s, o) => s + Number(o.members || 0), 0);
         
               const remaining = (parseInt(table.maxPax) || 0) - membersSeated;
               const disabled = remaining <= 0;
         
               html += `
                 <div class=\"table-card \${disabled ? 'disabled' : ''}\"
                     data-table-id=\"\${table.id}\"
                     data-table-name=\"\${safeStr(table.name)}\"
                     data-table-max=\"\${table.maxPax}\"
                     style=\"background:#1a1f2e;border-radius:10px;padding:9px;
                     border:2px solid \${disabled ? '#ff4444' : '#2a3040'};
                     cursor:\${disabled ? 'not-allowed' : 'pointer'};
                     width:260px;height:160px;display:flex;flex-direction:column;
                     justify-content:space-between;\">
                   
                   <div style=\"display:flex; justify-content:space-between; gap:12px;\">
                     
                     <div style=\"color:#fff; width:120px;\">
                       <div style=\"font-size:18px; font-weight:700; margin-bottom:10px;\">
                         \${safeStr(table.name)}
                       </div>
         
                       <div style=\"font-size:13px; margin-bottom:8px; color:#bfc5d2;\">
                         \${membersSeated}/\${table.maxPax} SEATED
                       </div>
                     </div>
         
                     <div style=\"display:flex;flex-direction:column;gap:6px;
                         align-items:flex-end;width:120px;height:90px;overflow-y:auto;\">
                       \${orders.length ? orders.map(o => `
                         <div style=\"display:flex; align-items:center; gap:6px; white-space:nowrap;\">
                           <span style=\"color:#00d18f; font-size:12px;\">
                             #\${o.orderId}/\${o.members}
                           </span>
                           <button 
                             class=\"clear-live-order-btn\"
                             data-live-id=\"\${o.id}\"
                             style=\"background:#ff4444;color:#fff;border:none;
                             padding:4px 6px;font-size:10px;border-radius:4px;\">
                             CLEAR
                           </button>
                         </div>
                       `).join('') : ''}
                     </div>
         
                   </div>
                 </div>
               `;
             });
         
             return html;
           }
         
           // small helper for escaping attributes in template
           function escapeHtml(text) {
             if (text === null || text === undefined) return '';
             return String(text).replace(/[&<>\"'`=\\/]/g, function (s) {
               return ({'&':'&amp;','<':'&lt;','>':'&gt;','\"':'&quot;',\"'\":'&#39;','/':'&#x2F;','`':'&#x60;','=':'&#x3D;'})[s];
             });
           }
         
           // ---------------------------------------------------------
           // CLICK TABLE â†’ OPEN SEAT MODAL (DB ONLY)
           // ---------------------------------------------------------
           \$(document).on('click', '#table-grid-container .table-card', function () {
         
             const card = \$(this);
         
             if (card.hasClass('disabled')) {
               //console.log('Table is FULL');
               return;
             }
         
             const tableId = card.data('table-id');
             const tableName = card.data('table-name');
             const tableMax = parseInt(card.data('table-max'), 10) || 0;
         
             const table = window.tablesList.find(t => String(t.id) === String(tableId)) || { orders: [] };
             const orders = table.orders || [];
         
             const membersSeated = orders.reduce((s, o) => s + Number(o.members || 0), 0);
             const remaining = tableMax - membersSeated;
         
             \$('#selectedTableInfo').text(`\${tableName} - Remaining seats: \${remaining} / Max: \${tableMax}`);
             \$('#seatError').hide();
             \$('#seatCountInput').val('');
         
             window._selectedTableForSeats = {
               id: tableId,
               name: tableName,
               max: tableMax,
               remaining: remaining
             };
         
             \$('#selectSeatsModal').modal('show');
           });
         
           // ---------------------------------------------------------
           // CONFIRM SEATS â†’ DB INSERT â†’ REDIRECT TO POS
           // ---------------------------------------------------------
           \$(document).on('click', '#confirmSeatsBtn', function () {
         
             const count = parseInt(\$('#seatCountInput').val(), 10);
             const sel = window._selectedTableForSeats;
         
             if (!sel) return;
             if (!count || count <= 0) { \$('#seatError').text('Enter a valid number').show(); return; }
             if (count > sel.remaining) { \$('#seatError').text(`Only \${sel.remaining} seats available`).show(); return; }
         
             const orderId = uid();
         
             // Persist temp selection in session for POS flow
             sessionStorage.setItem('selected_table_id', sel.id);
             sessionStorage.setItem('selected_table_name', sel.name);
             sessionStorage.setItem('selected_table_members', count);
             sessionStorage.setItem('selected_order_id', orderId);
         
             // Insert into DB (server should create a row in your live table)
             \$.ajax({
               url: 'index.php?route=extension/purpletree_pos/pos/home.addLiveTable',
               type: 'POST',
               dataType: 'json',
               data: {
                 table_id: sel.id,
                 order_id: orderId,
                 members: count
               },
               // no need to wait â€” server will have row; UI will be refreshed when tables are loaded
               error: function(err){ console.error('addLiveTable error', err); }
             });
         
             \$('#selectSeatsModal').modal('hide');
         
             // Redirect to POS
             const home = (typeof POS_HOME_URL !== 'undefined')
               ? POS_HOME_URL
               : window.location.origin + window.location.pathname;
         
             window.location.href = home;
           });
         
           // ---------------------------------------------------------
           // CLEAR LIVE ORDER (DB ONLY) â€” using orderId as identifier
           // ---------------------------------------------------------
           let _clearLiveId = null;
         
           \$(document).on('click', '.clear-live-order-btn', function (e) {
             e.stopPropagation();
             _clearLiveId = \$(this).data('live-id'); // here this is orderId (per your clarification)
             \$('#clearTableModal').modal('show');
           });
         
           \$(document).on('click', '#confirmClearTableBtn', function () {
         
             if (!_clearLiveId) return;
         
             \$.ajax({
               url: 'index.php?route=extension/purpletree_pos/pos/home|clearLiveTable',
               type: 'POST',
               dataType: 'json',
               data: { id: _clearLiveId }, // send orderId; change key if your API expects a different param
               success: function (res) {
                 if (res.success) {
                   \$('#clearTableModal').modal('hide');
                   loadTables(); // RELOAD FROM DB (reflects cleared seats)
                 } else {
                   // server returned failure â€” show message
                   //console.log(res.message || 'Unable to clear order');
                 }
               },
               error: function (err) {
                 console.error('clearLiveTable error', err);
                 //console.log('Clear request failed');
               }
             });
           });
         
           // ---------------------------------------------------------
           // PAGE READY
           // ---------------------------------------------------------
           \$(document).ready(function () {
         
             const selName = sessionStorage.getItem('selected_table_name');
             const selOrder = sessionStorage.getItem('selected_order_id');
         
             if (selName) \$('.pos-sidebar-header .title').text(selName);
             if (selOrder) \$('.order span').text('#' + selOrder);
         
         
         //new code 
           \$(document).on('click', '#tableSection', function (e) {
             e.preventDefault();
             
             // Remove active class from all nav links
             \$('.nav-link').removeClass('active');
             \$(this).addClass('active');
             \$('.pos-search-div').show();
             // Hide other sections
             \$('#posproduct').hide();
             \$('#posCateProduct').empty().hide();
             \$('#posCateProduct').hide();
             \$('#pos-popular').hide();
             \$('#invoiceContent').hide();
             
             // Show tables
             \$('#tablesContent').show();
             loadTables();
         });
         
         // Hide tables when clicking other navigation items
             \$(document).on('click', '.nav-link:not(#tableSection), .nav-item-header:not(#tableSection)', function () {
                 \$('#tablesContent').hide();
                 //\$('#invoiceContent').hide();
                 
                 // Show product sections
                 \$('#posproduct').show();
                 \$('#posCateProduct').show();
                 \$('#pos-popular').show();
             });
         
         
             \$(document).on('click', '.nav-link:not(#tableSection)', function () {
               \$('#tablesContent').hide();
               \$('#posproduct').show();
               \$('#posCateProduct').show();
               \$('#pos-popular').show();
               \$('.pos-search-div').show();
             });
         
             const query = new URLSearchParams(window.location.search);
