         // Set todayâ€™s date automatically
         function setTodayDates() {
             var today = new Date().toISOString().split('T')[0];
             \$('#invoice_from_date').val(today);
             \$('#invoice_to_date').val(today);
              \$('#invoice1_from_date').val(today);
             \$('#invoice1_to_date').val(today);
              \$('#wallet_history_from_date').val(today);
             \$('#wallet_history_to_date').val(today);
             \$('#quote_from_date').val(today);
             \$('#quote_to_date').val(today);
             \$('#mergebill_from_date').val(today);
             \$('#mergebill_to_date').val(today);
         }
                  // Global variable to store all invoice data
          var allInvoiceData = [];
          
          function loadInvoiceData() {
              var from = \$('#invoice1_from_date').val();
              var to   = \$('#invoice1_to_date').val();
              
              var orderId = \$('#invoice_id_search').val().trim().toLowerCase();
              var mobile  = \$('#invoice_mobile_search').val().trim().toLowerCase();
              var name    = \$('#invoice_name_search').val().trim().toLowerCase();
          
              \$.ajax({
                  url: 'index.php?route=extension/purpletree_pos/pos/home|getOrdersbyDate',
                   beforeSend: function() { showPremiumLoader(); },
                   complete: function() { hidePremiumLoader(); },
                  type: 'GET',
                  dataType: 'json',
                  data: { from_date: from, to_date: to, order_id: orderId, mobile: mobile, name: name },
                  success: function (res) {
                      if (!res || !res.data || !res.data.length) {
                          \$('#invoiceResults').html('<p style=\"color:white; padding:10px;\">No invoices found.</p>');
                          allInvoiceData = [];
                          return;
                      }
          
                      allInvoiceData = res.data;
                      window.invoiceApiTotals = res.totals || {};
                      
                      var filteredData = allInvoiceData.filter(function(row) {
                          var matchId     = orderId === '' || row.order_info.order_id.toString().toLowerCase().includes(orderId);
                          var matchMobile = mobile  === '' || (row.order_info.telephone || '').toString().toLowerCase().includes(mobile);
                          var fullName    = ((row.order_info.firstname || '') + ' ' + (row.order_info.lastname || '')).toLowerCase();
                          var matchName   = name    === '' || fullName.includes(name);
                          return matchId && matchMobile && matchName;
                      });
                      
                      if (!filteredData.length) {
                          \$('#invoiceResults').html('<p style=\"color:white; padding:10px;\">No results found matching your search.</p>');
                          return;
                      }

                      // Use totals returned by the API (status5 = Completed, status6 = Return Completed)
                      const totals = (res && res.totals) ? res.totals : {};

                      const completedTotals = {
                          cash: parseFloat(totals.status5_cash || 0),
                          upi: parseFloat(totals.status5_upi || 0),
                          ra: parseFloat(totals.status5_returnable || 0),
                          due: parseFloat(totals.status5_balance || 0),
                          received: parseFloat(totals.status5_total_received || 0),
                          total: parseFloat(totals.status5_subtotal || 0)
                      };

                      const returnCompletedTotals = {
                          cash: parseFloat(totals.status6_cash || 0),
                          upi: parseFloat(totals.status6_upi || 0),
