         // EXPORT INVOICE DATA TO EXCEL - INVOICE ONLY
         function exportInvoiceToExcel() {
             var fromDate = document.getElementById('invoice1_from_date').value;
             var toDate = document.getElementById('invoice1_to_date').value;
             
             if (!fromDate || !toDate) {
                 if (typeof errorMessage === \"function\") {
                     errorMessage(\"Please select both From and To dates\", 2000);
                 }
                 return;
             }
             
             // Find invoice table (adjust ID if different)
             var table = document.querySelector('#invoiceResults table') || 
                         document.querySelector('#invoiceTable') || 
                         document.querySelector('#invoiceContent table');
             
             if (!table || table.rows.length <= 1) {
                 if (typeof errorMessage === \"function\") {
                     errorMessage(\"No invoice data found. Please search first.\", 2000);
                 }
                 return;
             }
             
             // Convert table to Excel data
             var data = [];
             
             // Headers
             var headerRow = table.rows[0];
             var headers = [];
             for (var i = 0; i < headerRow.cells.length; i++) {
                 headers.push(headerRow.cells[i].textContent.trim());
             }
             data.push(headers);
             
             // Data rows
             for (var i = 1; i < table.rows.length; i++) {
                 var row = [];
                 for (var j = 0; j < table.rows[i].cells.length; j++) {
                     row.push(table.rows[i].cells[j].textContent.trim());
                 }
                 data.push(row);
             }
             
             // Create and download Excel
             var ws = XLSX.utils.aoa_to_sheet(data);
             var wb = XLSX.utils.book_new();
             XLSX.utils.book_append_sheet(wb, ws, \"Invoices\");
             
             var fileName = 'Invoice_Report_' + fromDate + '_to_' + toDate + '.xlsx';
             XLSX.writeFile(wb, fileName);
             
             if (typeof successMessage === \"function\") {
                 successMessage(\"✅ Invoice Excel exported successfully!\", 2000);
             }
         }
         function exportReturnToExcel() {
             // Use same IDs as loadReturnData / HTML
             var fromInput = document.getElementById('invoice_from_date');
             var toInput   = document.getElementById('invoice_to_date');
         
             if (!fromInput || !toInput) {
                 alert('Return date inputs not found');
                 return;
             }
         
             var fromDate = fromInput.value;
             var toDate   = toInput.value;
             
             if (!fromDate || !toDate) {
                 alert('Please select both From and To dates');
                 return;
             }
             
             // Get current table data
             var table = document.getElementById('returnTable');
             if (!table || table.rows.length === 0) {
                 alert('No data to export. Please search first.');
                 return;
             }
             
             // Convert table to array
             var data = [];
             var headers = [];
             
             // Get headers
             var headerRow = table.querySelector('thead tr');
             if (headerRow) {
                 headerRow.querySelectorAll('th').forEach(function(th) {
                     headers.push(th.textContent.trim());
                 });
             }
             data.push(headers);
             
             // Get rows
             table.querySelectorAll('tbody tr').forEach(function(tr) {
                 var row = [];
                 tr.querySelectorAll('td').forEach(function(td) {
                     row.push(td.textContent.trim());
                 });
                 if (row.length > 0) {
                     data.push(row);
                 }
             });
             
             // Create workbook
             var ws = XLSX.utils.aoa_to_sheet(data);
             var wb = XLSX.utils.book_new();
             XLSX.utils.book_append_sheet(wb, ws, 'Return Report');
             
             // Generate filename with date range
             var fileName = 'Return_Report_' + fromDate + '_to_' + toDate + '.xlsx';
             XLSX.writeFile(wb, fileName);
             
             //console.log('Return data exported successfully');
         }
         
         
         // Global variable to store all return data
         // Global variable to store all return data
         var allReturnData = [];
         var allQuotationData = [];
         var allEditOrderData = [];
         var currentQuotationPage = 1;
         var quotationRowsPerPage = 10;
         var filteredQuotationData = [];


         function loadQuotationData(callback) {
             var from    = \$('#quote_from_date').val();
             var to      = \$('#quote_to_date').val();
             
             var orderId = \$('#quote_order_id_search').val().trim().toLowerCase();
             var mobile  = \$('#quote_mobile_search').val().trim().toLowerCase();
             var name    = \$('#quote_name_search').val().trim().toLowerCase();

             \$.ajax({
                 url: 'index.php?route=extension/purpletree_pos/pos/home|getQuotesByDate',
                  beforeSend: function() { showPremiumLoader(); },
                  complete: function() { hidePremiumLoader(); },
                 type: 'GET',
                 dataType: 'json',
                 data: { from_date: from, to_date: to, order_id: orderId, mobile: mobile, name: name  },
                 success: function (res) {
                     if (!res || !res.data || !res.data.length) {
                         \$('#quotationResults').html('<p style=\"color:white; padding:10px;\">No quotations found.</p>');
                         allQuotationData = [];
                         filteredQuotationData = [];
                         return;
                     }

                     allQuotationData = res.data;
                     filteredQuotationData = allQuotationData.filter(function (row) {
                          if (!row || !row.quote_info) return false;
                          var matchId     = orderId === '' || row.quote_info.order_id.toString().toLowerCase().includes(orderId);
                          var matchMobile = mobile  === '' || (row.quote_info.telephone || '').toString().toLowerCase().includes(mobile);
                          var fullName    = ((row.quote_info.firstname || '') + ' ' + (row.quote_info.lastname || '')).toLowerCase();
                          var matchName   = name    === '' || fullName.includes(name);
                          
                          return matchId && matchMobile && matchName;
                      });

                     if (filteredQuotationData.length > 0) {
                         currentQuotationPage = 1; 
                         renderQuotationTable();
                     } else {
                         \$('#quotationResults').html('<p style=\"color:white; padding:10px;\">No results found matching your search criteria.</p>');
                     }

                     if (typeof callback === 'function') {
                         callback();
                     }
                 },
                 error: function (xhr, status, err) {
                     \$('#quotationResults').html('<p style=\"color:red; padding:10px;\">Error loading quotations.</p>');
                     allQuotationData = [];
                     filteredQuotationData = [];
                     if (typeof callback === 'function') {
                         callback();
                     }
                 }
             });
         }

         function renderQuotationTable() {
             var totalPages = Math.ceil(filteredQuotationData.length / quotationRowsPerPage);
             if (currentQuotationPage < 1) currentQuotationPage = 1;
             if (currentQuotationPage > totalPages) currentQuotationPage = totalPages;

             var startIdx = (currentQuotationPage - 1) * quotationRowsPerPage;
             var endIdx   = startIdx + quotationRowsPerPage;
             var pageData = filteredQuotationData.slice(startIdx, endIdx);

              var html = ''
                 + '<style>'
                 + '  #quotationTable { background-color: transparent !important; color: white !important; }'
                 + '  #quotationTable tbody tr { background-color: transparent !important; }'
                 + '  #quotationTable tbody tr:hover { background-color: rgba(255, 255, 255, 0.1) !important; cursor: pointer; }'
                 + '  #quotationTable thead th { background-color: white !important; color: black !important; }'
                 + '</style>'
                 + '<table id=\"quotationTable\" class=\"table table-bordered mt-3\">'
                 + '  <thead>'
                 + '    <tr>'
                 + '      <th style=\"background-color: white !important; color: black !important;\">Sl.No</th>'
                 + '      <th style=\"background-color: white !important; color: black !important;\">Order</th>'
                 + '      <th style=\"background-color: white !important; color: black !important;\">Date</th>'
                 + '      <th style=\"background-color: white !important; color: black !important;\">Customer</th>'
                 + '      <th style=\"background-color: white !important; color: black !important;\">Phone</th>'
                 + '      <th style=\"background-color: white !important; color: black !important;\">Total</th>'
                 + '      <th style=\"background-color: white !important; color: black !important;\">Status</th>'
                 + '      <th style=\"background-color: white !important; color: black !important;\">Action</th>'
                 + '    </tr>'
                 + '  </thead>'
                 + '  <tbody>';

             if (pageData.length === 0) {
                 html += '<tr><td colspan=\"8\" class=\"text-center\" style=\"color:white;\">No data available</td></tr>';
             } else {
                 pageData.forEach(function (row, idx) {
                     var globalIdx = startIdx + idx + 1;
                     var statusId = parseInt(row.quote_info.order_status_id || 0, 10);
                     var statusText = \"Pending\";
                     if (statusId === 7) statusText = \"Cancelled\";
                     else if (statusId === 5) statusText = \"Completed\";
                     else if (statusId === 1) statusText = \"Pending\";

                     var displayId = row.quote_info.order_id || row.quote_info.quote_id || \"-\";
                     var uniqueId = displayId; 

                     var actionBtn = '';
                     if (statusId === 5 ) {
                         actionBtn += '<button class=\"btn btn-danger btn-sm\" disabled style=\"opacity: 0.6; cursor: not-allowed; display: inline;\">Completed</button>';
                     }
                     else if (statusId === 7) {
                         actionBtn += '<button class=\"btn btn-danger btn-sm\" disabled style=\"opacity: 0.6; cursor: not-allowed; display: inline;\">Cancelled</button>';
                     }
                     else {
                         actionBtn += '<button class=\"btn btn-primary btn-sm\" onclick=\"restoreQuotationOrder(\\'' + uniqueId + '\\')\" style=\"margin-right:5px; display: inline;\">Pull Quote</button>';
                         actionBtn += '<button class=\"btn btn-danger btn-sm\" onclick=\"cancelQuotationOrder(\\'' + uniqueId + '\\')\" style=\"display: inline;\"> Cancel</button>';
                     }

                     html += '<tr>' +
                             '<td style=\"color: black;\">' + globalIdx + '</td>' +
                             '<td style=\"color: black;\">' + displayId + '</td>' +
                             '<td style=\"color: black;\">' + row.quote_info.date_added + '</td>' +
                             '<td style=\"color: black;\">' + row.quote_info.firstname + ' ' + row.quote_info.lastname + '</td>' +
                             '<td style=\"color: black;\">' + (row.quote_info.telephone || '-') + '</td>' +
                             '<td style=\"color: black;\">' + row.invoice.sub_total + '</td>' +
                             '<td style=\"color: black;\">' + statusText + '</td>' +
                             '<td>' + actionBtn + '</td>' +
                             '</tr>';
                 });
             }
             
             html += '</tbody></table>';

             if (totalPages > 1) {
                 html += '<div id=\"quotationPager\" style=\"margin-top:-15px; text-align:right; display: flex; justify-content: end; \">'
                      + '  <button type=\"button\" class=\"btn btn-sm btn-secondary me-1\" onclick=\"jumpToQuotationPage(1)\">Start</button>'
                      + '  <button type=\"button\" class=\"btn btn-sm btn-secondary me-1\" onclick=\"changeQuotationPage(-1)\"> < </button>'
                      + '  <button type=\"button\" class=\"btn btn-sm btn-secondary me-1\" onclick=\"changeQuotationPage(1)\"> > </button>'
                      + '  <button type=\"button\" class=\"btn btn-sm btn-secondary\" onclick=\"jumpToQuotationPage(' + totalPages + ')\">End</button>'
                      + '</div>';
             }

             \$('#quotationResults').html(html);
         }

         function jumpToQuotationPage(page) {
             currentQuotationPage = page;
             renderQuotationTable();
         }

         function changeQuotationPage(direction) {
             currentQuotationPage += direction;
             renderQuotationTable();
         }

         function cancelQuotationOrder(orderId) {
             if (!confirm(\"Are you sure you want to delete this quotation order? This action cannot be undone.\")) {
                 return;
             }

             \$.ajax({
                 url: 'index.php?route=extension/purpletree_pos/pos/home|cancelQuoteOrder',
                 type: 'POST',
                 dataType: 'json',
                 data: { order_id: orderId },
                 beforeSend: function() { showPremiumLoader(); },
                 complete: function() { hidePremiumLoader(); },
                 success: function(json) {
                     if (json.success) {
                         successMessage(\"Deleted successfully\", 2000);
                         loadQuotationData(); 
                     } else {
                         errorMessage(json.error || \"Failed to delete order\", 3000);
                     }
                 },
                 error: function(xhr, ajaxOptions, thrownError) {
                      console.error(thrownError + \"\\r\\n\" + xhr.statusText + \"\\r\\n\" + xhr.responseText);
                      errorMessage(\"An error occurred while deleting the order.\", 3000);
                 }
             });
         }

         function fetchQuotationById(orderId, callback) {
             if (!orderId) {
                 if (typeof callback === 'function') callback(null);
                 return;
             }

             \$.ajax({
                 url: 'index.php?route=extension/purpletree_pos/pos/home|getQuotationById',
                 type: 'GET',
                 dataType: 'json',
                 data: {
                     order_id: orderId,
                     agent_id: getAgentId()
                 },
                 beforeSend: function() { showPremiumLoader(); },
                 complete: function() { hidePremiumLoader(); },
                 success: function(res) {
                     if (res && res.data) {
                         if (typeof callback === 'function') callback(res.data);
                     } else {
                         if (typeof callback === 'function') callback(null);
                     }
                 },
                 error: function() {
                     if (typeof callback === 'function') callback(null);
                 }
             });
         }

         function searchAndRestoreQuotation(orderId) {
             if (!orderId || !orderId.toString().trim()) {
                 errorMessage(\"Please enter a quotation ID.\", 2000);
                 return;
             }

             fetchQuotationById(orderId, function(orderData) {
                 if (orderData) {
                     restoreQuotationOrder(orderId, orderData);
                     return;
                 }

                 // Fallback to the existing list-based approach
                 if (!allQuotationData || !allQuotationData.length) {
                     // If date filters are empty, default to today so API returns something
                     var today = new Date().toISOString().split('T')[0];
                     if (!\$('#quote_from_date').val()) \$('#quote_from_date').val(today);
                     if (!\$('#quote_to_date').val()) \$('#quote_to_date').val(today);

                     \$('#quote_order_id_search').val(orderId);
                     loadQuotationData(function() {
                         restoreQuotationOrder(orderId);
                     });
                     return;
                 }

                 restoreQuotationOrder(orderId);
             });
         }

         function restoreQuotationOrder(orderId, selectedOrder) {
             console.log(\"Restoring Quotation ID:\", orderId);
             var searchId = (orderId || '').toString().trim();

             if (!selectedOrder) {
                 selectedOrder = allQuotationData.find(function (row) {
                     if (!row || !row.quote_info) return false;
                     var orderIdValue = (row.quote_info.order_id || row.quote_info.quote_id || '').toString().trim();
                     return orderIdValue === searchId;
                 });
             }

             if (!selectedOrder) {
                 errorMessage(\"Quotation not found.\", 2000);
                 return;
             }

             // Set active quotation flag
             sessionStorage.setItem('currentQuotationOrder', JSON.stringify(selectedOrder));
             sessionStorage.removeItem('currentReturnOrder'); // Clear return mode if active

             var orderProducts = selectedOrder.products || [];
             var cartProducts = [];
             orderProducts.forEach(function (p, index) {
                 // Attempt to preserve GST percent from server data if available
                 var gstPercent = parseFloat(p.gst_percent || p.tax_percent || 0) || 0;
                 if (!gstPercent && Array.isArray(p.proTax)) {
                     p.proTax.forEach(function(t){ if ((t.name||'').toLowerCase().includes('gst')) gstPercent += parseFloat(t.rate)||0; });
                 }

                 cartProducts.push({
                     product_id : p.product_id,
                     quantity   : parseInt(p.quantity) || 1,
                     price      : parseFloat(p.price) || 0,
                     name       : p.name,
                     reward     : p.reward || 0,
                     excluded   : (p.excluded == 1 || String(p.excluded).toLowerCase() === 'true') ? 1 : 0,
                     gst_percent: parseFloat(p.gst_percent || p.gst || 0) || 0
                 });
             });

             localStorage.setItem(\"pos_cart\", JSON.stringify(cartProducts));

             // Refresh UI
             var cartArea = document.getElementById('cartArea');
             if (cartArea) cartArea.innerHTML = '';
             cartProducts.forEach(function (p) {
                 addProductRowToCartArea(p);
             });

             updateCartTotals();
             updateInvoiceRightColumn();

             \$('#quotationHistoryContent').hide();
             \$('#cartArea').show();
             \$('.cart-header-row').show();
             \$('.discount-row').show();
             \$('.search-section').show();

             successMessage(\"Quotation \" + orderId + \" pulled successfully.\", 3000);
         }

                  // Load return data (multi-field enhanced)
          function loadReturnData() {
              var from    = \$('#invoice_from_date').val();
              var to      = \$('#invoice_to_date').val();
              
              var orderId = \$('#return_order_id').val().trim().toLowerCase();
              var mobile  = \$('#return_mobile_search').val().trim().toLowerCase();
              var name    = \$('#return_name_search').val().trim().toLowerCase();
          
              \$.ajax({
                  url: 'index.php?route=extension/purpletree_pos/pos/home|getOrdersbyDate',
                   beforeSend: function() { showPremiumLoader(); },
                   complete: function() { hidePremiumLoader(); },
                  type: 'GET',
                  dataType: 'json',
                  data: { from_date: from, to_date: to, order_id: orderId, mobile: mobile, name: name },
                  success: function (res) {
                      if (!res || !res.data || !res.data.length) {
                          \$('#returnResults').html('<p style=\"color:white; padding:10px;\">No invoices found.</p>');
                          allReturnData = [];
                          return;
                      }
          
                      allReturnData = res.data;
                      
                      var filteredData = allReturnData.filter(function (row) {
                          var matchId     = orderId === '' || row.order_info.order_id.toString().toLowerCase().includes(orderId);
                          var matchMobile = mobile  === '' || (row.order_info.telephone || '').toString().toLowerCase().includes(mobile);
                          var fullName    = ((row.order_info.firstname || '') + ' ' + (row.order_info.lastname || '')).toLowerCase();
                          var matchName   = name    === '' || fullName.includes(name);
                          
                          return matchId && matchMobile && matchName;
                      });
          
                      if (filteredData.length > 0) {
                          displayReturnTable(filteredData);
                      } else {
                          \$('#returnResults').html('<p style=\"color:white; padding:10px;\">No results found matching your search criteria.</p>');
                      }
                  },
                  error: function (xhr, status, err) {
                      \$('#returnResults').html('<p style=\"color:red; padding:10px;\">Error loading invoices.</p>');
                      allReturnData = [];
                  }
              });
          }
function restoreReturnOrder(orderId) {
             //console.log(\"=== RETURN ORDER CLICKED ===\");
             //console.log(\"Order ID:\", orderId);
         
             var selectedOrder = allReturnData.find(function (row) {
                 return row &&
                        row.order_info &&
                        row.order_info.order_id != null &&
                        row.order_info.order_id.toString() === orderId.toString();
             });
         
             //console.log(\"Selected Order FULL DATA:\", selectedOrder);
         
             if (!selectedOrder) {
                 console.error(\"Order not found for return.\");
                 if (typeof errorMessage === \"function\") {
                     errorMessage(\"Order not found.\", 2000);
                 }
                 return;
             }
         
             sessionStorage.setItem('currentReturnOrder', JSON.stringify(selectedOrder));
             //console.log(\"✅ Stored in sessionStorage:\", selectedOrder);
         
             var orderProducts = selectedOrder.products || [];
             console.log(\"Products from API:\", orderProducts);
         
             if (!orderProducts.length) {
                 console.warn(\"No products array on selectedOrder; cannot build cart.\");
                 return;
             }
         
             var cartProducts = [];
             orderProducts.forEach(function (p, index) {
                 var qty   = parseInt(p.quantity || 1, 10);
                 var price = parseFloat(p.price || (p.total ? p.total / qty : 0));
         
                 var cartItem = {
                     cartid      : 'return_' + orderId + '_' + (p.product_id || p.order_product_id || index),
                     customerid  : 0,
                     product_id   : p.product_id,
                     recurringid : 0,
                     option      : [],
                     quantity    : qty,
                     price       : price,
                     name        : p.name,
                     reward     : p.reward,
                     excluded   : p.excluded,
                     gst_percent: parseFloat(p.gst_percent || p.gst || 0) || 0
                 };
                 cartProducts.push(cartItem);
             });
         
             var posCartForGrid = cartProducts.map(function (item) {
                 return {
                     product_id : item.product_id,
                     quantity   : item.quantity,
                     price      : item.price,
                     name       : item.name,
                     reward     : item.reward,
                     excluded   : item.excluded,
                     gst_percent: parseFloat(item.gst_percent || item.gst || 0) || 0

                 };
             });
             localStorage.setItem(\"pos_cart\", JSON.stringify(posCartForGrid));
         
             var cartArea = document.getElementById('cartArea');
             if (cartArea) {
                 cartArea.innerHTML = '';
             }
         
             posCartForGrid.forEach(function (p) {
                 var productForUI = {
                     product_id : p.product_id,
                     quantity   : p.quantity,
                     price      : p.price,
                     name       : p.name,
                     reward     : p.reward,
                     excluded   : p.excluded,
                     gst_percent: parseFloat(p.gst_percent || p.gst || 0) || 0

                 };
                 console.log(\"productForUI.........\",productForUI);
                 addProductRowToCartArea(productForUI);
             });

             window.alreadyPaidAmount = 0;
             if (selectedOrder && selectedOrder.invoice && selectedOrder.invoice.total_received) {
                 window.alreadyPaidAmount = parseFloat(selectedOrder.invoice.total_received) || 0;
             }

             // now safe to call cart/price functions that use allProducts.find(...)
             if (typeof updateCartTotals === \"function\") {
                 updateCartTotals();
             }
             if (typeof updateInvoiceRightColumn === \"function\") {
                 updateInvoiceRightColumn();
             }
             if (typeof updateTaxDisplay === \"function\") {
                 updateTaxDisplay();
             }
             if (typeof setOrderItems === \"function\") {
                 setOrderItems();
             }
         
             \$('#returnContent').hide();
             \$('#invoiceContent').hide();
             \$('#cancelOrderContent').hide();
             \$('#cartArea').show();
             \$('.cart-header-row').show();
             \$('.discount-row').show();
             \$('.search-section').show();
         
             if (typeof successMessage === \"function\") {
                 successMessage(\"Order \" + orderId + \" loaded for return. You can now remove/add items.\", 3000);
             }
         
                ////console.log(\"✅ Return cart ready. Products rendered into cartArea.\");
         
             // === NEW: auto-check Save Returnable as Advance ONLY for return orders with returnable amount ===
             
                 
             
             
         }
         
         
         
         
         // Table renderer with button → restoreReturnOrder
         function displayReturnTable(data) {
             ////console.log(\"Rendering table with data:\", data);
         
             var html = ''
                 + '<table id=\"returnTable\" class=\"table table-bordered table-dark mt-3\">'
                 + '  <thead>'
                 + '    <tr>'
                 + '      <th style=\"background-color: white;color: black;\">Sl.No</th>'
                 + '      <th style=\"background-color: white;color: black;\">Order</th>'
                 + '      <th style=\"background-color: white;color: black;\">Date</th>'
                 + '      <th style=\"background-color: white;color: black;\">Mobile</th>'
                 + '      <th style=\"background-color: white;color: black;\">Subtotal</th>'
                 + '      <th style=\"background-color: white;color: black;\">Tax</th>'
                 + '      <th style=\"background-color: white;color: black;\">Received</th>'
                 + '      <th style=\"background-color: white;color: black;\">PaymentMethod</th>'
                 + '      <th style=\"background-color: white;color: black;\">SellerId</th>'
                 + '      <th style=\"background-color: white;color: black;\">Change</th>'
                 + '      <th style=\"background-color: white;color: black;\">Status</th>'
                 + '      <th style=\"background-color: white;color: black;\">Pre Order</th>'
                 + '      <th style=\"background-color: white;color: black;\">Action</th>'
                 + '    </tr>'
                 + '  </thead>'
                 + '  <tbody>';
         
             data.forEach(function (row, idx) {
                 let paymentHTML = \"\";
                 let methods = (row.invoice.amount_through || \"\").split(',');
         
                 methods.forEach(function (m) {
                     m = m.trim().toUpperCase();
                     if (m === \"CASH\") paymentHTML += 'CASH: ₹ ' + row.invoice.cash_amount + ' ';
                     if (m === \"UPI\")  paymentHTML += '| UPI: ₹ ' + row.invoice.upi_amount + ' ';
                     if (m === \"CARD\") paymentHTML += '| CARD: ₹ ' + (row.invoice.card_amount || '0.00') + ' ';
                 });
         
                 // --- NEW: decide button text + disabled based on status id 4 or 6 ---
                 var statusId = parseInt(row.order_info.order_status_id || row.order_info.order_status || 0, 10);
                 var isReturned = (statusId === 4 || statusId === 6);
                 var btnLabel = isReturned ? 'Returned' : 'Return';
                 var btnDisabledAttr = isReturned ? ' disabled' : '';
                 // --------------------------------------------------------------------
         
                 html += ''
                     + '<tr class=\"return-row\" data-order-id=\"' + row.order_info.order_id + '\">'
                     + '  <td style=\"background-color: white;color: black;\">' + (idx + 1) + '</td>'
                     + '  <td style=\"background-color: white;color: black;\">' + row.order_info.order_id + '</td>'
                     + '  <td style=\"background-color: white;color: black;\">' + row.order_info.date_added + '</td>'
                     + '  <td style=\"background-color: white;color: black;\">' + row.order_info.telephone + '</td>'
                     + '  <td style=\"background-color: white;color: black;\">' + row.invoice.sub_total + '</td>'
                     + '  <td style=\"background-color: white;color: black;\">' + row.invoice.total_tax + '</td>'
                     + '  <td style=\"background-color: white;color: black;\">' + row.invoice.total_received + '</td>'
                     + '  <td style=\"background-color: white;color: black;\">' + paymentHTML + '</td>'
                     + '  <td style=\"background-color: white;color: black;\">' + row.order_info.sellerId + '</td>'
                     + '  <td style=\"background-color: white;color: black;\">' + (row.invoice.returnable_balance || '0') + '</td>'
                     + '  <td style=\"background-color: white;color: black;\">' + (row.order_info.order_status || 'null') + '</td>'
                     + '  <td style=\"background-color: white;color: black;\">' + (row.order_info.pre_order_id || 'null') + '</td>'
                     + '  <td style=\"background-color: white;color: black;\">'
                     + '      <button class=\"btn btn-warning btn-sm return-order-btn\" data-order-id=\"' + row.order_info.order_id + '\"' + btnDisabledAttr + '>'
                     +            btnLabel
                     + '      </button>'
                     + '  </td>'
                     + '</tr>';
             });
         
             html += '  </tbody></table>';
             html += '<div id=\"invoicePager\" '
                  + '     style=\"margin-top:-15px; text-align:right; display: flex; justify-content: end;\">'
                  + '  <button type=\"button\" id=\"invFirst\" class=\"btn btn-sm btn-secondary me-1\">Start</button>'
                  + '  <button type=\"button\" id=\"invPrev\"  class=\"btn btn-sm btn-secondary me-1\"> < </button>'
                  + '  <button type=\"button\" id=\"invNext\"  class=\"btn btn-sm btn-secondary me-1\"> > </button>'
                  + '  <button type=\"button\" id=\"invLast\"  class=\"btn btn-sm btn-secondary\">End</button>'
                  + '</div>';
         
             \$('#returnResults').html(html);
         
             // pagination and click handler stay unchanged
             var \$rows      = \$('#returnTable tbody tr');
             var perPage    = 10;
             var pageCount  = Math.ceil(\$rows.length / perPage);
             var current    = 1;
         
             function renderPage(page) {
                 if (page < 1) page = 1;
                 if (page > pageCount) page = pageCount;
                 current = page;
         
                 \$rows.hide();
                 var start = (page - 1) * perPage;
                 var end   = start + perPage;
                 \$rows.slice(start, end).show();
             }
         
             renderPage(1);
         
             \$('#invFirst').off('click').on('click', function () { renderPage(1); });
             \$('#invPrev').off('click').on('click', function () { renderPage(current - 1); });
             \$('#invNext').off('click').on('click', function () { renderPage(current + 1); });
             \$('#invLast').off('click').on('click', function () { renderPage(pageCount); });
         
             \$(document).off('click', '.return-order-btn').on('click', '.return-order-btn', function (e) {
                 e.preventDefault();
                 e.stopPropagation();
                 if (this.disabled) return; // extra safety
                 var orderId = \$(this).data('order-id');
                 restoreReturnOrder(orderId);
                 var saveBtn = document.getElementById('saveSaleBtn');
             saveBtn.style.pointerEvents = 'none';
             saveBtn.style.opacity = '0.5';
             saveBtn.innerHTML = 'Return Processing...';
             saveBtn.onclick = null;  // Remove onclick completely
             });
 
        }

