         // ---------------------------------------------------------
         // Toggle Wallet Amount Visibility
         // ---------------------------------------------------------
         function toggleWalletAmount() {
             var walletAmount = document.getElementById('walletAmount');
             var walletIcon = document.getElementById('walletIcon');
             var toggleBtn = document.getElementById('toggleWalletBtn');
             
             if (walletAmount.style.display === 'none') {
                 // Show the icon and amount
                 walletIcon.style.display = 'inline';
                 walletAmount.style.display = 'inline';
                 toggleBtn.textContent = 'Hide';
             } else {
                 // Hide the icon and amount
                 walletIcon.style.display = 'none';
                 walletAmount.style.display = 'none';
                 toggleBtn.textContent = 'Wallet Amount';
             }
         }
         
         // ---------------------------------------------------------
         // Check and Update Pay Button State
         // ---------------------------------------------------------
          function checkAndUpdatePayButtonState() {
              var cartArea = document.getElementById('cartArea');
              var cartRows = cartArea ? cartArea.querySelectorAll('.cart-row') : [];
              var isPayDisabled = false;
              var isSaveDisabled = (cartRows.length === 0);

              if (cartRows.length === 0) {
                  isPayDisabled = true;
              } else if (cartRows.length === 1) {
                  // Pay-specific: Disable if only one item and it is excluded
                  if (cartRows[0].classList.contains('excluded-row')) {
                      isPayDisabled = true;
                  }
              }
              
              // Apply Pay Button State
              if (isPayDisabled) {
                  \$('#submit-order-btn').addClass('disabled').css({
                      'pointer-events': 'none'
                  });
              } else {
                  \$('#submit-order-btn').removeClass('disabled').css({
                      'pointer-events': 'auto'
                  });
              }

              // Apply Save Sale Button State
              var saveBtn = document.getElementById('saveSaleBtn');
              var quoteBtn = document.getElementById('sendQuotationBtn');
              var printBtn = document.getElementById('printCartBtn');

              if (saveBtn) {
                  // Safety: Avoid interference during 'Return Processing' flow
                  if (!saveBtn.innerHTML.includes('Return Processing')) {
                      if (isSaveDisabled) {
                          \$(saveBtn).addClass('disabled').css({
                              'pointer-events': 'none',
                              'opacity': '0.5'
                          });
                      } else {
                          \$(saveBtn).removeClass('disabled').css({
                              'pointer-events': 'auto',
                              'opacity': '1'
                          });
                      }
                   }
               }

               // Apply Send Quotation Button State
               if (quoteBtn) {
                   var isReturnMode = !!sessionStorage.getItem('currentReturnOrder');
                   
                   if (isSaveDisabled || isReturnMode) {
                       \$(quoteBtn).addClass('disabled').css({
                           'pointer-events': 'none',
                           'opacity': '0.5'
                       });
                       if (printBtn) {
                           \$(printBtn).addClass('disabled').css({
                               'pointer-events': 'none',
                               'opacity': '0.5'
                           });
                       }
                   } else {
                       \$(quoteBtn).removeClass('disabled').css({
                           'pointer-events': 'auto',
                           'opacity': '1'
                       });
                       if (printBtn) {
                           \$(printBtn).removeClass('disabled').css({
                               'pointer-events': 'auto',
                               'opacity': '1'
                           });
                       }
                   }
               }

               // Action Grid Button: Quotations
               var historyBtn = document.getElementById('quotationHistoryBtn');
               if (historyBtn) {
                   \$(historyBtn).removeClass('disabled').css('opacity', '1');
               }
           }

          // ---------------------------------------------------------
          // Quotation Functionality
          // ---------------------------------------------------------
          function openQuotationModal() {
              var name = '';
              var phone = '';
              
              var currentQuotationOrder = sessionStorage.getItem('currentQuotationOrder');
              if (currentQuotationOrder) {
                  try {
                      var q = JSON.parse(currentQuotationOrder);
                      if (q && q.quote_info) {
                          name = (q.quote_info.firstname || '') + ' ' + (q.quote_info.lastname || '');
                          phone = q.quote_info.telephone || '';
                      }
                  } catch (e) {
                      console.error(\"Error parsing quotation for modal population:\", e);
                  }
              }
              
              if (!name || !phone) {
                  var currentEditOrder = sessionStorage.getItem('currentEditOrder');
                  if (currentEditOrder) {
                      try {
                          var eOrder = JSON.parse(currentEditOrder);
                          if (eOrder && eOrder.order_info) {
                              name = ((eOrder.order_info.firstname || '') + ' ' + (eOrder.order_info.lastname || '')).trim();
                              phone = eOrder.order_info.telephone || '';
                          }
                      } catch (e) {}
                  }
              }

              \$('#quote_customer_name').val(name.trim());
              \$('#quote_customer_phone').val(phone.trim());
              \$('#quote_name_error').hide();
              \$('#quote_phone_error').hide();
              \$('#quotationModal').modal('show');
          }

