              const gstPercent = \$('#gst_percentage_val').val().trim();
              const taxPercent = \$('#gst_tax_percentage').val().trim();

              if (!fromDate || !toDate || !gstPercent || !taxPercent) {
                  alert('Please fill all fields.');
                  return;
              }

              const url = 'index.php?route=extension/purpletree_pos/pos/home|gstCalculation'
                  + '&from_date=' + encodeURIComponent(fromDate)
                  + '&to_date=' + encodeURIComponent(toDate)
                  + '&gst_percentage=' + encodeURIComponent(gstPercent)
                  + '&tax_percentage=' + encodeURIComponent(taxPercent);

              window.open(url, '_blank');
              \$('#gstCalculationModal').modal('show'); // Keep it open or hide it? I'll hide it for consistency.
              \$('#gstCalculationModal').modal('hide');
          }
          
