           function submitTradeAdjustment() {
               const amount = \$('#trade_adj_amount').val();
               const type = \$('input[name=\"trade_type\"]:checked').val();
               const desc = \$('#trade_adj_description').val();
               
               if(!amount || amount <= 0) {
                   alert(\"Please enter a valid amount.\");
                   return;
               }

               \$.ajax({
                   url: 'index.php?route=extension/purpletree_pos/pos/home|adjustTrade',
                   type: 'POST',
                   data: {
                       customer_id: currentWalletCustomerId,
                       amount: amount,
                       type: type,
                       wallet_type: 'aeps',
                       description: desc
                   },
                   dataType: 'json',
                   beforeSend: function() { \$('#submitTradeAdjBtn').attr('disabled', true).text('Processing...'); },
                   success: function(res) {
                       if(res && res.status === 'success') {
                           \$('#tradeAdjustmentModal').modal('hide');
                           loadWalletData(\$('#wallet_phone_search').val()); 
                       } else {
                           alert(res.message || \"Adjustment failed.\");
                       }
                   },
                   complete: function() { \$('#submitTradeAdjBtn').attr('disabled', false).text('Submit Adjustment'); },
                   error: function() { alert(\"An error occurred while processing the request.\"); }
               });
           }

           function submitDueAdjustment() {
               const amount = \$('#due_adj_amount').val();
               const type = \$('input[name=\"due_type\"]:checked').val();
               const desc = \$('#due_adj_description').val();
               
               if(!amount || amount <= 0) {
                   alert(\"Please enter a valid amount.\");
                   return;
