               \$.ajax({
                   url: 'index.php?route=extension/purpletree_pos/pos/home|adjustDue',
                   type: 'POST',
                   data: {
                       customer_id: currentWalletCustomerId,
                       amount: amount,
                       type: type,
                       wallet_type: 'main',
                       description: desc
                   },
                   dataType: 'json',
                   beforeSend: function() { \$('#submitDueAdjBtn').attr('disabled', true).text('Processing...'); },
                   success: function(res) {
                       if(res && res.status === 'success') {
                           \$('#dueAdjustmentModal').modal('hide');
                           loadWalletData(\$('#wallet_phone_search').val()); 
                       } else {
                           alert(res.message || \"Adjustment failed.\");
                       }
                   },
                   complete: function() { \$('#submitDueAdjBtn').attr('disabled', false).text('Submit Adjustment'); },
                   error: function() { alert(\"An error occurred while processing the request.\"); }
               });
