         function handleCouponInvoice() {
             const couponInput = document.getElementById('couponCodeInvoice');
             const couponBtn = document.getElementById('couponBtnInvoice');
             const creditLimitCheckbox = document.getElementById('creditLimitInvoice');
             
             const couponCode = couponInput.value.trim();
             
             if (couponBtn.textContent === 'Apply') {
                 if (couponCode) {
                     // Disable button to prevent multiple clicks
                     couponBtn.disabled = true;
                     couponBtn.textContent = 'Applying...';
                     let grandTotal = 0;
         const gtEl = document.getElementById('grandTotal');
         
         if (gtEl && gtEl.value) {
             grandTotal = parseFloat(
                 gtEl.value.replace(/[^0-9.-]/g, '')
             ) || 0;
         }
         
                     
                     \$.ajax({
                         url: 'index.php?route=extension/purpletree_pos/pos/home|applycoupon',
                         type: 'POST',
                         dataType: 'json',
                         data: { coupon: couponCode,grand_total: grandTotal },
                         success: function(response) {
                             couponBtn.disabled = false;
                             couponBtn.textContent = 'Apply';
                             
                             //console.log('Coupon Response:', response);
                             
                             if (response.success && response.coupon_info) {
         
                                 const couponInfo      = response.coupon_info;
                                 const grandTotalField = document.getElementById('grandTotal');
                                 const grandTotal      = parseFloat(grandTotalField.value.replace(/[^0-9.]/g, '')) || 0;
                                 const minAmount       = parseFloat(couponInfo.minimum_total) || 0;
                             
                                 if (grandTotal >= minAmount) {
                                     applyCouponDiscount(couponInfo, couponCode);
                                     // message is now handled inside applyCouponDiscount
                                 } else {
                                     const formattedMin   = minAmount.toFixed(2);
                                     const formattedGrand = grandTotal.toFixed(2);
                             
                                     showCouponMessage(
                                         `This coupon requires a minimum bill of ₹ \${formattedMin}. Your total is ₹ \${formattedGrand}.`,
                                         'error'
                                     );
                                 }
                             
                             } else if (response.error) {
                                 showCouponMessage(response.error, 'error');
                             } else {
                                 showCouponMessage('Invalid or expired coupon code', 'error');
                             }
                             
         
                         },
                         error: function(xhr, status, error) {
                             couponBtn.disabled = false;
                             couponBtn.textContent = 'Apply';
                             console.error('Coupon AJAX Error:', error);
                             console.error('Response:', xhr.responseText);
                             showCouponMessage('Error validating coupon. Please try again.', 'error');
                         }
                     });
                 } else {
                     showCouponMessage('Please enter a coupon code', 'error');
                 }
             } else {
                 // Remove coupon
                 removeCoupon();
             }
         }
         
        function applyCouponDiscount(coupon, couponCode) {
            const couponInput = document.getElementById('couponCodeInvoice');
            const couponBtn   = document.getElementById('couponBtnInvoice');
        
            // PROFESSIONAL FIX: Always use grandTotalAmount as base to avoid double-adding DA
            let grandTotal = grandTotalAmount || 0;

         
             if (!sessionStorage.getItem('originalGrandTotal')) {
                 sessionStorage.setItem('originalGrandTotal', grandTotal.toFixed(2));
             }
         
             let discount = 0;
         
             if (coupon.type === 'P') {
                 discount = (grandTotal * parseFloat(coupon.discount)) / 100;
             } else if (coupon.type === 'F') {
                 discount = parseFloat(coupon.discount);
             }
         
             // 2️⃣ HARD CAP by coupon.total
             const maxAllowed = parseFloat(coupon.total) || 0;
             if (maxAllowed > 0) {
                 discount = Math.min(discount, maxAllowed);
             }
         
             // 3️⃣ Also never exceed bill amount
             discount = Math.min(discount, grandTotal);
         
             const newGrandTotal = Math.max(grandTotal - discount, 0);
         
             // Update UI
             document.getElementById('grandTotal').value =
                 format(newGrandTotal, posData.currency_code);
         
             grandTotalAmount = newGrandTotal;
         
             sessionStorage.setItem('couponApplied', JSON.stringify({
                 coupon_id: coupon.coupon_id,
                 code: couponCode,
                 discount: discount,
                 type: coupon.type,
                 max_limit: maxAllowed,
                 originalTotal: grandTotal
             }));
         
             couponBtn.textContent = 'Remove';
             couponBtn.classList.add('remove');
             couponInput.disabled = true;
         
             updateTotalsWithCoupon(discount, couponCode);
             updateTotals();
         
             showCouponMessage(
                 `Coupon applied. You saved ₹ \${discount.toFixed(2)}`,
                 'success'
             );
         }
         
         
         function showCouponMessage(msg, type = 'error') {
             const box = document.getElementById('couponMessage');
             if (!box) return;
         
             box.textContent = msg;
             box.style.color = type === 'error' ? 'red' : 'green';
         
             // Keep success text visible; auto-clear only errors
             if (type === 'error') {
                 setTimeout(() => { 
                     box.textContent = ''; 
                 }, 3000);
             }
         }
         
         
         
