         function handleImmediateInput(inputElement) {
             const currentValue = inputElement.value.trim();
             let code = currentValue.length;
             
             // ✅ FIXED LOGIC: First try 8-digit SKU, then 15-digit UPC
             if (currentValue.length === 8) {
                 findProductBySKU(currentValue).then(function(product) {
                     if (product) {
                         // Success feedback
                         inputElement.classList.remove('error');
                         inputElement.classList.add('success');
                         setTimeout(() => inputElement.classList.remove('success'), 2000);
         
                         inputElement.value = '';
                         allProductsCount.push(product);
                         localStorage.setItem(\"allProductsCount\", JSON.stringify(allProductsCount));
                         addProductToCart(product);
                         console.log(\"Handle Immediate input 8\");
                     } else {
                         // Error feedback
                         inputElement.classList.remove('success');
                         inputElement.classList.add('error');
                         setTimeout(() => inputElement.classList.remove('error'), 2000);
                     }
                 });
                 return;
             }
             
             // ✅ 15-digit UPC processing
             else if (currentValue.length === 15) {
                 inputElement.value = '';
                 findProductBySKU(currentValue).then(function(product) {
                     if (product) {
                         // Success feedback
                         inputElement.classList.remove('error');
                         inputElement.classList.add('success');
                         setTimeout(() => inputElement.classList.remove('success'), 2000);
         
                         allProductsCount.push(product);
                         localStorage.setItem(\"allProductsCount\", JSON.stringify(allProductsCount));
                         addProductToCart(product);
                         console.log(\"Handle Immediate input 15\");

                     } else {
                         // Error feedback
                         inputElement.classList.remove('success');
                         inputElement.classList.add('error');
                         setTimeout(() => inputElement.classList.remove('error'), 2000);
                         showErrorFeedback('Product not found: ' + currentValue);
                     }
                 });
                 return;
             }
         }
         
         
         
         
         /**
          * Handles PASTE event specifically
          */
         // PASTE: matches onpaste=\"handlePasteEvent(event, this)\"
         function handlePasteEvent(event, inputElement) {
             const pastedText = (event.clipboardData || window.clipboardData)
                 .getData('text')
                 .trim();
         
             if (pastedText.length >= 6) {
                 event.preventDefault();
                 inputElement.value = pastedText;
                 setTimeout(function () {
                     findProductBySKU(pastedText).then(function (product) {
                         if (product) {
                             // Success feedback
                             inputElement.classList.remove('error');
                             inputElement.classList.add('success');
                             setTimeout(() => inputElement.classList.remove('success'), 2000);
         
                             allProductsCount.push(product);
                             localStorage.setItem(\"allProductsCount\",JSON.stringify(allProductsCount));
                             addProductToCart(product);
                            console.log(\"handlePasteEvent\");

                             inputElement.value = '';
                         } else {
                             // Error feedback
                             inputElement.classList.remove('success');
                             inputElement.classList.add('error');
                             setTimeout(() => inputElement.classList.remove('error'), 2000);
                             showErrorFeedback('Product not found: ' + pastedText);
                         }
                     });
                 }, 50);
             }
         }
         
       
         function handleSearchKeypress(event, inputElement) {
             if (event.which === 13 || event.keyCode === 13) {
                 event.preventDefault();
                 
                 const skuCode = inputElement.value.trim();
                 //console.log('ENTER KEY PRESSED:', skuCode);
                 
                 if (skuCode.length >= 6) {
                     // Try exact SKU match first
                     const product = findProductBySKU(skuCode);
                     
                     if (product) {
                         //console.log('Product found by SKU');
                         console.log(\"handleSearchKeypress\");
                         addProductToCart(product);
                         inputElement.value = '';
                     } else {
                         // If no exact match, perform regular search
                         //console.log('No exact SKU match, performing search');
                         performSearch();
                     }
                 } else if (skuCode.length > 0) {
                     // Short input - do regular search
                     performSearch();
                 }
             }
         }
         
         
         function findProductBySKU(sku) {
             if (!sku) return Promise.resolve(null);
         
             const url =
                 'index.php?route=extension/purpletree_pos/pos/home|getProductBySku&sku=' +
                 encodeURIComponent(sku);
         
             return new Promise(function (resolve) {
                 \$.ajax({
                     url: url,
                     type: 'get',
                     dataType: 'json',
                     success: function (products) {
                         if (products.length === 1) {
                             
                              
                             resolve(products[0]);
                             
                         } else if (products.length > 1)
                         {
                             
                             displaySearchResults(products);
                         }
                         else{
                             resolve(null);
                         }
                     },
                     error: function () {
                         resolve(null);
                     }
                 });
             });
         }
         
         
         function addProductToCart(product) {
             if (!product) {
                 console.error('Invalid product');
                 return false;
             }
             
                const productQuantity = (product && product.pos_quantity != null) ? parseInt(product.pos_quantity, 10) : null;
                console.log(\"quantity\", productQuantity);
                if (productQuantity === null) {
                console.log(\"product data not ready yet — skipping add-to-cart\");
                return; // skip until product data is loaded
                }
                if (productQuantity <= 0) {
                showErrorFeedback(\"Product is OUT OF STOCK\");
                return false; // EXIT FUNCTION - do not add to cart
                }
             
          
             getCartProductHTML();
         
             // Check if product has options
             if (product.options && product.options.length > 0) {
                 //console.log('Product has options, opening product modal');
                 
                 // Open product options modal
                 if (typeof productdata === 'function') {
                     const mockElement = {
                         attributes: {
                             dataproduct: { value: product.product_id }
                         }
                     };
                     productdata(mockElement);
                 }
                 
                 return true;
             }
             
             // Add product to backend cart
             if (typeof addToCartProducts === 'function') {
                 addToCartProducts(product);
             }
             
             // Add product row to cart UI
             addProductRowToCartArea(product);
             
             // Highlight if the row already existed (quantity increased via barcode)
             const row = document.querySelector('.cart-row[data-product-id=\"' + product.product_id + '\"]');
             if (row) {
                 applyRowHighlight(row);
             }
             
             // Clear search input after item added
             \$('#pos_search').val('');
             
             // Update totals
             updateCartTotals();
             
             // Refresh cart display
             if (typeof getCartProductHTML === 'function') {
                 getCartProductHTML();
             }
             
             // Show success feedback
             showSuccessFeedback(product.name || product.heading_title || 'Product');
             
             return true;
         }
         
         
