         // ✅ Put this AFTER your HTML modal
         
         function editCartProduct(cartId, productId) {
             if (!EDITABLE_PRODUCT_IDS.includes(parseInt(productId))) {
                 return;
             }
         
             let productToEdit = null;
             
             // Fallback chain for product data
             // 1) Try posData.products
             if (typeof posData !== 'undefined' && posData && posData.products) {
                 if (posData.products[productId]) {
                     productToEdit = posData.products[productId];
                 } else {
                     Object.keys(posData.products).forEach(function (key) {
                         const p = posData.products[key];
                         if (!productToEdit && (p.productid == productId || p.product_id == productId)) {
                             productToEdit = p;
                         }
                     });
                 }
             }
         
             // 2) Try allProductsCount from localStorage
             if (!productToEdit) {
                 let allProductsCount = JSON.parse(localStorage.getItem(\"allProductsCount\") || \"[]\");
                 productToEdit = allProductsCount.find(p => p.product_id == productId || p.productid == productId);
             }
         
             // 3) Try allProducts global
             if (!productToEdit && typeof allProducts !== 'undefined' && allProducts) {
                 productToEdit = allProducts.find(p => p.product_id == productId || p.productid == productId);
             }
         
             if (!productToEdit) {
                 console.error('Product ' + productId + ' not found');
                 return;
             }
         
             // fill popup inputs
             const modalEl = document.getElementById('editProduct154Modal');
             modalEl.setAttribute('data-product-id', productId);
             
             // Update modal title
             const modalTitle = modalEl.querySelector('.modal-title');
             if (modalTitle) {
                 modalTitle.textContent = '✏️ Edit Product ' + productId;
             }
         
             document.getElementById('prod154_name').value  = productToEdit.heading_title || productToEdit.name || '';
             document.getElementById('prod154_price').value = productToEdit.price || 0;
         
             // open modal
             const modal = new bootstrap.Modal(document.getElementById('editProduct154Modal'));
             modal.show();
         }
         
         // ============================================
