         var lastSearchResults = [];
         
         function displaySearchResults(products) {
             lastSearchResults = products; // store API results
             const popupBody = document.getElementById('searchPopupBody');
             
             if (products.length === 0) {
                 popupBody.innerHTML = '<div class=\"no-results-message\"><div class=\"no-results-icon\">❌</div><div class=\"no-results-text\">No Products Found</div><div class=\"no-results-subtext\">Try searching with a different term</div></div>';
             } else {
                 let html = '<div class=\"search-results-table\"><div class=\"search-results-header\"><div class=\"search-header-cell\" style=\"flex: 2;\">PRODUCT NAME</div><div class=\"search-header-cell\" style=\"flex: 1;\">MODEL</div><div class=\"search-header-cell\" style=\"flex: 1;\">PRICE</div><div class=\"search-header-cell\" style=\"flex: 1;\">QUANTITY</div><div class=\"search-header-cell\" style=\"flex: 1;\">ACTION</div></div><div class=\"search-results-body\">';
                 
                 products.forEach(function(product) {
                     const productId = product.product_id || product.productid || 'N/A';
                     const productName = product.name || product.heading_title || 'Unknown Product';
                     const productModel = product.model || 'N/A';
                     const productPrice = product.price || 0;
                     const productQuantity = product.pos_quantity || product.posquantity || product.quantity || 0;
                     
                     let formattedPrice = productPrice;
                     if (typeof format === 'function' && typeof posData !== 'undefined') {
                         formattedPrice = format(productPrice, posData.currency_code || 'INR');
                     } else {
                         formattedPrice = '₹' + parseFloat(productPrice).toFixed(2);
                     }
                     
         if (productQuantity <= 0) {
             actionButton = '<span class=\"out-of-stock-badge\" style=\"background: linear-gradient(135deg, #ff6b6b, #ee5a52); color: white; border: none; padding: 8px 4px; border-radius: 8px; font-size: 14px; font-weight: 700; cursor: not-allowed;\">OUT OF STOCK</span>';
         } else {
             // normal products → add button
             actionButton = '<button class=\"search-add-btn\" onclick=\"addProductFromSearch(' + productId + ')\">ADD PRODUCT</button>';
             
             // If editable, add edit button
             if (EDITABLE_PRODUCT_IDS.includes(parseInt(productId))) {
                 actionButton += '<button class=\"edit-product-btn edit-product-any\" data-product-id=\"' + productId + '\" style=\"margin-left:5px; background:#C9A24D; color:white; border:none; padding:8px; border-radius:8px;\"><i class=\"fas fa-edit\"></i></button>';
             }
         }
         
         
         
                     
                     html += '<div class=\"search-result-row\" data-product-id=\"' + productId + '\"><div class=\"search-result-cell\" style=\"flex: 2;\">' + productName + '</div><div class=\"search-result-cell\" style=\"flex: 1;\">' + productModel + '</div><div class=\"search-result-cell price\" style=\"flex: 1;\">' + formattedPrice + '</div><div class=\"search-result-cell quantity\" style=\"flex: 1;\">' + productQuantity + '</div><div class=\"search-result-cell\" style=\"flex: 1;\">' + actionButton + '</div></div>';
                 });
                 
                 html += '</div></div>';
                 popupBody.innerHTML = html;
             }
             
             document.getElementById('searchPopupModal').style.display = 'block';
         }
        
         \$(document).on('click', '.edit-product-any', function(e) {
             e.preventDefault();
             e.stopPropagation();
             
             let productId = \$(this).attr('data-product-id') || \$(this).data('product-id');
             if (!productId) return;
             
             editCartProduct(null, productId);
