         function saveProduct154() {
             const modalEl = document.getElementById('editProduct154Modal');
             const productId = parseInt(modalEl.getAttribute('data-product-id'));
             
             if (isNaN(productId)) {
                 console.error(\"Invalid product ID in modal\");
                 return;
             }
         
             // 1) Get updated values from popup
             var name  = document.getElementById('prod154_name').value || \"\";
             var price = parseFloat(document.getElementById('prod154_price').value) || 0;
             
             let productToEdit = null;
             let allProductsCount = JSON.parse(localStorage.getItem(\"allProductsCount\") || \"[]\");
         
             if (!allProductsCount || allProductsCount.length === 0) {
                 console.error(\"allProductsCount not available\");
                 return;
             }
         
             // Find in allProductsCount
             if (allProductsCount[productId]) {
                 productToEdit = allProductsCount[productId];
             } else {
                 productToEdit = allProductsCount.find(p => p.product_id == productId || p.productid == productId);
             }
         
             if (!productToEdit) {
                 console.error(\"Product \" + productId + \" not found in allProductsCount\");
                 return;
             }
         
             // Update product object with new values
             productToEdit.heading_title = name;
             productToEdit.headingtitle  = name;
             productToEdit.name          = name;
             productToEdit.price         = price;
             
             // CRITICAL FIX: Persist changes back to localStorage
             localStorage.setItem(\"allProductsCount\", JSON.stringify(allProductsCount));
         
             // Also update posData in memory
             if (window.posData && posData.products) {
                 if (posData.products[productId]) {
                     posData.products[productId].price = price;
                     posData.products[productId].name = name;
                     posData.products[productId].heading_title = name;
                 } else {
                      Object.keys(posData.products).forEach(function (key) {
                         var p = posData.products[key];
                         if (p.product_id == productId || p.productid == productId) {
                             p.price = price;
                             p.name = name;
                             p.heading_title = name;
                         }
                     });
                 }
             }
         
             // 3) Remove existing product from cart
             let posCart = JSON.parse(localStorage.getItem('poscart') || '[]');
             posCart = posCart.filter(function (item) {
                 return parseInt(item.productid) !== productId;
             });
             localStorage.setItem('poscart', JSON.stringify(posCart));
         
             if (typeof removeFromCart === 'function') {
                 removeFromCart(productId);
             }
         
             // 4) Add updated product back to cart
             if (typeof addToCartProducts === 'function') {
                 addToCartProducts(productToEdit);
             }
         
             // 5) Refresh UI components
             if (typeof addProductRowToCartArea === 'function') {
                 addProductRowToCartArea(productToEdit);
             }
         
             if (typeof getCartProductHTML === 'function') {
                 getCartProductHTML();
             }
         
             if (typeof updateCartTotals === 'function') {
                 updateCartTotals();
             }
             if (typeof updateInvoiceRightColumn === 'function') {
                 updateInvoiceRightColumn();
             }
         
             // 6) Close popup
             var modal = bootstrap.Modal.getInstance(modalEl);
             if (modal) modal.hide();
         }
         
         
         
         
         
         function addProductFromSearch(productId) {
         
             const product = lastSearchResults.find(function (p) {
                 return String(p.product_id) === String(productId);
             });
         
             if (!product) {
                 console.error('Product not found in API results:', productId);
                 showErrorFeedback('Product not found');
                 return;
             }
             allProductsCount.push(product);
             localStorage.setItem(\"allProductsCount\",JSON.stringify(allProductsCount));
             addProductToCart(product);
             console.log(\"addProductFromSearch\");
             document.getElementById('searchPopupModal').style.display = 'none';
             const input = document.getElementById(\"pos_search\");
             input.focus();
         }
         
         
         
         
         function closeSearchPopup() {
             document.getElementById('searchPopupModal').style.display = 'none';
             \$('#pos_search').val('');
         }
         
         function addProductRowToCartArea(product) {
         const cartArea = document.getElementById('cartArea');
         if (!cartArea) {
             console.error('Cart area not found');
             return;
         }
         
         
         // Ensure we display the actual product name if available (fallbacks like \"Product 4910\" come from missing data).
         if (product && product.product_id) {
             const pid = String(product.product_id);
             const isFallbackName = typeof product.name === 'string' && /^Product\\s*\\d+\$/i.test(product.name);
             if (!product.name || product.name.trim() === '' || isFallbackName) {
                 // Look up the original product details from posData or allProducts.
                 const sourceProduct = (window.posData && posData.products && posData.products[pid]) ||
                     (Array.isArray(allProducts) && allProducts.find(p => String(p.product_id) === pid));
                 if (sourceProduct) {
                     product.name = product.name || sourceProduct.name || sourceProduct.heading_title || sourceProduct.model || '';
                     product.heading_title = product.heading_title || sourceProduct.heading_title || sourceProduct.name || sourceProduct.model || '';
                 }
             }
         }

         if (!validateCartProductSingle(product)) {
          return; // ❌ stop further processing
        }

         // FIXED: Use product.posquantity for initial Actual Quantity (stock available)
         const stockQuantity = parseInt(product.pos_quantity || product.posquantity || product.quantity || 1);
         
         // User-editable Quantity (from localStorage or default 1)
         let editableQuantity = 1;
         const posCart = JSON.parse(localStorage.getItem(\"pos_cart\") || \"[]\");
         const existingCartItem = posCart.find(item => parseInt(item.product_id) === parseInt(product.product_id));
         if (existingCartItem) {
         editableQuantity = parseInt(existingCartItem.quantity);
         }
         
         // Calculate actual remaining stock: stock - current cart quantity
         const actualQuantity = Math.max(0, stockQuantity - editableQuantity);
         
         // Check if product row already exists in UI
         const existingRow = document.querySelector('.cart-row[data-product-id=\"' + product.product_id + '\"]');
         if (existingRow) {
         // Update existing row quantities
         const actualQtySpan = existingRow.querySelector('.actual-qty');
         const qtyInput = existingRow.querySelector('.qty-input');
         if (actualQtySpan) actualQtySpan.textContent = actualQuantity;
         if (qtyInput) {
         qtyInput.value = editableQuantity;
         updateRowTotal(existingRow, editableQuantity);
         }
         
         // Highlight the existing row that was updated
         applyRowHighlight(existingRow);
         
         updateInvoiceRightColumn();
         return;
         }
                  let formattedPrice = product.price || 0;
          if (typeof format === 'function' && typeof posData !== 'undefined') {
          formattedPrice = format(product.price, posData.currency_code || 'INR', '', true, 0);
          } else {
          formattedPrice = '₹' + Math.round(parseFloat(product.price));
          }
                  let totalPrice = product.price * editableQuantity;
          let formattedTotal = totalPrice;
          if (typeof format === 'function' && typeof posData !== 'undefined') {
          formattedTotal = format(totalPrice, posData.currency_code || 'INR', '', true, 0);
          } else {
          formattedTotal = '₹' + Math.round(parseFloat(totalPrice));
          }
         
         // const isPlusDisabled = actualQuantity <= 0 ? '' : '';
         
         const isEditable = EDITABLE_PRODUCT_IDS.includes(parseInt(product.product_id));
         const isCustomProduct = product.is_custom || false;

         // For quick-added custom products, allow editing the unit price directly in the cart row
         let priceCellHtml;
         if (isCustomProduct) {
             priceCellHtml =
                 '<div class=\"cart-cell single-qty\" style=\"padding-left: 15px;\" data-product-id=\"' + product.product_id + '\">' +
                  '<span class=\"qty-label\">' + editableQuantity + 'x</span>' +
                 '<input type=\"number\" step=\"0.01\" min=\"0\" class=\"cart-price-input\" value=\"' + Number(product.price).toFixed(2) + '\" ' +
                 'oninput=\"handleCartPriceChange(this, \\'' + product.product_id + '\\')\" ' +
                 'style=\"width: 100px;border: 1px; padding: 4px; font-size: 14px; background: white;\" />' +
                
                 '</div>';
         } else {
             priceCellHtml =
                 '<div class=\"cart-cell single-qty\" style=\"padding-left: 15px;\" data-product-id=\"' + product.product_id + '\">' +
                 editableQuantity + 'x ' + Math.round(product.price) + ' </div>';
         }

         const rowIndex = document.querySelectorAll('.cart-row').length + 1;
         
         
          // GST Calculation Logic - try all common fields (product-level, category, tax lines)
          let gstPercent = 0;
          if (product.gst_percent != null && product.gst_percent !== '') {
              gstPercent = parseFloat(product.gst_percent) || 0;
          } else if (product.gst != null && product.gst !== '') {
              gstPercent = parseFloat(product.gst) || 0;
          } else if (product.categories && Array.isArray(product.categories) && product.categories.length > 0 && product.categories[0].gst) {
              gstPercent = parseFloat(product.categories[0].gst) || 0;
          } else if (product.proTax && Array.isArray(product.proTax)) {
              product.proTax.forEach(function(tax) {
                  if ((tax.name || '').toLowerCase().includes('gst')) {
                      gstPercent += parseFloat(tax.rate) || 0;
                  }
              });
          }
          console.log('GST for product ' + product.product_id + ': ' + gstPercent + '%');
          
          let rowGst = (gstPercent / 100) * (product.price * editableQuantity);
          let formattedRowGst = rowGst;
          if (typeof format === 'function' && typeof posData !== 'undefined') {
              formattedRowGst = format(rowGst, posData.currency_code || 'INR', '', true, 0);
          } else {
              formattedRowGst = '₹' + Math.round(rowGst);
          }

          const productObj = {
               product_id: product.product_id,
               name: product.name || product.heading_title || '',
               price: Number(product.price),
               disc_price: product.disc_price ?? null,
               reward: product.reward ?? 0,
               quantity: editableQuantity,
               pos_quantity: product.pos_quantity ?? product.posquantity ?? 0,
               total: Number(product.price) * editableQuantity,
               excluded: product.excluded || false,
               gst_percent: gstPercent
             };
          console.log(\"productObj...............\",productObj);
          console.log(\"productObj....product...............\",product);
          const cartRowHTML =
          '<div data-product=\"' + encodeProduct(productObj) + '\" class=\"cart-row\" data-product-id=\"' + product.product_id + '\" data-price=\"' + product.price + '\">' +
          '<div class=\"cart-cell index\">' + rowIndex + '</div>' +
          '<div class=\"cart-cell\">' + product.product_id + '</div>' +
          '<div class=\"cart-cell\">' + (product.name || product.heading_title) + '</div>' +
          // ACTUAL QUANTITY = Stock - Cart Quantity (remaining available)
          '<div class=\"cart-cell actual-qty\" style=\"color:blue;\" data-initial-stock=\"' + stockQuantity + '\">' + actualQuantity + '</div>' +
          '<div class=\"cart-cell amount\"><div class=\"qty-controls\">' +
          '<button class=\"qty-btn\" onclick=\"decreaseQuantity(\\'' + product.product_id + '\\')\"> - </button>' +
          '<input type=\"number\" class=\"qty-input\" style=\"width: 59px; border-left: 1px solid #999; border-right: 1px solid #999; border-bottom: 1px solid #999;\" ' +
          'value=\"' + editableQuantity + '\" data-product-id=\"' + product.product_id + '\" oninput=\"handleManualQuantityEntry(this, \\'' + product.product_id + '\\')\">' +
          '<button class=\"qty-btn\" onclick=\"increaseQuantity(\\'' + product.product_id + '\\')\">+</button>' +
          '</div></div>' +
          '<div class=\"cart-cell discount\" style=\"text-align: center;\">0 %</div>' +
          priceCellHtml +
          '<div class=\"cart-cell gst-percent\" style=\"text-align: center; color: #856404;\" data-product-id=\"' + product.product_id + '\">' + gstPercent + ' %</div>' +
          '<div class=\"cart-cell row-gst\" style=\"text-align: right; padding-right: 10px; color: #856404;\" data-product-id=\"' + product.product_id + '\">' + formattedRowGst + '</div>' +
          '<div class=\"cart-cell total\" data-product-id=\"' + product.product_id + '\">' + formattedTotal + '</div>' +
          '<div class=\"cart-cell\" style=\"text-align: center; display:flex; align-items:center; justify-content:center; gap:6px;\">' +
          '<button class=\"exclude-toggle-btn included\" onclick=\"toggleProductExclusion(\\'' + product.product_id + '\\')\"><i class=\"fa-solid fa-empty-set\"></i></button>' +
          '<button class=\"delete-btn\" ' +
          'style=\"background-color: lightgray; border: 1px solid #959393; font-size: 15px; color: black;' +
          ((isEditable && !isCustomProduct) ? '' : ' opacity:0.3; cursor:not-allowed;') + '\" ' +
          ((isEditable && !isCustomProduct) ? 'onclick=\"editCartProduct(null, \\'' + product.product_id + '\\')\"' : 'disabled') +
          '>' +
          '<i class=\"fas fa-edit\"></i>' +
          '</button>' +
          '<button class=\"delete-btn\" style=\"background-color: lightgray; border: 1px solid #959393; font-size: 15px; color: black;\" ' +
          'onclick=\"removeFromCart(\\'' + product.product_id + '\\')\">✖️</button>' +
          '</div>' +
          '</div><hr class=\"cart-hr\">';
         
         cartArea.insertAdjacentHTML('beforeend', cartRowHTML);
         
         // Get the newly added row
         const newlyAddedRow = cartArea.lastElementChild.previousElementSibling || cartArea.lastElementChild;
         
         // Restore excluded state if product was previously excluded
         if (product.excluded === true || product.excluded === '1') {
             const toggleBtn = newlyAddedRow.querySelector('.exclude-toggle-btn');
             if (toggleBtn) {
                 toggleBtn.classList.remove('included');
                 toggleBtn.classList.add('excluded');
             }
             newlyAddedRow.classList.add('excluded-row');
         }
         
         // Highlight the newly added row (this will also scroll it into view automatically)
         applyRowHighlight(newlyAddedRow);
         
         setTimeout(updateCartTotals, 50);
         }
         
         
         
         function encodeProduct(obj) {
            return encodeURIComponent(JSON.stringify(obj));
            }
            
            function decodeProduct(str) {
            try {
            return JSON.parse(decodeURIComponent(str));
            } catch (e) {
            console.error('Invalid product JSON in DOM', e);
            return null;
            }
            }

         
         
        //  Adding product add validation
      function validateCartProductSingle(p) {
  const errors = [];

  if (!p || typeof p !== 'object') {
    errorMessage('Invalid product object');
    return false;
  }

  // product_id (required)
  if (!p.product_id || isNaN(p.product_id) || Number(p.product_id) <= 0) {
    errors.push(\"product_id\");
  }

  // name OR heading_title (required string)
  // If missing, fall back to heading_title or a placeholder based on product_id.
  if (!p.name || typeof p.name !== \"string\" || p.name.trim() === \"\") {
    if (p.heading_title && typeof p.heading_title === \"string\" && p.heading_title.trim() !== \"\") {
      p.name = p.heading_title;
    } else if (p.product_id != null) {
      p.name = 'Product ' + p.product_id;
      p.heading_title = p.name;
    } else {
      p.name = 'Unknown product';
      p.heading_title = p.name;
    }
    console.warn('Cart product missing name/heading_title; using fallback:', p.name, p);
  }

  // disc_price (null OR numeric)
  if (p.disc_price != null && isNaN(p.disc_price)) {
    errors.push(\"disc_price\");
  }

  // price (null OR numeric)
  if (p.price != null && isNaN(p.price)) {
    errors.push(\"price\");
  }

  // total (null OR numeric)
  if (p.total != null && isNaN(p.total)) {
    errors.push(\"total\");
  }

  // reward (null OR numeric)
  if (p.reward != null && isNaN(p.reward)) {
    errors.push(\"reward\");
  }

  // quantity (null allowed, but if present must be >= 1)
  if (
    p.quantity != null &&
    (isNaN(p.quantity) || Number(p.quantity) < 1)
  ) {
    errors.push(\"quantity\");
  }

  // pos_quantity (numeric, 0 or -1 allowed)
  if (p.pos_quantity != null && isNaN(p.pos_quantity)) {
    errors.push(\"pos_quantity\");
  }

  if (errors.length) {
    console.error(\"Cart product validation failed:\", errors, p);
    errorMessage(`Missing / invalid field: \${errors.join(\", \")}`, 2000);
    return false;
  }

  return true;
}

         
         
          // FIXED: Helper function to update row total using price from data-price
          function updateRowTotal(row, quantity) {
              const price = parseFloat(row.dataset.price) || 0;
              const product = decodeProduct(row.dataset.product);
              const gstPercent = product ? (product.gst_percent || 0) : 0;
              
              const totalCell = row.querySelector('.cart-cell.total');
              const totalSingleCell = row.querySelector('.cart-cell.single-qty');
              const rowGstCell = row.querySelector('.cart-cell.row-gst');
              
              if (totalCell) {
                  let totalPrice = price * quantity;
                   if (typeof format === 'function' && typeof posData !== 'undefined') {
                       totalCell.textContent = format(totalPrice, posData.currency_code || 'INR', '', true, 0);
                   } else {
                       totalCell.textContent = '₹' + Math.round(totalPrice);
                   }
              }
              if (totalSingleCell) {
                   const priceInput = totalSingleCell.querySelector('.cart-price-input');
                   const qtyLabel = totalSingleCell.querySelector('.qty-label');

                   if (priceInput) {
                        if (document.activeElement !== priceInput) {
                           priceInput.value = price.toFixed(2);
                       }
                       if (qtyLabel) qtyLabel.textContent = `\${quantity}x`;
                   } else {
                       totalSingleCell.textContent = `\${quantity}x \${Math.round(price)}`;
                   }
              }
              if (rowGstCell) {
                  let rowGst = (gstPercent / 100) * (price * quantity);
                  if (typeof format === 'function' && typeof posData !== 'undefined') {
                      rowGstCell.textContent = format(rowGst, posData.currency_code || 'INR', '', true, 0);
                  } else {
                      rowGstCell.textContent = '₹' + Math.round(rowGst);
                  }
              }
          }
         
         function increaseQuantity(productId) {
         const row = document.querySelector('.cart-row[data-product-id=\"' + productId + '\"]');
         if (!row) return;
         
         let product = decodeProduct(row.dataset.product);
         if (!product) return;
         
         const qtyInput = row.querySelector('.qty-input');
         const actualQtySpan = row.querySelector('.actual-qty');
         const increaseBtn = row.querySelector('.qty-btn[onclick*=\"increaseQuantity\"]');
         
         let currentQty = parseInt(qtyInput.value) || 1;
         let currentActualQty = parseInt(actualQtySpan.textContent) || 0;
         
         currentQty++;
         
         // In Return Mode, stock INCREASES when adding to cart (returning items to store).
         var isReturnOrder = !!sessionStorage.getItem('currentReturnOrder');
         if (isReturnOrder) {
             actualQtySpan.textContent = currentActualQty - 1;
         } else {
             actualQtySpan.textContent = currentActualQty - 1;
         }
         
         qtyInput.value = currentQty;
         
         product.quantity = currentQty;
         product.total = product.quantity * product.price;
         row.dataset.product = encodeProduct(product);
         
         updateLocalStorageQuantity(productId, currentQty);
         updateRowTotal(row, currentQty);
         applyRowHighlight(row); // Gray highlight on interaction
         
         updateCartTotals();
         updateInvoiceRightColumn();
         
         if (typeof add_qty === 'function') {
         add_qty(productId);
         }
         
         const input = document.getElementById(\"pos_search\");
         input.focus();
         }
         
         
         
         function decreaseQuantity(productId) {
         const row = document.querySelector('.cart-row[data-product-id=\"' + productId + '\"]');
         if (!row) return;
         
           let product = decodeProduct(row.dataset.product);
          if (!product) return;
          
         const qtyInput = row.querySelector('.qty-input');
         const actualQtySpan = row.querySelector('.actual-qty');
         const increaseBtn = row.querySelector('.qty-btn[onclick*=\"increaseQuantity\"]');
         
         let currentQty = parseInt(qtyInput.value) || 1;
         let currentActualQty = parseInt(actualQtySpan.textContent) || 0;
         
         if (currentQty > 1) {
         currentQty--;
         
         // Update Available Quantity (Stock): 
         // In Return Mode, stock DECREASES when removing from cart (returning fewer items).
         var isReturnOrder = !!sessionStorage.getItem('currentReturnOrder');
         if (isReturnOrder) {
             actualQtySpan.textContent = currentActualQty + 1;
         } else {
             actualQtySpan.textContent = currentActualQty + 1;
         }
         
         qtyInput.value = currentQty;


         product.quantity = currentQty;
         product.total = product.quantity * product.price;

         row.dataset.product = encodeProduct(product);

         
         updateLocalStorageQuantity(productId, currentQty);
         updateRowTotal(row, currentQty);
         applyRowHighlight(row); // Gray highlight on interaction
         
         updateCartTotals();
         updateInvoiceRightColumn();

         
         if (typeof sub_qty === 'function') {
         sub_qty(productId);
         }
         
         // Re-enable + button if stock becomes available
         if (increaseBtn && parseInt(actualQtySpan.textContent) > 0) {
         increaseBtn.disabled = false;
         increaseBtn.style.opacity = '1';
         increaseBtn.style.cursor = 'pointer';
         }
         }
         const input = document.getElementById(\"pos_search\");
         input.focus();
         }
         
         
          function handleManualQuantityEntry(input, productId) {
             const row = document.querySelector('.cart-row[data-product-id=\"' + productId + '\"]');
             if (!row) return;
             
             let product = decodeProduct(row.dataset.product);
             if (!product) return;
             
             const actualQtySpan = row.querySelector('.actual-qty');
             
             // Consistent stock tracking using data-initial-stock anchor
             let cartQty = parseInt(product.quantity) || 0;
             let totalAvailable = actualQtySpan.hasAttribute('data-initial-stock') 
                ? parseInt(actualQtySpan.getAttribute('data-initial-stock')) 
                : (parseInt(actualQtySpan.textContent) + cartQty);
             
             if (!actualQtySpan.hasAttribute('data-initial-stock')) {
                actualQtySpan.setAttribute('data-initial-stock', totalAvailable);
             }
             
             let newQty = parseInt(input.value);
             if (isNaN(newQty)) return; 
             
             // User can edit quantity irrespective of available stock
             if (newQty < 1) newQty = 1;
             input.value = newQty;
             
             // Update Stock UI
             actualQtySpan.textContent = totalAvailable - newQty;
             
             // Update Data
             product.quantity = newQty;
             product.total = product.quantity * product.price;
             row.dataset.product = encodeProduct(product);
             
             // Sync everything
             updateLocalStorageQuantity(productId, newQty);
             updateRowTotal(row, newQty);
             updateCartTotals(); // This calls updateInvoiceRightColumn which updates the footer
             
             // Sync cart badge
             const badge = document.getElementById('pos-cart-badge');
             if (badge) {
                 const numItems = document.querySelectorAll('.cart-row').length;
                 badge.textContent = numItems;
             }
          }
         
         
         
         
         
         // FIXED: New helper function to sync UI quantity with localStorage
         function updateLocalStorageQuantity(productId, newQuantity) {
             let posCart = JSON.parse(localStorage.getItem(\"pos_cart\") || \"[]\");
             let updated = false;
             
             for (let i = 0; i < posCart.length; i++) {
                 if (parseInt(posCart[i].product_id) === parseInt(productId)) {
                     posCart[i].quantity = newQuantity;
                     updated = true;
                     break;
                 }
             }
             
             if (updated) {
                 localStorage.setItem(\"pos_cart\", JSON.stringify(posCart));
             }
         }

         // Allows editing price for quick-added / custom products directly in the cart row
         function handleCartPriceChange(input, productId) {
             const row = document.querySelector('.cart-row[data-product-id=\"' + productId + '\"]');
             if (!row) return;

             let newPrice = parseFloat(input.value);
             if (isNaN(newPrice) || newPrice < 0) {
                 newPrice = 0;
             }

             // Keep displayed price in sync
             row.dataset.price = newPrice;

             const product = decodeProduct(row.dataset.product);
             if (!product) return;

             product.price = newPrice;
             product.total = (product.quantity || 1) * newPrice;
             row.dataset.product = encodeProduct(product);

             updateLocalStoragePrice(productId, newPrice);
             updateRowTotal(row, product.quantity || 1);
             updateCartTotals();
         }
        function formatCartPriceInput(input, productId) {
             let val = parseFloat(input.value);
             if (isNaN(val) || val < 0) val = 0;
             input.value = val.toFixed(2);
             // propagate change to cart data as well
             handleCartPriceChange(input, productId);
         }
         function updateLocalStoragePrice(productId, newPrice) {
             let posCart = JSON.parse(localStorage.getItem(\"pos_cart\") || \"[]\");
             let updated = false;

             for (let i = 0; i < posCart.length; i++) {
                 if (parseInt(posCart[i].product_id) === parseInt(productId)) {
                     posCart[i].price = newPrice;
                     updated = true;
                     break;
                 }
             }

             if (updated) {
                 localStorage.setItem(\"pos_cart\", JSON.stringify(posCart));
             }
         }

         /**
          * Applies a temporary highlight to a cart row
          */
         /**
          * Toggle product exclusion from calculations
          */
         function toggleProductExclusion(productId) {
             const row = document.querySelector('.cart-row[data-product-id=\"' + productId + '\"]');
             if (!row) return;
             
             const toggleBtn = row.querySelector('.exclude-toggle-btn');
             if (!toggleBtn) return;
             
             // Get current exclusion state
             const isCurrentlyExcluded = toggleBtn.classList.contains('excluded');
             
             // Toggle the state
             if (isCurrentlyExcluded) {
                 // Change from EXCLUDED (green) to INCLUDED (red)
                 toggleBtn.classList.remove('excluded');
                 toggleBtn.classList.add('included');
                 row.classList.remove('excluded-row');
             } else {
                 // Change from INCLUDED (red) to EXCLUDED (green)
                 toggleBtn.classList.remove('included');
                 toggleBtn.classList.add('excluded');
                 row.classList.add('excluded-row');
             }
             
             // Update localStorage
             let posCart = JSON.parse(localStorage.getItem(\"pos_cart\") || \"[]\");
             for (let i = 0; i < posCart.length; i++) {
                 if (parseInt(posCart[i].product_id) === parseInt(productId)) {
                     posCart[i].excluded = !isCurrentlyExcluded;
                     break;
                 }
             }
             localStorage.setItem(\"pos_cart\", JSON.stringify(posCart));
             
             // Update product data attribute in row
             let product = decodeProduct(row.dataset.product);
             if (product) {
                 product.excluded = !isCurrentlyExcluded;
                 row.dataset.product = encodeProduct(product);
             }
             
             // Recalculate totals
             updateCartTotals();
             updateInvoiceRightColumn();
             
             // Highlight and scroll to the toggled row
             applyRowHighlight(row);
         }
         
         function applyRowHighlight(row) {
    if (!row) return;
    
    // Remove highlight from all other rows
    document.querySelectorAll('.cart-row').forEach(r => r.classList.remove('highlighted-row'));
    
    // Add highlight to current row
    row.classList.add('highlighted-row');
    
    // Automatically scroll the highlighted row into view
    setTimeout(function() {
        const cartArea = document.getElementById('cartArea');
        if (cartArea && row) {
            // Get positions
            const rowRect = row.getBoundingClientRect();
            const cartRect = cartArea.getBoundingClientRect();
            
            // Check if row is outside visible area
            const isAboveView = rowRect.top < cartRect.top;
            const isBelowView = rowRect.bottom > cartRect.bottom;
            
            // Scroll only if needed
            if (isAboveView || isBelowView) {
                row.scrollIntoView({
                    behavior: 'smooth',
                    block: 'center',
                    inline: 'nearest'
                });
            }
        }
    }, 50);
}
         
         /**
          * Handles input changes on the return payment field
          */
         function handlePaymentChange(inputElement) {
             // Sanitize input to numbers and decimal only
             const val = inputElement.value.replace(/[^0-9.]/g, '');
             const newVal = parseFloat(val) || 0;
             window.alreadyPaidAmount = newVal;
             // We update the totals to reflect the new payment balance
             if (typeof updateCartTotals === 'function') {
                 updateCartTotals();
             }
         }
         
         /**
          * Remove product from cart with proper cleanup
          */
         function removeFromCart(productId) {
             const cartRow = document.querySelector('.cart-row[data-product-id=\"' + productId + '\"]');
             if (cartRow) {
                 const nextHr = cartRow.nextElementSibling;
                 if (nextHr && nextHr.classList.contains('cart-hr')) {
                     nextHr.remove();
                 }
                 cartRow.remove();
                 
                 // Professional cleanup: Remove from localStorage and clean up excluded flag
                 let posCart = JSON.parse(localStorage.getItem(\"pos_cart\") || \"[]\");
                 posCart = posCart.filter(item => parseInt(item.product_id) !== parseInt(productId));
                 
                 // Clean up excluded flags from remaining products if needed
                 posCart.forEach(function(product) {
                     if (product.excluded === false) {
                         delete product.excluded; // Remove default false values for cleaner data
                     }
                 });
                 
                 localStorage.setItem(\"pos_cart\", JSON.stringify(posCart));
                 
                 reindexCartRows();
                 updateCartTotals();
                 updateInvoiceRightColumn();
                 
                 if (typeof removeProductFromCart === 'function') {
                     removeProductFromCart(productId);
                 }
             }
             
             const input = document.getElementById(\"pos_search\");
             input.focus();
         }
         
         function reindexCartRows() {
             const rows = document.querySelectorAll('.cart-row');
         
             rows.forEach((row, index) => {
                 const indexCell = row.querySelector('.cart-cell.index');
                 if (indexCell) {
                     indexCell.textContent = index + 1;
                 }
             });
         }
         
      
         function calculateProductTax(product, quantity, lineSubtotal) {
             if (!product.proTax || !Array.isArray(product.proTax) || product.proTax.length === 0) {
                 return { vatTax: 0, ecoTax: 0, totalTax: 0 };
             }
         
             let vatTax = 0;
             let ecoTax = 0;
         
             product.proTax.forEach(function (tax) {
                 const taxRate = parseFloat(tax.rate) || 0;
                 const taxType = tax.type;
                 const taxName = (tax.name || '').toLowerCase();
         
                 let calculatedTax = 0;
         
                 if (taxType === 'P') {
                     // percent on full line (already includes quantity)
                     calculatedTax = (lineSubtotal * taxRate / 100);
                 } else if (taxType === 'F') {
                     // fixed per unit
                     calculatedTax = taxRate * quantity;
                 }
         
                 if (taxName.includes('vat')) {
                     vatTax += calculatedTax;
                 } else if (taxName.includes('eco')) {
                     ecoTax += calculatedTax;
                 } else {
                     vatTax += calculatedTax;
                 }
             });
         
             return {
                 vatTax: vatTax,
                 ecoTax: ecoTax,
                 totalTax: vatTax - ecoTax
             };
         }
         
         
         function updateInvoiceRightColumn() {
             var cartRows = document.querySelectorAll('.cart-row');
             var qtyTotal = 0;
             var numItems = 0;
             
             cartRows.forEach(function(row) {
                 // Skip excluded products
                 if (row.classList.contains('excluded-row')) {
                     return;
                 }
                 
                 var qtyInput = row.querySelector('.qty-input');
                 if (qtyInput) {
                     qtyTotal += parseInt(qtyInput.value) || 0;
                 }
                 numItems++;
             });
             
             // UPDATE EXISTING DOM (if already rendered)
             var qtyElement = document.querySelector('#invoice-right .value-box-pos:nth-of-type(1)');
             var itemsElement = document.querySelector('#invoice-right .value-box-pos:nth-of-type(2)');
             
             if (qtyElement) qtyElement.textContent = qtyTotal;
             if (itemsElement) itemsElement.textContent = numItems;
         
             // Mirror to discount-left summary (for spans under .discount-left)
             var summaryQty   = document.getElementById('summaryQuantityTotal');
             var summaryItems = document.getElementById('summaryNumberOfItems');

             if (summaryQty)   summaryQty.textContent   = 'Qty: '   + qtyTotal;
             if (summaryItems) summaryItems.textContent = 'Items: ' + numItems;
             
           
             
             if (typeof checkAndUpdatePayButtonState === 'function') {
                 checkAndUpdatePayButtonState();
             }
         }
         
          function updateCartTotals() {
              let netTotal = 0;
              let totalTax = 0;
              let totalDiscount = 0;
          
              const cartRows = document.querySelectorAll('.cart-row');
          
              cartRows.forEach(function (row) {
                  // Skip excluded products
                  if (row.classList.contains('excluded-row')) {
                      return;
                  }
                  
                  const qtyInput     = row.querySelector('.qty-input');
                  const product      = decodeProduct(row.dataset.product);
          
                  if (!qtyInput || !product) return;
          
                  const quantity = parseInt(qtyInput.value) || 0;
                  const unitPrice = parseFloat(row.dataset.price) || 0;
                  const gstPercent = product.gst_percent || 0;
          
                  let lineTotal = unitPrice * quantity;
                  netTotal += lineTotal;

                  // GST logic - per-row GST amount
                  let lineGst = (gstPercent / 100) * lineTotal;
                  totalTax += lineGst;

                  // No per-line discount is applied. Keep totalDiscount at 0.
              });
          
              // Mirror totalTax into discount for display purposes
              totalDiscount = totalTax;

              // Grand total remains net + tax
              const grandTotal = netTotal;

              updateTotalsDisplay(netTotal, totalTax, grandTotal, totalDiscount);
              updateInvoiceRightColumn();
          }
         
          function updateTotalsDisplay(netTotal, totalTax, grandTotal, totalDiscount) {
              let formattedNetTotal, formattedTotalTax, formattedGrandTotal, formattedTotalDiscount;
              
              if (typeof format === 'function' && typeof posData !== 'undefined') {
                  formattedNetTotal = format(netTotal, posData.currency_code || 'INR');
                  formattedTotalTax = format(totalTax, posData.currency_code || 'INR');
                  formattedGrandTotal = format(grandTotal, posData.currency_code || 'INR');
                  formattedTotalDiscount = format(totalDiscount || 0, posData.currency_code || 'INR');
              } else {
                  formattedNetTotal = '₹' + netTotal.toFixed(2);
                  formattedTotalTax = '₹' + totalTax.toFixed(2);
                  formattedGrandTotal = '₹' + grandTotal.toFixed(2);
                  formattedTotalDiscount = '₹' + (totalDiscount || 0).toFixed(2);
              }
              
              // Use explicit IDs to avoid DOM order dependency.
              const netTotalSpan = document.getElementById('netTotalValue');
              const totalDiscountSpan = document.getElementById('discountValue');
              const totalTaxSpan = document.getElementById('taxValue');
              const grandTotalSpan = document.getElementById('grandTotalValue');
              
              if (netTotalSpan) netTotalSpan.textContent = formattedNetTotal;
              if (totalDiscountSpan) totalDiscountSpan.textContent = formattedTotalDiscount;
              if (totalTaxSpan) totalTaxSpan.textContent = formattedTotalTax;
              if (grandTotalSpan) grandTotalSpan.textContent = formattedGrandTotal;
          }
         
