         /**
          * Professional cleanup function to remove excluded flags from all products in localStorage
          * This ensures clean data when cart is cleared or order is completed
          */
         function cleanupExcludedFlags() {
             let posCart = JSON.parse(localStorage.getItem(\"pos_cart\") || \"[]\");
             
             // Remove excluded flag from all products
             posCart.forEach(function(product) {
                 if (product.hasOwnProperty('excluded')) {
                     delete product.excluded;
                 }
             });
             
             // Update localStorage with cleaned data
             if (posCart.length > 0) {
                 localStorage.setItem(\"pos_cart\", JSON.stringify(posCart));
             }
         }
         function renderHoldCartList() {
             var container = document.getElementById(\"holdCartList\");
             if (!container) return;
         
             var allHolds = JSON.parse(localStorage.getItem(HOLD_CART_KEY) || \"[]\");
             container.innerHTML = \"\";
             //console.log(allHolds);
         
             if (!allHolds || !allHolds.length) {
                 return;
             }
             
             allHolds.forEach(function (hold) {
                 var card = document.createElement(\"div\");
                 card.className = \"hold-cart-card\";
                 card.dataset.holdId = hold.id;   // ✅ identify this card
                 card.style.border = \"3px solid #ccc\";
                 card.style.padding = \"6px\";
                 card.style.margin = \"3px\";
                 card.style.backgroundColor = \"#f7f7f7\";
                 card.style.fontSize = \"12px\";
                 card.style.height = \"89px\";
                 card.style.display = \"inline-block\";
                 card.style.minWidth = \"120px\";
         
                 // first line: description
                 var title = document.createElement(\"div\");
                 title.textContent = hold.description || \"(no description)\";
                 title.style.fontWeight = \"bold\";
                 title.style.whiteSpace = \"nowrap\";
                 title.style.overflow = \"hidden\";
                 title.style.textOverflow = \"ellipsis\";
                 title.style.fontSize = \"15px\";        // FIXED
                 title.style.color = \"black\";
                 title.style.textAlign = \"center\";     // FIXED
                 card.appendChild(title);
         
                 // second line: small info from cart (items count)
                 var info = document.createElement(\"div\");
                 var itemCount = hold.cart ? hold.cart.length : 0;
                 info.textContent = \"Items Count: \" + itemCount;
                 info.style.fontSize = \"12px\";
                 info.style.color = \"#555\";
                 card.appendChild(info);
         
                 // buttons
                 var btnRow = document.createElement(\"div\");
                 btnRow.style.marginTop = \"4px\";
                 
                 var restoreBtn = document.createElement(\"button\");
                 restoreBtn.textContent = \"RESTO\";
                 restoreBtn.style.marginRight = \"4px\";
                 restoreBtn.style.fontSize = \"13px\";
                 restoreBtn.style.padding = \"0px 3px\";
                 restoreBtn.style.color = \"#0d01a8\";
                 restoreBtn.style.border = \"none\";
                 restoreBtn.onclick = function () {
                     restoreHoldCart(hold.id);
                 };
         
                 var deleteBtn = document.createElement(\"button\");
                 deleteBtn.textContent = \"DEL\";
                 deleteBtn.style.fontSize = \"13px\";
                 deleteBtn.style.padding = \"0px 3px\";
                 deleteBtn.style.color = \"red\";
                 deleteBtn.style.border = \"none\";
                 deleteBtn.onclick = function () {
                     deleteHoldCart(hold.id);
                 };
         
                 btnRow.appendChild(restoreBtn);
                 btnRow.appendChild(deleteBtn);
                 card.appendChild(btnRow);
         
