         // ========================================
         // PERSISTENT LOGIN TIME SYSTEM (NO RESET ON REFRESH)
         // ========================================
         var clockInTime = null;
         var timerId = null;
         
         // Initialize from storage on page load
         function initializeLoginTime() {
             var savedLoginTime = localStorage.getItem('posLoginTime');
             if (savedLoginTime) {
                 clockInTime = new Date(savedLoginTime);
         
                 // Logged in text in SAME format as current
                 document.getElementById('loginTime').textContent =
                     'Logged : ' + formatTimeOnly(clockInTime);
         
                 document.getElementById('clockBtn').textContent = 'Clock out';
         
                 if (!timerId) {
                     timerId = setInterval(updateCurrentTime, 1000);
                 }
             } else {
                 document.getElementById('loginTime').textContent = '';
                 document.getElementById('clockBtn').textContent = 'Clock in';
             }
         
             updateCurrentTime();
         }
         
         function formatDateTime(d, withSeconds) {
             var dd  = String(d.getDate()).padStart(2, '0');
             var mm  = String(d.getMonth() + 1).padStart(2, '0');
             var yy  = d.getFullYear();
             var hh  = String(d.getHours()).padStart(2, '0');
             var mi  = String(d.getMinutes()).padStart(2, '0');
             var ss  = String(d.getSeconds()).padStart(2, '0');
         
             if (withSeconds) {
                 return dd + '-' + mm + '-' + yy + ' ' + hh + ':' + mi + ':' + ss;
             } else {
                 return dd + '-' + mm + '-' + yy + ' ' + hh + ':' + mi;
             }
         }
         
         // Use SAME format as \"Current\" (e.g. 6:35:55 PM)
         function formatTimeOnly(d) {
             return d.toLocaleTimeString();   // includes seconds + AM/PM, locale based
         }
         
         function getDurationText(from, to) {
             var diffMs = to.getTime() - from.getTime();
             if (diffMs < 0) diffMs = 0;
         
             var totalMinutes = Math.floor(diffMs / 60000);
             var hours = Math.floor(totalMinutes / 60);
             var minutes = totalMinutes % 60;
         
             var parts = [];
             if (hours > 0) {
                 parts.push(hours + 'h');
             }
             parts.push(minutes + 'm');
         
             return parts.join(' ');
         }
         
         function updateCurrentTime() {
             const loginTimeEl   = document.getElementById('loginTime');
             const currentTimeEl = document.getElementById('currentTime');
             const durationEl    = document.getElementById('duration');
         
             const savedLoginTimeStr = localStorage.getItem('posLoginTime');
         
             if (savedLoginTimeStr) {
                 const loginTime = new Date(savedLoginTimeStr);
                 const now       = new Date();
         
                 // Calculate duration HH:MM:SS
                 const diffMs       = now - loginTime;
                 const totalSeconds = Math.floor(diffMs / 1000);
                 const hours        = Math.floor(totalSeconds / 3600);
                 const minutes      = Math.floor((totalSeconds % 3600) / 60);
                 const seconds      = totalSeconds % 60;
         
                 const durationStr =
                     `\${hours.toString().padStart(2,'0')}:` +
                     `\${minutes.toString().padStart(2,'0')}:` +
                     `\${seconds.toString().padStart(2,'0')}`;
         
                 // Current time and duration text
                 currentTimeEl.textContent = 'Current: ' + now.toLocaleTimeString();
                 durationEl.textContent    = 'Duration: ' + durationStr;
         
                 // Logged in text in SAME format as current
                 loginTimeEl.textContent   = 'Logged: ' + formatTimeOnly(loginTime);
             } else {
                 currentTimeEl.textContent = '';
                 durationEl.textContent    = '';
                 loginTimeEl.textContent   = '';
             }
         
             setTimeout(updateCurrentTime, 1000);
         }
         
         function loginTimings() {
             const loginTimeEl   = document.getElementById('loginTime');
             const currentTimeEl = document.getElementById('currentTime');
             const clockBtn      = document.getElementById('clockBtn');
         
             const savedLoginTimeStr = localStorage.getItem('posLoginTime');
         
             if (savedLoginTimeStr) {
                 const savedLoginTime = new Date(savedLoginTimeStr);
         
                 // Show login time in SAME format
                 loginTimeEl.textContent = 'Logged : ' + formatTimeOnly(savedLoginTime);
         
                 clockBtn.textContent = 'Clock out';
                 updateCurrentTime();
             } else {
                 loginTimeEl.textContent = '';
                 currentTimeEl.textContent = '';
                 clockBtn.textContent = 'Clock in';
             }
         }
         
         // ONE function for everything - with persistence
         function toggleClock() {
             const clockBtn    = document.getElementById('clockBtn');
             const loginTimeEl = document.getElementById('loginTime');
         
             if (clockBtn.textContent.trim() === 'Clock in') {
                 // Clock in
                 const now = new Date();
         
                 // Text in SAME format as \"Current\"
                 loginTimeEl.textContent = 'Logged : ' + formatTimeOnly(now);
         
                 localStorage.setItem('posLoginTime', now.toISOString());
                 clockBtn.textContent = 'Clock out';
             } else {
                 // Clock out
                 clockBtn.textContent = 'Clock in';
                 loginTimeEl.textContent = '';
                 localStorage.removeItem('posLoginTime');
             }
         
             updateCurrentTime();
         }
        
         
        
         
