         // Product autocomplete search function
         function search_product_info(input) {
             var searchTerm = input.value.trim().toLowerCase();
             
             if (searchTerm.length === 0) {
                 \$('#product_autocomplete_list').empty().hide();
                 return;
             }
             
             // Get products from localStorage (pos_cart)
             let cartProducts = [];
             if (localStorage.getItem(\"pos_cart\") !== null) {
                 cartProducts = JSON.parse(localStorage.getItem(\"pos_cart\"));
             }
             
             // Create a unique set of product names (avoid duplicates)
             let uniqueProductNames = new Set();
             cartProducts.forEach(product => {
                 if (product.name && product.name.toLowerCase().includes(searchTerm)) {
                     uniqueProductNames.add(product.name);
                 }
             });
             
             // Display results
             \$('#product_autocomplete_list').empty().show();
             
             if (uniqueProductNames.size > 0) {
                 uniqueProductNames.forEach(name => {
                     let item = `
                     <li class=\"dropdown-item\" 
                         onclick=\"selectProductByName('\${name.replace(/'/g, \"\\\\'\")}')\"
                         style=\"cursor:pointer; padding:8px 12px; border-bottom:1px solid #2a3040; color: #fff;\">
                         \${name}
                     </li>`;
                     \$('#product_autocomplete_list').append(item);
                 });
             } 
            //  else {
            //      \$('#product_autocomplete_list').html('<li class=\"dropdown-item\" style=\"padding:8px 12px; color: #8a93a2;\">No products found</li>');
            //  }
         }
         
         // Select product from dropdown by name
         function selectProductByName(productName) {
             \$('#quick_add_name').val(productName);
             \$('#product_autocomplete_list').hide();
         }
         
         // Hide dropdown when clicking outside
         \$(document).on('click', function (e) {
