         function saveQuickAddProduct() {
             
             const name = \$('#quick_add_name').val().trim() || 'SGC Product';
             const quantity = parseInt(\$('#quick_add_quantity').val()) || 1;
             const priceStr = \$('#quick_add_price').val().trim();
             
             if (!priceStr || isNaN(parseFloat(priceStr))) {
                 \$('#quick_add_error').fadeIn();
                 return;
             }
             
            const price = parseFloat(priceStr);
            const gstPercent = parseFloat(\$('#quick_add_gst').val()) || 0;
             \$('#quick_add_error').hide();
             
             const now = new Date();
         
             const hour = String(now.getHours()).padStart(2, '0');
             const minute = String(now.getMinutes()).padStart(2, '0');
             const second = String(now.getSeconds()).padStart(2, '0');
             
             // 3 random digits (100–999)
             const randomDigits = Math.floor(100 + Math.random() * 900);
             
             const productId = hour + minute + second + randomDigits;
             
             //console.log(productId);
         
             \$('#quick_add_name').val('');
             \$('#quick_add_price').val('');
             \$('#quick_add_gst').val('3');
             
             // 1. Add to custom products (for Cart.getProducts to recognize it)
             let customProducts = [];
             if (localStorage.getItem(\"custom_product\") !== null) {
                 customProducts = JSON.parse(localStorage.getItem(\"custom_product\"));
             }
             
             let cartProducts = [];
             if (localStorage.getItem(\"pos_cart\") !== null) {
                 cartProducts = JSON.parse(localStorage.getItem(\"pos_cart\"));
             }
             
             let customer_id = 0;
             if (sessionStorage.getItem('currentCustomerData') !== null) {
                 const currentCustomerData = JSON.parse(sessionStorage.getItem('currentCustomerData'));
                 customer_id = currentCustomerData.customer_id;
             }
             
             const cartId = Date.now();
             
             const customProductObj = {
                cart_id: cartId,
                 product_id: productId,
                 customer_id: customer_id,
                 name: name,
                 recurring_id: '0',
                 model: name,
                price: price,
                 quantity: quantity,
                 pos_quantity: 1, // Set to 999 to allow increasing quantity in cart
                 is_custom: true,    // Mark as custom to disable edit button
                 tax_class_id: 0,
                 image: '',
                 option: [],
                 small_thumb: ''
             };
            // Attach GST and discount metadata for quick-added products
            customProductObj.gst_percent = gstPercent;
             
             customProducts.push(customProductObj);
             localStorage.setItem('custom_product', JSON.stringify(customProducts));
             
              allProductsCount.push(customProductObj);
             localStorage.setItem(\"allProductsCount\", JSON.stringify(allProductsCount));

             
             const posCartData = {
                 'cart_id': cartId,
                 'customer_id': customer_id,
                 'product_id': productId,
                 'recurring_id': '0',
                 'option': [],
                 'quantity': quantity
             };
             
             cartProducts.push(customProductObj);
             localStorage.setItem('pos_cart', JSON.stringify(cartProducts));

             // clear quick add inputs
             \$('#quick_add_name').val('');
             \$('#quick_add_price').val('');
             \$('#quick_add_gst').val('0');
             
             // 3. UI Update
     if (typeof PlaySound === 'function') PlaySound();
             
             // Call the specific function requested by the user
             
             if (typeof addProductRowToCartArea === 'function') {
                 addProductRowToCartArea(customProductObj);
             }
             
             // Force totals update
             if (typeof updateCartTotals === 'function') {
                 updateCartTotals();
             } else if (typeof getCartProductHTML === 'function') {
                 getCartProductHTML();
             }
             
             // Hide modal
             const modalElement = document.getElementById('quickAddProductModal');
             const modalInstance = bootstrap.Modal.getInstance(modalElement);
             if (modalInstance) {
                 modalInstance.hide();
             } else {
                 \$(modalElement).modal('hide');
             }
             
             // Optional: Notify success
             if (typeof toastr !== 'undefined') {
                 \$('#submit-order-btn').removeClass('disabled').css('pointer-events', 'auto');
         
                 toastr.success('Product added to cart');
             }
             
             const input = document.getElementById(\"pos_search\");
             input.focus();
         }
         
         
         let currentVal = \"0\";
    const screen = document.getElementById('display');

    function input(val) {
        if (currentVal === \"0\" && val !== '.') {
            currentVal = val;
        } else {
            currentVal += val;
        }
        update();
    }

    function clearDisplay() {
        currentVal = \"0\";
        update();
    }

    function calculate() {
        try {
            currentVal = eval(currentVal).toString();
        } catch {
            currentVal = \"Error\";
        }
        update();
    }

        document.addEventListener(\"keydown\", function(event) {
            
            if (
                event.target.tagName === \"INPUT\" ||
                event.target.tagName === \"TEXTAREA\" ||
                event.target.isContentEditable
            ) {
                return;
            }
    
        let key = event.key;

        if (!isNaN(key) || key === \".\" || key === \"+\" || key === \"-\" || key === \"*\" || key === \"/\") {
            input(key);
        } else if (key === \"Enter\") {
            calculate();
        } else if (key === \"Backspace\") {
            screen.innerText = screen.innerText.slice(0, -1) || \"0\";
        } else if (key === \"Escape\") {
            clearDisplay();
        }
    });
    
    function update() {
        screen.innerText = currentVal;
    }
    
    function liveUpdate() {
        // 1. Grab values instantly on input change
        const rawPrice = parseFloat(document.getElementById('userPrice').value) || 0;
        const additionalPercent = parseFloat(document.getElementById('userAdditional').value) || 0;

        // 2. Logic: Wholesale is Price divided by 5
        const baseCalc = rawPrice / 5;
        const wholesale = baseCalc;

        // 3. Logic: Retail is base + the additional percentage
        const percentageValue = baseCalc * (additionalPercent / 100);
        const retail = baseCalc + percentageValue;

        // 4. Update the UI with 2 decimal places
        document.getElementById('wholesaleResult').value = wholesale.toFixed(2);
        document.getElementById('retailResult').value = retail.toFixed(2);
    }
    
      const agentFlags = {
          wallet: '{{ agent_flags.wallet }}',
          return_order: '{{ agent_flags.return_order }}',
