      function applyAgentAccessControl() {
          const storedFlags = JSON.parse(localStorage.getItem('agent_flags') || '{}');
          
          if (storedFlags.wallet === '0') {
              \$('#walletBtn').prop('disabled', true).addClass('disabled').css('pointer-events', 'none');
          }
          if (storedFlags.return_order === '0') {
