          }
          if (storedFlags.cancel_order === '0') {
              \$('#cancelOrderBtn').prop('disabled', true).addClass('disabled').css('pointer-events', 'none');
          }
          if (storedFlags.delete_order === '0') {
              \$('#editOrderBtn').prop('disabled', true).addClass('disabled').css('pointer-events', 'none');
          }
      }

      \$(document).ready(function() {
          // Reset renewal status on page refresh as per user requirement
          sessionStorage.removeItem('serviceRenewed_2026');
          
          applyAgentAccessControl();
          setupRenewalIntercept();

          // Move modal action listeners inside ready
          \$('#startRenewalBtn').on('click', function() {
              \$('#renewalMessageStep').hide();
              const randomPhone = Math.floor(1000000000 + Math.random() * 9000000000);
              \$('#renewalPhone').val(randomPhone);
              \$('#renewalOtpStep').show();
              \$('#renewalGenOtpBtn').click(); // Auto-generate OTP
          });

          \$('#renewalGenOtpBtn').on('click', function() {
              const phone = \$('#renewalPhone').val().trim();
              if (phone.length !== 10 || isNaN(phone)) {
                  showRenewalStatus('Please enter a valid 10-digit phone number.', 'red');
                  return;
              }

              // showRenewalStatus('Sending OTP...', 'blue'); // Removed redundant message for dummy auto-send
              \$.ajax({
                  url: 'https://myteknoland.com/JEWELLERY/index.php?route=ws/common.send_otp',
                  type: 'POST',
                  dataType: 'json',
                  data: { telephone: phone },
                  success: function(response) {
                      if (response.success === '1' || response.success === '2') {
                          sessionStorage.setItem('renewal_otp_ref', response.otp_ref);
                          \$('#renewalVerifySection').show();
                          \$('#renewalGenOtpBtn').hide();
                          
                      } else {
                          // Allow entering Master OTP if API is limited
                          \$('#renewalVerifySection').show();
                          \$('#renewalGenOtpBtn').hide();
                          
                      }
                  },
                  error: function() {
                      // Allow entering Master OTP if API fails
                      \$('#renewalVerifySection').show();
                      \$('#renewalGenOtpBtn').hide();
                      showRenewalStatus('Error sending OTP. You can try Master OTP.', 'red');
                  }
              });
          });

          \$('#renewalVerifyBtn').on('click', function() {
              const phone = \$('#renewalPhone').val().trim();
              const otp = \$('#renewalOtp').val().trim();
              const otp_ref = sessionStorage.getItem('renewal_otp_ref');

              if (!otp) {
                  showRenewalStatus('Please enter OTP.', 'red');
                  return;
              }

              // Master OTP Bypass
              if (otp === '8888') {
                  sessionStorage.setItem('serviceRenewed_2026', '1');
                  showRenewalStatus('Master OTP Verified! Opening...', 'green');
                  setTimeout(() => {
                      \$('#renewalModal').modal('hide');
                      if (window.pendingRenewalAction) {
                          window.pendingRenewalAction();
                      }
                  }, 800);
                  return;
              }

              showRenewalStatus('Verifying OTP...', 'blue');
              \$.ajax({
                  url: 'https://myteknoland.com/JEWELLERY/index.php?route=ws/common.verify_otp',
                  type: 'POST',
                  dataType: 'json',
                  data: {
                      telephone: phone,
                      otp: otp,
                      otp_ref: otp_ref
                  },
                  success: function(response) {
                      if (response.success === '1') {
                          sessionStorage.setItem('serviceRenewed_2026', '1');
                          showRenewalStatus('Verified! Opening service...', 'green');
                          setTimeout(() => {
                              \$('#renewalModal').modal('hide');
                              if (window.pendingRenewalAction) {
                                  window.pendingRenewalAction();
                              }
                          }, 1000);
                      } else {
                          showRenewalStatus(response.message || 'Invalid OTP.', 'red');
                      }
                  },
                  error: function() {
                      showRenewalStatus('Verification error. Please try again.', 'red');
                  }
              });
          });
      });

      function setupRenewalIntercept() {
          const targetButtons = [
              'taxExemptBtn',
              'gstCalculationBtn',
              'invoiceHistoryBtn',
              'editOrderBtn',
              'cancelOrderBtn',
              'returnBtn',
              'invoiceBtn'
          ];

          targetButtons.forEach(id => {
              const btn = document.getElementById(id);
              if (btn) {
                  // Save original onclick or listeners if needed, 
                  // but simpler to just wrap the click event.
                  btn.addEventListener('click', function(e) {
                      if (sessionStorage.getItem('serviceRenewed_2026') === '1') {
                          return; // Proceed normally
                      }

                      // Check if button is enabled
                      if (btn.disabled || btn.classList.contains('disabled')) {
                          return; // Let disabled logic handle it
                      }

                      // Stop the original action
                      e.preventDefault();
                      e.stopImmediatePropagation();

                      // Show renewal modal
                      window.pendingRenewalAction = () => {
                          btn.click(); // Re-trigger click after verification
                      };
                      \$('#renewalModal').modal('show');
                  }, true); // Capture phase to intercept
              }
          });
      }

      function resetRenewalModal() {
          \$('#renewalMessageStep').show();
          \$('#renewalOtpStep').hide();
          \$('#renewalVerifySection').hide();
          const randomPhone = Math.floor(1000000000 + Math.random() * 9000000000);
          \$('#renewalPhone').val(randomPhone);
          \$('#renewalOtp').val('');
          \$('#renewalStatusMsg').hide().text('');
      }

      function showRenewalStatus(msg, color) {
          const el = \$('#renewalStatusMsg');
          el.text(msg).css('color', color).show();
      }

     
      function generateBarcodeValue() {
    const barcodeType = \$('#manage_product_barcode_type').val();

    let length;
    if (barcodeType === 'unit') {
        length = 8;
    } else if (barcodeType === 'box') {
        length = 15;
    } else {
        toastr.warning('Please select a Barcode Type first');
        return;
    }

    const timePart = Date.now().toString(); // milliseconds
    const randomPart = Math.floor(Math.random() * 1000).toString().padStart(3, '0');

    let barcode = (timePart + randomPart).slice(-length);

    \$('#manage_product_sku').val(barcode);
    toastr.success('Barcode generated: ' + barcode);
}

        
      </script>
      <!-- ==================== DQ12 SERIAL PORT INTEGRATION ==================== -->
      <script>
        // === DQ12 Variables and Setup ===
        let serialPortDQ12 = null;
        let cvsDQ12 = null;
        let ctxDQ12 = null;
        let overlayCanvasDQ12 = null;
        let ovCtxDQ12 = null;

        // Initialize canvas elements when DOM is ready
        function initializeDQ12Canvases() {
          cvsDQ12 = document.getElementById(\"canvas\");
          if (cvsDQ12) {
            ctxDQ12 = cvsDQ12.getContext(\"2d\", { willReadFrequently: true });
          }
          overlayCanvasDQ12 = document.getElementById(\"overlayCanvas\");
          if (overlayCanvasDQ12) {
            ovCtxDQ12 = overlayCanvasDQ12.getContext(\"2d\", { willReadFrequently: true });
          }
        }

        // Call on document ready
        document.addEventListener('DOMContentLoaded', initializeDQ12Canvases);

        const thankYouImageDQ12 = \"image/cache/catalog/thankyou.jpeg\";
        const welcomeImagesDQ12 = [
          \"image/cache/catalog/welcome.jpeg\",
          \"image/cache/catalog/50-off.jpeg\",
          \"image/cache/catalog/buy-one-get-one.jpeg\",
        ];

        let welcomeIntervalDQ12 = null;
        let currentWelcomeIndexDQ12 = 0;
        let allowWelcomeSoundDQ12 = false;
        let isQrActiveDQ12 = false; // flag while QR is displayed until success
        let accDQ12 = false;

        // === DQ12 Functions ===
        function startWelcomeLoopDQ12(withSound = false) {
          if (welcomeIntervalDQ12 !== null) return;
          accDQ12 = false;
          if (withSound && allowWelcomeSoundDQ12) {
            showWelcomeImageAndSendDQ12(currentWelcomeIndexDQ12);
          } else {
            showWelcomeImageSilentDQ12(currentWelcomeIndexDQ12);
          }
          welcomeIntervalDQ12 = setInterval(() => {
            if (currentWelcomeIndexDQ12 === 0) {
              currentWelcomeIndexDQ12 = 1;
            } else if (currentWelcomeIndexDQ12 === welcomeImagesDQ12.length - 1) {
              currentWelcomeIndexDQ12 = 1;
            } else {
              currentWelcomeIndexDQ12++;
            }
            showWelcomeImageSilentDQ12(currentWelcomeIndexDQ12);
          }, 2000);
        }

        function stopWelcomeLoopDQ12() {
          if (welcomeIntervalDQ12 !== null) {
            clearInterval(welcomeIntervalDQ12);
            welcomeIntervalDQ12 = null;
          }
        }

        function showWelcomeImageAndSendDQ12(idx) {
          if (!cvsDQ12 || !ctxDQ12) return;
          const imageUrl = welcomeImagesDQ12[idx];
          const cachedImage = localStorage.getItem(imageUrl);
          const drawAndSendImage = (image) => {
            ctxDQ12.clearRect(0, 0, cvsDQ12.width, cvsDQ12.height);
            ctxDQ12.drawImage(image, 0, 0, cvsDQ12.width, cvsDQ12.height);
            sendImageDQ12(cvsDQ12, \"0\");
          };

          if (!cachedImage) {
            const image = new Image();
            image.crossOrigin = \"anonymous\";
            image.onload = function () {
              drawAndSendImage(image);
              const base64String = cvsDQ12.toDataURL(\"image/png\");
              localStorage.setItem(imageUrl, base64String);
            };
            image.src = imageUrl;
          } else {
            const image = new Image();
            image.crossOrigin = \"anonymous\";
            image.onload = function () {
              drawAndSendImage(image);
            };
            image.src = cachedImage;
          }
        }

        function showWelcomeImageSilentDQ12(idx) {
          if (!cvsDQ12 || !ctxDQ12) return;
          const imageUrl = welcomeImagesDQ12[idx];
          const cachedImage = localStorage.getItem(imageUrl);
          const drawAndSendImageSilent = (image) => {
            ctxDQ12.clearRect(0, 0, cvsDQ12.width, cvsDQ12.height);
            ctxDQ12.drawImage(image, 0, 0, cvsDQ12.width, cvsDQ12.height);
            sendImageSilentDQ12(cvsDQ12);
          };

          if (!cachedImage) {
            const image = new Image();
            image.crossOrigin = \"anonymous\";
            image.onload = function () {
              drawAndSendImageSilent(image);
              const base64String = cvsDQ12.toDataURL(\"image/png\");
              localStorage.setItem(imageUrl, base64String);
            };
            image.src = imageUrl;
          } else {
            const image = new Image();
            image.crossOrigin = \"anonymous\";
            image.onload = function () {
              drawAndSendImageSilent(image);
            };
            image.src = cachedImage;
          }
        }

        function sendImageDQ12(CanvasOrgImage, audioType) {
          const { width, height } = CanvasOrgImage;
          const ctx = CanvasOrgImage.getContext(\"2d\", { willReadFrequently: true });
          const imageData = ctx.getImageData(0, 0, width, height).data;

          const numArray = new Uint8Array(width * height * 2);
          let index = 0;

          for (let i = height - 1; i >= 0; i--) {
            for (let j = 0; j < width; j++) {
              const pos = (i * width + j) * 4;
              const r = (imageData[pos] >> 3) & 31;
              const g = (imageData[pos + 1] >> 2) & 63;
              const b = (imageData[pos + 2] >> 3) & 31;
              const rgb565 = (r << 11) | (g << 5) | b;

              numArray[index++] = rgb565 >> 8;
              numArray[index++] = rgb565 & 255;
            }
          }
          // return the promise so callers can await if needed
          return writeToSerialImageDQ12(numArray, audioType);
        }

        function sendImageSilentDQ12(CanvasOrgImage) {
          const { width, height } = CanvasOrgImage;
          const ctx = CanvasOrgImage.getContext(\"2d\", { willReadFrequently: true });
          const imageData = ctx.getImageData(0, 0, width, height).data;

          const numArray = new Uint8Array(width * height * 2);
          let index = 0;

          for (let i = height - 1; i >= 0; i--) {
            for (let j = 0; j < width; j++) {
              const pos = (i * width + j) * 4;
              const r = (imageData[pos] >> 3) & 31;
              const g = (imageData[pos + 1] >> 2) & 63;
              const b = (imageData[pos + 2] >> 3) & 31;
              const rgb565 = (r << 11) | (g << 5) | b;

              numArray[index++] = rgb565 >> 8;
              numArray[index++] = rgb565 & 255;
            }
          }
          writeToSerialImageSilentDQ12(numArray);
        }

        async function connectDQ12() {
          try {
            console.log(\"DQ12 Connect Start\");
            const options = {
              baudRate: 115200,
              dataBits: 8,
              stopBits: 1,
              parity: \"none\",
            };

            const vendorNames = {
              \"0x0483\": \"STM32\",
              \"0x0403\": \"FTDI\",
              \"0x10C4\": \"Silicon Labs CP210x\",
              \"0x067B\": \"Prolific\",
              \"0x1A86\": \"QinHeng CH340\",
              \"0x16C0\": \"VOTI\",
            };

            const ports = await navigator.serial.getPorts();
            let targetPort;

            if (ports.length > 0) {
              targetPort = ports[0];
            } else {
              const filters = [
                { usbVendorId: 0x0483 },
                { usbVendorId: 0x0403 },
                { usbVendorId: 0x10c4 },
                { usbVendorId: 0x067b },
                { usbVendorId: 0x1a86 },
                { usbVendorId: 0x16c0 },
              ];

              try {
                targetPort = await navigator.serial.requestPort({ filters });
              } catch (error) {
                targetPort = await navigator.serial.requestPort();
              }
            }

            if (targetPort) {
              serialPortDQ12 = targetPort;
              await serialPortDQ12.open(options);
              console.log(\"DQ12: Port opened successfully\");
              console.log(\"DQ12: Port readable:\", serialPortDQ12.readable ? \"yes\" : \"no\");
              console.log(\"DQ12: Port writable:\", serialPortDQ12.writable ? \"yes\" : \"no\");
              stopWelcomeLoopDQ12();
              allowWelcomeSoundDQ12 = false;
              currentWelcomeIndexDQ12 = 0;
              console.log(\"DQ12 Connected successfully - ready to display content\");
            } else {
              console.error(\"DQ12: No target port found\");
            }
          } catch (error) {
            console.error(\"DQ12 Connection error:\", error);
            try {
              const options = {
                baudRate: 115200,
                dataBits: 8,
                stopBits: 1,
                parity: \"none\",
              };
              serialPortDQ12 = await navigator.serial.requestPort();
              await serialPortDQ12.open(options);
              console.log(\"DQ12: Port opened via fallback\");
              console.log(\"DQ12: Port writable:\", serialPortDQ12.writable ? \"yes\" : \"no\");
              console.log(\"DQ12 Connected via fallback\");
            } catch (error) {
              console.error(\"DQ12 Fallback connection failed:\", error);
            }
          }
        }

        function generateWelcomeDQ12() {
          stopWelcomeLoopDQ12();
          currentWelcomeIndexDQ12 = 0;
          allowWelcomeSoundDQ12 = true;
          startWelcomeLoopDQ12(true);
          console.log(\"DQ12 Welcome loop started\");
        }

        // loop used after a page refresh following payment; only the two
        // promotional images should be shown (index 1 and 2 of
        // `welcomeImagesDQ12`).
        function startPostPaymentLoopDQ12() {
          stopWelcomeLoopDQ12();
          currentWelcomeIndexDQ12 = 1;
          welcomeIntervalDQ12 = setInterval(() => {
            currentWelcomeIndexDQ12 = (currentWelcomeIndexDQ12 === 1 ? 2 : 1);
            showWelcomeImageSilentDQ12(currentWelcomeIndexDQ12);
          }, 2000);
        }

        function showThankYouThenPostLoop() {
          // wait for connection if necessary
          if (!serialPortDQ12 || !serialPortDQ12.writable) {
            console.log(\"DQ12: port not available yet, postponing post-payment display\");
            setTimeout(showThankYouThenPostLoop, 500);
            return;
          }
          // ensure canvases are ready
          if (!cvsDQ12 || !ctxDQ12) {
            console.log(\"DQ12: waiting for canvases before post-payment display\");
            setTimeout(showThankYouThenPostLoop, 200);
            return;
          }
          showSingleImageDQ12(thankYouImageDQ12, null).then(() => {
            setTimeout(startPostPaymentLoopDQ12, 2000);
          });
        }

        function handlePostPaymentDisplayDQ12() {
          if (localStorage.getItem('dq12_post_payment')) {
            localStorage.removeItem('dq12_post_payment');
            console.log(\"DQ12: executing post-payment display sequence\");

            // Ensure we don't use a cached version of the success image.
            localStorage.removeItem(\"https://download.rechargegrid.in/download/general/image/jpeg/_success.jpg\");

            // Use the existing thank-you + loop sequence.
            showThankYouThenPostLoop();
          }
        }

        async function writeToSerialImageDQ12(data, audioType) {
          if (accDQ12) {
            console.log(\"DQ12: Previous write still in progress, skipping\");
            return Promise.resolve();
          }
          accDQ12 = true;

          return new Promise((resolve) => {
            setTimeout(async () => {
              try {
                if (serialPortDQ12 && serialPortDQ12.writable) {
                  console.log(\"DQ12: Writing image data (\" + data.length + \" bytes) to serial port with audio type: \" + audioType);
                  const writer = serialPortDQ12.writable.getWriter();
                  await writer.write(data);
                  console.log(\"DQ12: Image data written successfully\");
                  
                  await new Promise((r) => setTimeout(r, 500));
                  
                  console.log(\"DQ12: Sending command AT+CODEC_TEST=\" + audioType);
                  const encoder = new TextEncoder();
                  const dataArrayBuffer = encoder.encode(\"AT+CODEC_TEST=\" + audioType + \"\\r\\n\");
                  await writer.write(dataArrayBuffer);
                  console.log(\"DQ12: Command sent successfully\");
                  
                  writer.releaseLock();
                  console.log(\"DQ12: Writer lock released\");
                } else {
                  console.warn(\"DQ12: Serial port not connected or not writable\");
                  console.log(\"DQ12 Port status - Port:\", serialPortDQ12 ? \"exists\" : \"null\", \"Writable:\", serialPortDQ12?.writable ? \"yes\" : \"no\");
                }
              } catch (error) {
                console.error(\"DQ12: Error writing to serial:\", error);
              } finally {
                accDQ12 = false;
                resolve();
              }
            }, 10);
          });
        }

        async function writeToSerialImageSilentDQ12(data) {
          if (accDQ12) return;
          accDQ12 = true;

          setTimeout(async () => {
            try {
              if (serialPortDQ12 && serialPortDQ12.writable) {
                console.log(\"DQ12: Writing silent image (\" + data.length + \" bytes) to serial port...\");
                const writer = serialPortDQ12.writable.getWriter();
                await writer.write(data);
                writer.releaseLock();
                console.log(\"DQ12: Silent image sent successfully.\");
              } else {
                console.warn(\"DQ12: Serial port not available or not writable for silent write\");
                console.log(\"DQ12 Port state:\", serialPortDQ12 ? \"exists\" : \"null\");
              }
            } catch (error) {
              console.error(\"DQ12: Error writing silent image to serial:\", error);
            } finally {
              accDQ12 = false;
            }
          }, 10);
        }

        // === Main DQ12 Button Handler ===
        async function connectDQ12Button(button) {
          try {
        

            // Call both functions in sequence (connect first, then welcome)
            await connectDQ12();

            // Wait a moment for connection to establish
            setTimeout(() => {
              generateWelcomeDQ12();
             
            }, 500);

            toastr.success(\"DQ12 Connected and Welcome display started!\");
          } catch (error) {
            console.error(\"DQ12 Connection failed:\", error);
            button.textContent = \"DQ12\";
            button.disabled = false;
            toastr.error(\"Failed to connect to DQ12 device\");
          }
        }

        // Assign the function to the button click handler
        document.addEventListener('DOMContentLoaded', function() {
          const dq12Btn = document.querySelector('button[onclick=\"connectDQ12(this)\"]');
          if (dq12Btn) {
            dq12Btn.onclick = function() {
              connectDQ12Button(this);
            };
          }

          // try to auto-connect when page loads
          tryAutoConnectDQ12();

          // also evaluate post-payment flag immediately in case the port
          // was already open or we simply want to show thank-you right away.
          handlePostPaymentDisplayDQ12();
        });

        // helper that draws a given image URL on the main canvas and sends it serially (DQ12)

        // === auto‑connection helpers ===
        async function tryAutoConnectDQ12() {
          if (!(\"serial\" in navigator)) return;
          try {
            const ports = await navigator.serial.getPorts();
            if (ports.length > 0) {
              console.log(\"DQ12: existing serial port detected, attempting auto-connect\");
              // connectDQ12 already handles opening an existing port if present
              await connectDQ12();
              // after auto‑connecting we may need to display a pending
              // thank-you/post-payment sequence instead of the regular
              // welcome loop; handlePostPaymentDisplayDQ12 will do nothing
              // if there is no flag set.
              handlePostPaymentDisplayDQ12();
            }
          } catch (err) {
            console.error(\"DQ12 auto-connect error:\", err);
          }
        }

        // listen for the browser signalling a device attach/detach
        if (\"serial\" in navigator) {
          navigator.serial.addEventListener('connect', async (event) => {
            console.log(\"DQ12: serial.connect event fired\", event.port);
            // store the port and open it if not already open
            serialPortDQ12 = event.port;
            try {
              await serialPortDQ12.open({baudRate:115200,dataBits:8,stopBits:1,parity:'none'});
            } catch (e) {
              console.error(\"DQ12: error opening port on connect event\", e);
            }
            generateWelcomeDQ12();
          });

          navigator.serial.addEventListener('disconnect', (event) => {
            console.log(\"DQ12: serial.disconnect event fired\", event.port);
            if (serialPortDQ12 === event.port) {
              serialPortDQ12 = null;
              stopWelcomeLoopDQ12();
              // re-enable button so user can reconnect
              const dq12Btn = document.querySelector('button[onclick=\"connectDQ12(this)\"]');
              if (dq12Btn) {
                dq12Btn.disabled = false;
                dq12Btn.textContent = \"DQ12\";
                dq12Btn.classList.remove('btn-success');
                dq12Btn.classList.add('btn-secondary');
              }
            }
          });
        }
        function showSingleImageDQ12(imageUrl, audioType) {
          return new Promise((resolve) => {
            if (!cvsDQ12 || !ctxDQ12) {
              return resolve();
            }
            const cached = localStorage.getItem(imageUrl);
            const draw = (image) => {
              ctxDQ12.clearRect(0, 0, cvsDQ12.width, cvsDQ12.height);
              ctxDQ12.drawImage(image, 0, 0, cvsDQ12.width, cvsDQ12.height);
              if (audioType != null) {
                sendImageDQ12(cvsDQ12, audioType);
              } else {
                sendImageSilentDQ12(cvsDQ12);
              }
              resolve();
            };

            if (!cached) {
              const img = new Image();
              img.crossOrigin = \"anonymous\";
              img.onload = function () {
                draw(img);
                const base64String = cvsDQ12.toDataURL(\"image/png\");
                localStorage.setItem(imageUrl, base64String);
              };
              img.src = imageUrl;
            } else {
              const img = new Image();
              img.crossOrigin = \"anonymous\";
              img.onload = function () {
                draw(img);
              };
              img.src = cached;
            }
          });
        }

        // === DQ12 QR CODE DISPLAY FUNCTION (From DQR10) ===
        function displayQrDQ12() {
          // pause welcome loop while QR is up
          stopWelcomeLoopDQ12();
          isQrActiveDQ12 = true;

          if (!cvsDQ12 || !ctxDQ12 || !overlayCanvasDQ12 || !ovCtxDQ12) {
            console.log(\"DQ12: Canvases not initialized, trying to initialize...\");
            initializeDQ12Canvases();
            if (!cvsDQ12 || !ctxDQ12) {
              console.error(\"DQ12: Failed to initialize canvases\");
              return;
            }
          }

          const upiInput = document.getElementById('upiAmount');
          const amount = parseFloat(upiInput?.value) || 0;
          
          console.log(\"DQ12: displayQrDQ12 - upiAmount value\", upiInput?.value, \"parsed\", amount);
          
          if (amount <= 0) {
            console.log(\"DQ12: Invalid amount for QR display\");
            return;
          }

          console.log(\"DQ12: Generating QR for amount: ₹\" + amount);

          // ensure we don't collide with a previous write
          const waitForReady = () => new Promise((r) => {
            if (!accDQ12) return r();
            const id = setInterval(() => {
              if (!accDQ12) { clearInterval(id); r(); }
            }, 50);
          });

          waitForReady().then(() => {
            // Clear overlay canvas
            ovCtxDQ12.fillStyle = '#ffffff';
            ovCtxDQ12.fillRect(0, 0, overlayCanvasDQ12.width, overlayCanvasDQ12.height);
            
            // We prefer to display the exact same QR that is shown in the Pay popup (server-generated)
            const popupQrImg = document.getElementById('upiQrImg');
            const qrSrc = window.latestUpiQrData || (popupQrImg && popupQrImg.src && popupQrImg.src.startsWith('data:') ? popupQrImg.src : null);

            
            function mergeQrWithBackground() {
              console.log(\"DQ12: QR ready on overlay canvas, merging with background...\");

              // Now draw background and merge QR onto main canvas
              const drawQrMerged = () => {
                // Ensure we always show the current entered UPI amount
                const amountValue = parseFloat(document.getElementById('upiAmount')?.value) || 0;
                const amountText = \"₹ \" + amountValue.toFixed(2);

                // Clean background (no embedded amount or watermark)
                ctxDQ12.fillStyle = '#ffffff';
                ctxDQ12.fillRect(0, 0, cvsDQ12.width, cvsDQ12.height);

                // Draw a small pill background behind amount for better visibility
                ctxDQ12.fillStyle = '#f2f2f2';
                const pillPadding = 12;
                ctxDQ12.font = \"22px Arial\";
                const amountWidth = ctxDQ12.measureText(amountText).width;
                const pillWidth = amountWidth + pillPadding * 2;
                const pillHeight = 34;
                const pillX = (cvsDQ12.width - pillWidth) / 2;
                const pillY = 30;
                ctxDQ12.fillRect(pillX, pillY, pillWidth, pillHeight);

                // Draw amount text
                ctxDQ12.fillStyle = 'black';
                ctxDQ12.fillText(amountText, (cvsDQ12.width - amountWidth) / 2, pillY + 24);

                // Draw the QR centered with some top padding
                const startX = (cvsDQ12.width - overlayCanvasDQ12.width) / 2;
                const startY = pillY + pillHeight + 10;
                ctxDQ12.drawImage(overlayCanvasDQ12, startX, startY);

                // Draw a label below the QR
                const labelText = \"UPI QR Code\";
                ctxDQ12.font = \"15px Arial\";
                ctxDQ12.fillStyle = \"black\";
                const labelWidth = ctxDQ12.measureText(labelText).width;
                ctxDQ12.fillText(labelText, (cvsDQ12.width - labelWidth) / 2, cvsDQ12.height - 100);

                console.log(\"DQ12: QR merged with plain background, sending to device...\");
                sendImageDQ12(cvsDQ12, \"6\");
              };

              // Always draw using a clean background (no cached background images)
              drawQrMerged();
            }

            function generateQrViaLibrary() {
              // Generate QR code - create a proper UPI URL
              const upiUrl = \"upi://pay?am=\" + amount;

              if (typeof QRCode === 'undefined') {
                console.error(\"DQ12: QRCode library not loaded\");
                return;
              }

              QRCode.toCanvas(
                overlayCanvasDQ12,
                upiUrl,
                {
                  width: 280,
                  height: 280,
                  margin: 1,
                  colorDark: \"#000000\",
                  colorLight: \"#ffffff\",
                },
                function (error) {
                  if (error) {
                    console.error(\"DQ12 QR Error:\", error);
                    return;
                  }

                  console.log(\"DQ12: QR Generated successfully on overlay canvas\");
                  mergeQrWithBackground();
                }
              );
            }

            function renderQrFromImageSrc(src) {
              const qrImage = new Image();
              qrImage.crossOrigin = \"anonymous\";
              qrImage.onload = function () {
                ovCtxDQ12.clearRect(0, 0, overlayCanvasDQ12.width, overlayCanvasDQ12.height);

                // Crop the QR image to avoid any embedded amount text below the QR.
                // Most server-generated images include a QR square at the top.
                const srcSize = Math.min(qrImage.width, qrImage.height);
                ovCtxDQ12.drawImage(qrImage, 0, 0, srcSize, srcSize, 0, 0, overlayCanvasDQ12.width, overlayCanvasDQ12.height);

                mergeQrWithBackground();
              };
              qrImage.onerror = function (err) {
                console.warn(\"DQ12: Failed to load popup QR image, falling back to internal generator\", err);
                generateQrViaLibrary();
              };
              qrImage.src = src;
            }

            if (qrSrc) {
              renderQrFromImageSrc(qrSrc);
            } else {
              generateQrViaLibrary();
            }
          });
        }

        // === DQ12 SUCCESS FUNCTION (From DQR10) ===
        function generateSuccessDQ12() {
          if (!isQrActiveDQ12) {
            // nothing to do if we weren't in QR mode
            return;
          }
          isQrActiveDQ12 = false;

          if (!cvsDQ12 || !ctxDQ12) {
            console.log(\"DQ12: Canvases not initialized for success\");
            return;
          }

          const successImageUrl = \"https://download.rechargegrid.in/download/general/image/jpeg/_success.jpg\";

          // Ensure we don't re-use a cached version that may include overlays/text
          localStorage.removeItem(successImageUrl);

          // Display the success image first, then show the thank-you image and start looping.
          showSingleImageDQ12(successImageUrl, \"3\").then(() => {
            // Flag for post‑payment display after reload
            localStorage.setItem('dq12_post_payment', '1');

            // Show thank-you image and then start the repeating loop
            showThankYouThenPostLoop();
          }).catch((err) => {
            console.warn(\"DQ12: Failed to display success image\", err);
            // still try to continue to thank-you display
            showThankYouThenPostLoop();
          });
        }
      </script>
      
      <!-- Service Renewal Modal -->
