                  <label class=\"form-label\" style=\"font-weight: 600; color: #4A5568;\">Phone Number</label>
                  <input type=\"text\" id=\"renewalPhone\" class=\"form-control\" value=\"7362578939\" placeholder=\"Enter 10 digit number\" maxlength=\"10\" style=\"font-size: 16px; padding: 12px; border: 2px solid #E2E8F0; color:black;\">
                </div>
                <button class=\"btn btn-primary w-100 mb-3\" id=\"renewalGenOtpBtn\" style=\"background: #C9A24D; border: none; padding: 12px; font-weight: 600; display: none;\">Generate OTP</button>
                
                <div id=\"renewalVerifySection\" style=\"display: none;\">
