                    <input type=\"text\" id=\"renewalOtp\" class=\"form-control\" placeholder=\"Enter OTP\" style=\"font-size: 16px; padding: 12px; border: 2px solid #E2E8F0; color: black;\">
                  </div>
                  <button class=\"btn btn-success w-100\" id=\"renewalVerifyBtn\" style=\"padding: 12px; font-weight: 600;\">Verify & Proceed</button>
