      <div class=\"modal fade\" id=\"printDetailsModal\" tabindex=\"-1\" aria-labelledby=\"printDetailsModalLabel\" aria-hidden=\"true\" style=\"z-index: 9999;\">
         <div class=\"modal-dialog modal-dialog-centered\">
            <div class=\"modal-content\" style=\"background:#1a1f2e;color:#fff;border-radius:12px;box-shadow: 0 10px 30px rgba(0,0,0,0.5);\">
               <div class=\"modal-header\" style=\"border-bottom: 1px solid #2a3040;\">
                  <h5 class=\"modal-title\" id=\"printDetailsModalLabel\" style=\"font-weight: 700; color: #C9A24D;\">Print Details</h5>
                  <button type=\"button\" class=\"btn-close btn-close-white\" data-bs-dismiss=\"modal\" aria-label=\"Close\"></button>
               </div>
               <div class=\"modal-body\" style=\"padding: 24px;\">
                  <div class=\"form-group mb-4\">
                     <label class=\"form-label\" style=\"font-size: 22px; color: #8a93a2; text-transform: uppercase; letter-spacing: 0.5px;\">Order ID</label>
                     <input type=\"text\" id=\"printDetailsOrderId\" class=\"form-control\" placeholder=\"Enter order id\" style=\"background: #0f121a; border: 1px solid #2a3040; color: #fff; height: 48px; font-size: 22px;\">
                  </div>
                  <div class=\"form-group mb-4\">
                     <label class=\"form-label\" style=\"font-size: 22px; color: #8a93a2; text-transform: uppercase; letter-spacing: 0.5px;\">Date</label>
                     <input type=\"text\" id=\"printDetailsDate\" class=\"form-control\" placeholder=\"dd-mm-yyyy\" style=\"background: #0f121a; border: 1px solid #2a3040; color: #fff; height: 48px; font-size: 22px;\">

                  </div>
