                  <button type=\"button\" class=\"btn btn-link\" data-bs-dismiss=\"modal\" style=\"color: #8a93a2; text-decoration: none; font-weight: 600;\">Cancel</button>
                  <button type=\"button\" class=\"btn btn-success\" id=\"printDetailsConfirmBtn\" onclick=\"confirmPrintDetailsAndSubmit()\" style=\"background: #C9A24D; border: none; padding: 10px 24px; font-weight: 700; border-radius: 6px; color: white;\">Print</button>
