      <script>
         
          document.addEventListener('DOMContentLoaded', function(){
              const tabApp = document.getElementById('tabApp');
              const tabProducts = document.getElementById('tabProducts');
              if(tabApp) tabApp.addEventListener('click', ()=>switchRightTab('app'));
              if(tabProducts) tabProducts.addEventListener('click', ()=>switchRightTab('products'));

              // load categories immediately so they are available regardless of which
              // tab the user is viewing (app or products).
              loadCategoriesRight();

              // start with the app tab active, per the new requirement
              switchRightTab('app');
              const printDetailsDate = document.getElementById('printDetailsDate');
              if (printDetailsDate) {
                  // Use jQuery UI datepicker if available, otherwise fall back to native date input
                  if (window.jQuery && typeof \$(printDetailsDate).datepicker === 'function') {
                      \$(printDetailsDate).datepicker({ dateFormat: 'dd-mm-yy' });
                  } else {
                      printDetailsDate.type = 'date';
                  }
              }
          });
          function switchRightTab(name){
              const appRight = document.getElementById('appRightContent');
              const catList = document.getElementById('categoryListRight');
              const prodList = document.getElementById('productListRight');

              if(appRight) appRight.style.display = (name==='app' ? 'block' : 'none');

              // categories remain visible no matter what
              if(catList) catList.style.display = 'grid';

              // product list only when product tab is active
              if(prodList) prodList.style.display = (name==='products' ? 'grid' : 'none');

              document.getElementById('tabApp').classList.toggle('active', name==='app');
              document.getElementById('tabProducts').classList.toggle('active', name==='products');
          }
          function loadCategoriesRight(){
              fetch('index.php?route=extension/purpletree_pos/pos/home.getInitialData')
                .then(r=>r.json())
                .then(data=>{
                   if(data && data.status==='success' && Array.isArray(data.categories)){
                       const list = document.getElementById('categoryListRight');
                       if(!list) return;
                       list.innerHTML='';
                       data.categories.forEach(cat=>{
                           const btn = document.createElement('button');
                           btn.textContent = cat.name;
                           btn.className = 'category-btn';
                           btn.addEventListener('click', ()=>showCategoryProductsRight(cat));
                           list.appendChild(btn);
                       });
                   }
                })
                .catch(err=>console.error('category load failed',err));
          }
         function showCategoryProductsRight(cat){
    // when a user taps a category we always move the right panel to the
    // Products tab so the product buttons become visible.
    switchRightTab('products');

    // right-panel should use productListRight element
    const list = document.getElementById('productListRight');
    if(!list) return;

    list.innerHTML = '';

    if(Array.isArray(cat.products)){
        cat.products.forEach(p=>{
            const btn = document.createElement('button');

            // ✅ Name in first row, price in second row
            btn.innerHTML = `
                <div class=\"product-name\">\${p.name}</div>
                <div class=\"product-price\">₹ \${p.price}</div>
            `;

            btn.className = 'product-btn';

            btn.addEventListener('click', ()=> {
                const productData = Object.assign({}, p, {
                    pos_quantity: p.pos_quentity || p.pos_quantity || 0
                });
                addProductToCart(productData);
            });

            list.appendChild(btn);
        });
    }

    list.style.display = 'grid';
    list.style.gridTemplateColumns = 'repeat(4, 1fr)';
}
      </script>
   </body>
</html>", "extension/purpletree_pos/catalog/view/template/pos/index2.twig", "/home/k5ahkheh1fv2/public_html/JEWELLERY/extension/purpletree_pos/catalog/view/template/pos/index2.twig");
    }
